-- Poems batch 201
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a7e7a5ae-251b-48c1-9b9a-e94e9cc84935','送曇藏主雪峰見癡絕','釋師範','宋','宋诗','song-poetry','','[]','世上有蛇皆可弄，南山鱉鼻不可動。',62,'全唐诗/poet.song.190000.json','["世上有蛇皆可弄，南山鱉鼻不可動。", "動著冷口暗傷人，傷人至死未知痛。", "子今去也，當自著便宜。", "後日毒遭一口歸來，莫道山僧不曾說與伊。"]'),
('9e65a6fb-9668-4d02-aedc-be81fae74e3e','送姪昭上人歸鄉','釋師範','宋','宋诗','song-poetry','','[]','昭昭靈靈是何物，非物非心亦非佛。',145,'全唐诗/poet.song.190000.json','["昭昭靈靈是何物，非物非心亦非佛。", "五湖雲衲競頭參，空把光陰恣埋沒。", "我遊江湖三十有四年，飽飯之餘，一味閑打眠。", "子今迢迢苦尋討，不知尋討何慕焉。", "問吾道，今年大熟收成早。", "問吾禪，秋林噪晚聲喧喧。", "抖擻屎腸都說了，莫將一字歸去容易空流傳。", "斯言寫就相違別，目斷家山雲疊疊。", "我亦欲歸歸不得，千里萬里一條鐵。"]'),
('a52fff2a-8508-40af-bee3-974afa2bf0b7','林泉野人','釋師範','宋','宋诗','song-poetry','','[]','樂哉林泉人，自得林泉趣。',82,'全唐诗/poet.song.190000.json','["樂哉林泉人，自得林泉趣。", "渴則掬泉飲，健則穿林去。", "幾見幽鳥啼黄葉，聚薰入奏雪飛絮。", "四時適吾意，萬象爲吾侶。", "有人更問意如何，笑指巖前大松樹。", "阿呵呵，快活快活，有甚討處。"]'),
('04c060f3-d2d0-44aa-827f-bc1c8f94b352','再鑄粥鍋','釋師範','宋','宋诗','song-poetry','','[]','不解多方錮鏴成，一鎚打破與重烹。',32,'全唐诗/poet.song.190000.json','["不解多方錮鏴成，一鎚打破與重烹。", "等閑脫體離窠臼，煮粥依前不是羹。"]'),
('5a0478b2-ec69-4531-80cc-cdd263f24e88','大芙蓉接待','釋師範','宋','宋诗','song-poetry','','[]','水雲何處覓行蹤，踏破天台雁蕩峰。',32,'全唐诗/poet.song.190000.json','["水雲何處覓行蹤，踏破天台雁蕩峰。", "脚力盡時消息在，小芙蓉接大芙蓉。"]'),
('ef41af8e-156b-4679-968b-e8c6cd975f4c','寧海接待','釋師範','宋','宋诗','song-poetry','','[]','煙波盡處良田闊，歧路窮時活計新。',32,'全唐诗/poet.song.190000.json','["煙波盡處良田闊，歧路窮時活計新。", "南北憧憧故多士，不知誰是飽參人。"]'),
('3fd559c7-bda9-4fc7-8dad-6d9930922ba7','鷄鳴接待','釋師範','宋','宋诗','song-poetry','','[]','水雲遇夜須投宿，飯飽何妨又進程。',32,'全唐诗/poet.song.190000.json','["水雲遇夜須投宿，飯飽何妨又進程。", "山主豈徒開接待，養鷄意在五更鳴。"]'),
('cdc855bf-039c-49cb-b2e4-c7b4180250a8','元道士','釋師範','宋','宋诗','song-poetry','','[]','黄衣捨去混緇衣，棄却甜桃摘醋梨。',32,'全唐诗/poet.song.190000.json','["黄衣捨去混緇衣，棄却甜桃摘醋梨。", "酸澀一時嘗過了，攢眉歸去許誰知。"]'),
('a55f4810-4e4d-48ea-a3f8-f2f3b58aed8b','浄道士','釋師範','宋','宋诗','song-poetry','','[]','伊予頭腦不相似，鼻孔由來只一般。',32,'全唐诗/poet.song.190000.json','["伊予頭腦不相似，鼻孔由來只一般。", "冷地自家親摸著，老君元戴楮皮冠。"]'),
('3013c24e-2520-44f7-bb0f-19bf7b57630d','相士','釋師範','宋','宋诗','song-poetry','','[]','鱗皴一塊爛枯柴，幾見春風長綠苔。',32,'全唐诗/poet.song.190000.json','["鱗皴一塊爛枯柴，幾見春風長綠苔。", "豈謂先生也相許，馿年決定放花開。"]'),
('8a7c098b-6bea-4013-b15f-9ee7a44096c3','無方刊字','釋師範','宋','宋诗','song-poetry','','[]','道在貴亡覊，寧容滯一涯。',24,'全唐诗/poet.song.190000.json','["道在貴亡覊，寧容滯一涯。", "是山皆有石，隨處可鎸碑。"]'),
('a640b18f-a237-420f-862a-0aa03c5447c5','釋迦出山相贊','釋師範','宋','宋诗','song-poetry','','[]','入山去，何所圖。',28,'全唐诗/poet.song.190000.json','["入山去，何所圖。", "出山來，胡爲乎。", "早知今日事，悔不慎當初。"]'),
('ababad68-0507-4192-b333-35a866d9812e','觀音大士贊  其一','釋師範','宋','宋诗','song-poetry','','[]','提起數珠呈伎倆，無端弄出孩童相。',32,'全唐诗/poet.song.190000.json','["提起數珠呈伎倆，無端弄出孩童相。", "何似月明霜滿天，孤猿啼斷千峰上。"]'),
('44f0a99d-94b6-45c7-bdbf-39c9c18eeedd','觀音大士贊  其二','釋師範','宋','宋诗','song-poetry','','[]','隨流入流，無所分別。',36,'全唐诗/poet.song.190000.json','["隨流入流，無所分別。", "處處圜通，頭頭漏泄。", "雲浄八紘天宇寬，萬頃波心蓮一葉。"]'),
('e386014a-b749-4f37-8a9f-4ab9767e1fb5','觀音大士贊  其三','釋師範','宋','宋诗','song-poetry','','[]','寂滅現前，如月在天。',62,'全唐诗/poet.song.190000.json','["寂滅現前，如月在天。", "分身利物，影含百川。", "是所謂不然而然，虛而通，靜而應。", "萬國春容，千江月影。", "如今何處求普門，一聲鶴唳寒松頂。"]'),
('79003dc3-3314-4c0a-8060-5ae7666fdc61','觀音大士贊  其四','釋師範','宋','宋诗','song-poetry','','[]','大哉觀自在，善觀諸音聲。',168,'全唐诗/poet.song.190000.json','["大哉觀自在，善觀諸音聲。", "而於諸音聲，不作音聲見。", "是見亦寂滅，亦無寂滅者。", "由是離衆苦，處處得解脫。", "分身十方剎，救度於一切。", "然於救度中，而無救度想。", "如春在百花，不分長短枝。", "又如月在水，不分大小器。", "尋聲隨所念，平等獲利益。", "是三十二應，十四無畏法。", "無量方便門，一一皆成就。", "一一成就處，當體皆如幻。", "我觀如幻相，願作如幻讚。", "若有見聞者，當作如是觀。"]'),
('834c03b8-ac1a-422b-afd7-49958d76cc9f','漁婦觀音贊  其一','釋師範','宋','宋诗','song-poetry','','[]','腥穢通身不自知，更來漁市討便宜。',32,'全唐诗/poet.song.190000.json','["腥穢通身不自知，更來漁市討便宜。", "就中活底無多子，提向風前賣與誰。"]'),
('4c904f3d-eeef-43fd-9457-80daf1874f4e','漁婦觀音贊  其二','釋師範','宋','宋诗','song-poetry','','[]','籃內魚，衣中珠。',18,'全唐诗/poet.song.190000.json','["籃內魚，衣中珠。", "見買見賣，少實多虛。"]'),
('3770e9ad-aef4-4662-8bea-8e786fb53b47','文殊大士爲龍女說法贊','釋師範','宋','宋诗','song-poetry','','[]','文殊說法，所說何法。',40,'全唐诗/poet.song.190000.json','["文殊說法，所說何法。", "女子成佛，所成何佛。", "無法可說，無佛可成。", "卧龍奮迅，獅子嚬呻。"]'),
('6eb7e7bf-72ef-443a-a424-c1a3657ac8f7','三教合面相贊','釋師範','宋','宋诗','song-poetry','','[]','一三三一，三一一三。',36,'全唐诗/poet.song.190000.json','["一三三一，三一一三。", "解不能散，聚不成團。", "今古合成閉口面，只因門戶有多般。"]'),
('4cb70363-4b23-4402-a7fa-3578cde4c2a3','十六羅漢贊','釋師範','宋','宋诗','song-poetry','','[]','身如枯柴，心如斷崖。',46,'全唐诗/poet.song.190000.json','["身如枯柴，心如斷崖。", "萬般神變，一種平懷。", "面面相看，究竟不知論底事。", "阿耨達池龍王，來日請佛齋。"]'),
('38b6e5be-941a-4496-b2f7-2542ec630b79','須菩提贊','釋師範','宋','宋诗','song-poetry','','[]','頭白齒豁，空腹高心。',44,'全唐诗/poet.song.190000.json','["頭白齒豁，空腹高心。", "被憍尸迦當面上當，對維摩詰甘自屈沉。", "說甚解空稱第一，只堪倚杖獨沉吟。"]'),
('ba64480f-1d81-4474-bfaf-9a80746a12b5','布袋贊  其一','釋師範','宋','宋诗','song-poetry','','[]','露胸坦腹，皺眉搭嘴。',46,'全唐诗/poet.song.190000.json','["露胸坦腹，皺眉搭嘴。", "做箇模樣，是何儀軌。", "謂渠惺未必惺，請渠睡未必睡。", "吽吽奉化子，我儂識得你。"]'),
('4f28495f-aa0b-4cb7-9e07-3854e5b464c4','布袋贊  其二','釋師範','宋','宋诗','song-poetry','','[]','肉重千斤，智無半星。',52,'全唐诗/poet.song.190000.json','["肉重千斤，智無半星。", "回頭轉腦，昧却天真。", "一處尤堪笑，街頭等箇人。", "我當時若見，只緩緩地向他道，謝三娘秤銀。"]'),
('ff6194e6-e0da-46fd-9d33-d97cd4d6ca67','布袋贊  其三','釋師範','宋','宋诗','song-poetry','','[]','誰管你地，誰管你天。',34,'全唐诗/poet.song.190000.json','["誰管你地，誰管你天。", "放下布袋，打一覺眠。", "若論當來補處，馿年更待馿年。"]'),
('1a3e631f-8ac8-45b0-808d-350f29bba911','布袋贊  其四','釋師範','宋','宋诗','song-poetry','','[]','巡行掠布，既飽且醉。',34,'全唐诗/poet.song.190000.json','["巡行掠布，既飽且醉。", "無用心處，打箇噴嚏。", "更言是真彌勒，想見別有假底。"]'),
('98573f03-97fa-49d3-8c29-181ec989e26a','維摩居士贊  其一','釋師範','宋','宋诗','song-poetry','','[]','詐病從來不可醫，文殊特爲下針錐。',32,'全唐诗/poet.song.190000.json','["詐病從來不可醫，文殊特爲下針錐。", "事褫一啄長三尺，問著依前似鼓槌。"]'),
('3ed7faa6-66ad-4c2b-8f62-ae68335ee0b3','維摩居士贊  其二','釋師範','宋','宋诗','song-poetry','','[]','示疾毗耶，平地風波。',20,'全唐诗/poet.song.190000.json','["示疾毗耶，平地風波。", "醫不得處，病在口多。"]'),
('b382179a-b3c8-49a6-b78e-0efec3b7401f','達磨祖師贊  其一','釋師範','宋','宋诗','song-poetry','','[]','大破六宗，單傳一心。',37,'全唐诗/poet.song.190000.json','["大破六宗，單傳一心。", "遊梁歷魏，罕遇知音。", "少室九年空面壁，誰向同霜夜月沉沉。"]'),
('1c9414ab-8c77-4c10-aa67-04ca209d9887','達磨祖師贊  其二','釋師範','宋','宋诗','song-poetry','','[]','滿面盡是胡鬚，當門却無版齒。',28,'全唐诗/poet.song.190000.json','["滿面盡是胡鬚，當門却無版齒。", "縱不畫影圖形，東土有人識你。"]'),
('9066dc86-ef47-4f09-addf-59a5e6d02286','達磨祖師贊  其三','釋師範','宋','宋诗','song-poetry','','[]','觸忤梁王，恓恓渡江。',36,'全唐诗/poet.song.190000.json','["觸忤梁王，恓恓渡江。", "九年冷坐，重重話墮。", "一花五葉自芬披，不在春風著意吹。"]'),
('572af480-36bd-4963-be0d-641d458d37d2','祖師圖贊','釋師範','宋','宋诗','song-poetry','','[]','等是清平世界人，多因閑事長無明。',32,'全唐诗/poet.song.190000.json','["等是清平世界人，多因閑事長無明。", "使他箇箇能安分，圖上何緣有姓名。"]'),
('2290a90a-d34f-44a6-97b8-21e4b1470b62','豐干贊','釋師範','宋','宋诗','song-poetry','','[]','浄土不居居穢土，良馬不騎騎猛虎。',32,'全唐诗/poet.song.190000.json','["浄土不居居穢土，良馬不騎騎猛虎。", "回頭轉腦謾招呼，誰肯與伊爲伴侶。"]'),
('83f912cd-6f7d-44e0-aea2-b91d7041078e','寒山持經拾得手接  其一','釋師範','宋','宋诗','song-poetry','','[]','手持經卷，付與同倫。',20,'全唐诗/poet.song.190000.json','["手持經卷，付與同倫。", "己所不欲，勿施於人。"]'),
('96a83081-630a-4837-8a90-60e76ef7a84d','寒山持經拾得手接  其二','釋師範','宋','宋诗','song-poetry','','[]','自有一經，不肯受持。',20,'全唐诗/poet.song.190000.json','["自有一經，不肯受持。", "却從他覓，可煞愚癡。"]'),
('b8c45f05-9213-427a-8aa4-8ec521d725fa','蜆子贊  其一','釋師範','宋','宋诗','song-poetry','','[]','出手露脚，撈蝦摝蜆。',36,'全唐诗/poet.song.190000.json','["出手露脚，撈蝦摝蜆。", "這窮鬼子，可貴可賤。", "紙錢堆裏謾藏身，莫言冷地無人見。"]'),
('d1ebb2cc-7edd-4f42-987b-bc2cab5bbfc3','蜆子贊  其二','釋師範','宋','宋诗','song-poetry','','[]','谿尾谿頭打野盤，撈蝦摝蜆當朝餐。',32,'全唐诗/poet.song.190000.json','["谿尾谿頭打野盤，撈蝦摝蜆當朝餐。", "想應不是釣鰲手，得箇蝦兒便喜歡。"]'),
('229a1a87-0c74-40b2-8608-ce3767b9949e','金華聖者贊','釋師範','宋','宋诗','song-poetry','','[]','飽啖豬頭肉，長齋不喫素。',33,'全唐诗/poet.song.190000.json','["飽啖豬頭肉，長齋不喫素。", "莫言滋味別，要且少鹽醋。", "吽吽，大有著你處。"]'),
('92e30b53-94db-498e-b4e0-d9e08cdf0531','端獅子贊','釋師範','宋','宋诗','song-poetry','','[]','要弄便弄，要置便置。',34,'全唐诗/poet.song.190000.json','["要弄便弄，要置便置。", "眼晴倒轉，眉毛踢起。", "雖然好箇金毛，爭奈爪牙未備。"]'),
('90cc26da-39cd-49a4-93a4-481e83bc02cf','普化贊','釋師範','宋','宋诗','song-poetry','','[]','恣意放顛放獃，走徧前街後街。',28,'全唐诗/poet.song.190000.json','["恣意放顛放獃，走徧前街後街。", "就中一處尀耐，大悲院裏有齋。"]'),
('b0b2e0ba-0fde-42d7-847a-bc8a1d47f75b','泉大道贊','釋師範','宋','宋诗','song-poetry','','[]','這瞎禿，無撿束。',40,'全唐诗/poet.song.190000.json','["這瞎禿，無撿束。", "浴龍湫，繫蛇腹。", "瓢裏酒，鉢裏肉。", "到頭底事若爲論，郴州城中六月六。"]'),
('5451f8f5-6d21-4583-bd42-3480a437b3bf','郁山主贊','釋師範','宋','宋诗','song-poetry','','[]','收得蚌蛤珠，誇張無價數。',24,'全唐诗/poet.song.190000.json','["收得蚌蛤珠，誇張無價數。", "我儂不怪他，他是村山主。"]'),
('08906177-dce1-4600-8db4-71fc787145aa','言法華贊','釋師範','宋','宋诗','song-poetry','','[]','褰裳而趨，或然而住。',36,'全唐诗/poet.song.190000.json','["褰裳而趨，或然而住。", "咄咄書空，喃喃獨語。", "盡語渠儂轉法華，知得身心在何處。"]'),
('d5e57826-9a6c-46d2-ade2-cbb4a41f08d8','鳥窠贊','釋師範','宋','宋诗','song-poetry','','[]','佛法有些子，言中設網羅。',24,'全唐诗/poet.song.190000.json','["佛法有些子，言中設網羅。", "布毛吹起處，依舊不離窠。"]'),
('0f3df1ab-7feb-4a08-922d-b771e6e0cac6','臨濟贊  其一','釋師範','宋','宋诗','song-poetry','','[]','善戰不動旗鎗，善縛不加繩約。',30,'全唐诗/poet.song.190000.json','["善戰不動旗鎗，善縛不加繩約。", "其毒猶恒山之蛇，被傷者決定無藥。"]'),
('04808fb4-5e19-4428-951d-4eed8eaa3940','臨濟贊  其二','釋師範','宋','宋诗','song-poetry','','[]','竊不見蹤，敗不見贓。',20,'全唐诗/poet.song.190000.json','["竊不見蹤，敗不見贓。", "是真白拈，其誰與當。"]'),
('bb03befd-146b-44b3-85c8-09b846687c68','臨濟贊  其三','釋師範','宋','宋诗','song-poetry','','[]','晴空轟霹靂，官路栽荆棘。',24,'全唐诗/poet.song.190000.json','["晴空轟霹靂，官路栽荆棘。", "沒興遭逢著，前凶後不吉。"]'),
('0fd2362d-364b-4a64-9a15-41d5e392705c','忠道者贊','釋師範','宋','宋诗','song-poetry','','[]','聽教一味瞌睡，參禪不入爐冶。',44,'全唐诗/poet.song.190000.json','["聽教一味瞌睡，參禪不入爐冶。", "盜橘過於揮劍，騎虎穩如乘馬。", "伎倆元來箇樣生，幾乎喚作忠道者。"]'),
('44bd7157-e6ef-4761-99fe-6e5dc9e19642','靈照女贊','釋師範','宋','宋诗','song-poetry','','[]','有髻垂肩，無鞋磹脚。',36,'全唐诗/poet.song.190000.json','["有髻垂肩，無鞋磹脚。", "一掬精神，十分銷鑠。", "最苦拈來潑罩籬，風前索價無人著。"]'),
('36653549-90af-473e-a0b5-7a6724aa2b7e','常不輕童子贊','釋師範','宋','宋诗','song-poetry','','[]','作佛名何佛，不輕成自輕。',24,'全唐诗/poet.song.190000.json','["作佛名何佛，不輕成自輕。", "誰知眼睛裏，箇箇有瞳人。"]'),
('8558b30f-11c4-452a-84be-f64012d15630','豐干寒拾虎四睡贊','釋師範','宋','宋诗','song-poetry','','[]','善者未必善，惡者未必惡。',48,'全唐诗/poet.song.190000.json','["善者未必善，惡者未必惡。", "彼此不忘懷，如何睡得著。", "惡者難爲善，善者難爲惡。", "老虎既忘機，如何睡不著。"]'),
('942b4b1a-1753-4e1e-8c53-5f98af90f991','題巖寒拾','釋師範','宋','宋诗','song-poetry','','[]','五峰路上，雙磵寺前。',36,'全唐诗/poet.song.190000.json','["五峰路上，雙磵寺前。", "藏頭露面，撫背拍肩。", "舉筆欲題題不得，斷崖千仞鎖寒煙。"]'),
('3465bbc8-e2f1-4d46-9878-2ddab223b324','圜悟贊','釋師範','宋','宋诗','song-poetry','','[]','坐底是誰，立底是誰。',50,'全唐诗/poet.song.190000.json','["坐底是誰，立底是誰。", "兩枚漆桶，一種無知。", "非惟咈詬啒㖀，恣意鳳林吒之。", "壞盡東山窮活計，都因這漢兩爺兒。"]'),
('5cdb5439-fa4b-4537-8eda-357247387c58','大慧贊','釋師範','宋','宋诗','song-poetry','','[]','僧中之龍，法中之王。',20,'全唐诗/poet.song.190000.json','["僧中之龍，法中之王。", "讚不及處，衡陽梅陽。"]'),
('85365b71-b284-404d-98e5-7d8a34152009','破庵贊  其一','釋師範','宋','宋诗','song-poetry','','[]','噫嚱吁，何人歟。',42,'全唐诗/poet.song.190000.json','["噫嚱吁，何人歟。", "無德可敬，無言可書。", "非橫滅族，是真瞎馿。", "有口不能駡得，捲而分付雲居。"]'),
('4d7ac772-cfcf-4f87-81a6-9d5a4554b587','破庵贊  其二','釋師範','宋','宋诗','song-poetry','','[]','生平蕭散，渾無覊絆。',96,'全唐诗/poet.song.190000.json','["生平蕭散，渾無覊絆。", "奮惡拳頭，打會禪漢。", "我嘗一見，口似匾檐。", "凡侍之者，莫知其幾，往往瞠乎其後，終莫得其畔岸。", "是故不可毀，不可讚，至於不可奈何。", "但如今必要知其所竊之羊，謾去西邊屋角頭蜂桶裏尋看。"]'),
('25e5d537-6a4c-44be-8689-c5fd5e0e4254','無相贊','釋師範','宋','宋诗','song-poetry','','[]','重如山，靜如水。',34,'全唐诗/poet.song.190000.json','["重如山，靜如水。", "輕輕觸著，雙眉剔起。", "這般漏綻許誰知，分付天章破家子。"]'),
('c421f03e-8e44-4f26-bef6-1dc7feac28e5','孟保相贊','釋師範','宋','宋诗','song-poetry','','[]','澄之不清，混之不雜。',64,'全唐诗/poet.song.190000.json','["澄之不清，混之不雜。", "融融澹澹，辛辛辣辣。", "徑山橫贊豎贊，終是贊之不著。", "但以手加額，道箇南無大慈大悲救苦救難殺人不眨眼底觀世音菩薩。"]'),
('9e962567-a439-4fb6-8168-62d6fbfed500','鄒編修請贊','釋師範','宋','宋诗','song-poetry','','[]','骨稜層，髮䰐鬖。',47,'全唐诗/poet.song.190000.json','["骨稜層，髮䰐鬖。", "且不安分，更說指南。", "置須彌盧於一針鋒，貯四大海於無底籃。", "不知世有誰知己，樸庵。"]'),
('960c1e32-b5be-4122-aa91-6d847c529ad5','彰聖輝長老請贊','釋師範','宋','宋诗','song-poetry','','[]','一之上，三之下。',38,'全唐诗/poet.song.190000.json','["一之上，三之下。", "有來由，無縫罅。", "是甚牛溲馬浡，剛自遼天索價，累及兒孫成話欛。"]'),
('ecce917a-f7d8-41db-838e-3384787dd7be','興化益長老請贊','釋師範','宋','宋诗','song-poetry','','[]','益無所益，爲無所爲。',36,'全唐诗/poet.song.190000.json','["益無所益，爲無所爲。", "迥超玄化，杳絕機宜。", "桃紅李白自芬披，問著東風總不知。"]'),
('c54ff1c1-6d64-476e-bbe1-4b994be23d16','定慧圻長老請贊','釋師範','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','詐啞徉聾，指西作東。',36,'全唐诗/poet.song.190000.json','["詐啞徉聾，指西作東。", "肆無所畏，說大脫空。", "彎弓曾發蓬蒿箭，射中南山白額蟲。"]'),
('3cadd0d7-8f20-49d6-833b-483274f3dc10','延慶日長老請贊','釋師範','宋','宋诗','song-poetry','','[]','不愛人贊，不怕人謗。',36,'全唐诗/poet.song.190000.json','["不愛人贊，不怕人謗。", "令是一條筋，見者難近傍。", "要識渠儂端的，日在東山之上。"]'),
('34e5a7c1-cfbc-43ed-8cb4-1a04d38e620e','倫侍者請贊','釋師範','宋','宋诗','song-poetry','','[]','見假像真，弄真像假。',36,'全唐诗/poet.song.190000.json','["見假像真，弄真像假。", "裂破面門，非馿非馬。", "世上有誰親見來，天台方巖倫侍者。"]'),
('083e436b-e6c6-4ef2-82f9-6f590c48dc47','東林日長老請贊','釋師範','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','無德可崇，無善可從。',48,'全唐诗/poet.song.190000.json','["無德可崇，無善可從。", "近之不吉，遠之必凶。", "傲慢釋迦文，說甚臨濟宗。", "誰知目視凌霄外，意在廬山五老峰。"]'),
('92087398-2ed4-40aa-8837-1b6998c6f3b0','覺際融長老請贊','釋師範','宋','宋诗','song-poetry','','[]','無箇模樣，畫箇模樣。',36,'全唐诗/poet.song.190000.json','["無箇模樣，畫箇模樣。", "既有模樣，是甚模樣。", "節節危梁十二層，垂垂白髮三千丈。"]'),
('47ff2aa3-55aa-4b69-a133-1dedb298535c','曹山榘長老請贊','釋師範','宋','宋诗','song-poetry','','[]','頭圓象天，足方象地。',36,'全唐诗/poet.song.190000.json','["頭圓象天，足方象地。", "耳朵聞聲，鼻孔出氣。", "馬駒踏殺天下人，瞎馿不受靈山記。"]'),
('c16b7b7f-889a-46bd-9ab1-7dc14b73f445','洪長老請贊','釋師範','宋','宋诗','song-poetry','','[]','西有岷峨，南有雪峰。',34,'全唐诗/poet.song.190000.json','["西有岷峨，南有雪峰。", "靈龜未爆，爻象重重。", "拈却玄沙白袋，自然千里同風。"]'),
('4dcdd92a-f33b-4323-808c-1e084a40d7a2','永壽礎長老請贊','釋師範','宋','宋诗','song-poetry','','[]','怒駡當慈悲，脫空成善巧。',40,'全唐诗/poet.song.190000.json','["怒駡當慈悲，脫空成善巧。", "三錢買李子，偏向赤邊咬。", "如今此話許誰知，永壽破家真種草。"]'),
('455f9726-7dcc-497d-90e6-afd826889cb8','因大師請贊','釋師範','宋','宋诗','song-poetry','','[]','不是神，不是鬼。',42,'全唐诗/poet.song.190000.json','["不是神，不是鬼。", "突出人前，是何面嘴。", "妙因等閑覷破，扣齒擎拳頂禮。", "唵蘇嚧蘇嚧㗭唎㗭唎。"]'),
('20732359-750d-4fa5-bf57-8f47e52ecc93','日本琳上人請贊','釋師範','宋','宋诗','song-poetry','','[]','頭拄天，脚踏地。',38,'全唐诗/poet.song.190000.json','["頭拄天，脚踏地。", "大宋國裏鼻孔，日本國裏出氣。", "覺琳持此歸故鄉，大似波斯入閙市。"]'),
('8b8953ef-0bd5-4fc3-a7bc-8d3b0c1565d9','禪人請贊  其一','釋師範','宋','宋诗','song-poetry','','[]','似牛無角，似馿欠尾。',36,'全唐诗/poet.song.190000.json','["似牛無角，似馿欠尾。", "突箇形容，誠難比擬。", "無所思，無所爲，卧月眠雲誰得知。"]'),
('252d4de2-295d-40c9-94e3-ca1be6d78d0b','禪人請贊  其二','釋師範','宋','宋诗','song-poetry','','[]','眼裏沒瞳人，鼻頭無孔竅。',40,'全唐诗/poet.song.190000.json','["眼裏沒瞳人，鼻頭無孔竅。", "單賣赤髮綜，鬼見拍手笑。", "世有愚癡箇樣僧，難爲名字上傳燈。"]'),
('7ce46a45-d031-4f53-af7c-9ade9ef2688b','禪人請贊  其三','釋師範','宋','宋诗','song-poetry','','[]','人道脫似，我道不似。',36,'全唐诗/poet.song.190000.json','["人道脫似，我道不似。", "口少四方，眉欠八字。", "不是普豐清上人，定應喚作王蠻子。"]'),
('dd76b110-01de-4b0d-8584-a8a9cc106c40','禪人請贊  其四','釋師範','宋','宋诗','song-poetry','','[]','鬚髮蓬鬆，眼孔定動。',36,'全唐诗/poet.song.190000.json','["鬚髮蓬鬆，眼孔定動。", "解拈死貨，手頭活弄。", "觸著梧桐老樹樁，等閑驚起丹山鳳。"]'),
('59c95c3b-8cce-4f91-b05a-c2726c3b1cd3','禪人請贊  其五','釋師範','宋','宋诗','song-poetry','','[]','這瞎賊，無覊勒。',46,'全唐诗/poet.song.190000.json','["這瞎賊，無覊勒。", "指槐駡柳，將南作北。", "橫也湊他不得，豎也湊他不得。", "誰知籮裏生薑，元是井中侯黑。"]'),
('8aae59cd-2f03-493f-884c-c8a4593240c1','禪人請贊  其六','釋師範','宋','宋诗','song-poetry','','[]','僻性拗木枕，天生沒意智。',40,'全唐诗/poet.song.190000.json','["僻性拗木枕，天生沒意智。", "自己獨冤家，佛祖閑奴婢。", "嘗聞一飽忘百饑，今日山僧身便是。"]'),
('f1b5340f-c267-4db3-9d30-2d0c1d984919','禪人請贊  其七','釋師範','宋','宋诗','song-poetry','','[]','大不可忽，細不可欺。',52,'全唐诗/poet.song.190000.json','["大不可忽，細不可欺。", "丘嶽之崇，起於毫釐。", "善惡之積，發乎隠微。", "洞徹根源，迥絕機宜。", "可以拈一塵融十虛以無遺。"]'),
('d6dda87d-ab61-4b07-b1be-49f87886eb92','小師德輶請贊','釋師範','宋','宋诗','song-poetry','','[]','喜一上，怒一上，少機關，足伎倆。',46,'全唐诗/poet.song.190000.json','["喜一上，怒一上，少機關，足伎倆。", "硬把虛空量，剛道有一丈。", "似這般會算底本師，如何喚作無準和尚。"]'),
('0a3d69e2-d06d-408e-84bd-4344c8a4ea46','德義請贊','釋師範','宋','宋诗','song-poetry','','[]','義出豐年，儉生不孝。',36,'全唐诗/poet.song.190000.json','["義出豐年，儉生不孝。", "自古自今，豈容師教。", "義兮義兮知不知，官稅了兮何用鈔。"]'),
('dc59af40-4191-4339-a848-16805b0ce2ef','德濬請贊','釋師範','宋','宋诗','song-poetry','','[]','踞胡床，握麈尾，默默自問，誰家之子。',37,'全唐诗/poet.song.190000.json','["踞胡床，握麈尾，默默自問，誰家之子。", "寧可併喫五斗醋，不敢說著東山下左邊底。"]'),
('4337356f-fc4d-49b9-bb10-7c9645eb4741','題牧牛圖','釋師範','宋','宋诗','song-poetry','','[]','誰家牯，誰家犢。',34,'全唐诗/poet.song.190000.json','["誰家牯，誰家犢。", "谿東谿西，水甘草足。", "宜乎後夜當春耕，懹袖應難秘斯軸。"]'),
('7cd3332e-a297-451c-b1b5-b5dfd38ac4b3','題僧畫草蟲','釋師範','宋','宋诗','song-poetry','','[]','似則似矣，是則未是。',24,'全唐诗/poet.song.190000.json','["似則似矣，是則未是。", "若是伶利衲僧，不作這般蟲豸。"]'),
('a0006aed-9166-4db2-a2bf-10f5bfad05b5','臨終偈','釋師範','宋','宋诗','song-poetry','','[]','來時空索索，去也赤條條。',24,'全唐诗/poet.song.190000.json','["來時空索索，去也赤條條。", "更要問端的，天台有石橋。"]'),
('e082ee66-4675-4605-9e50-ee399a29b192','頌古三首  其一','釋師範','宋','宋诗','song-poetry','','[]','盡力提持只一刀，狸奴從此脫皮毛。',32,'全唐诗/poet.song.190000.json','["盡力提持只一刀，狸奴從此脫皮毛。", "血流滿地成狼籍，暗爲春風染小桃。"]'),
('d941b569-0328-4aa7-8216-40891450a964','頌古三首  其二','釋師範','宋','宋诗','song-poetry','','[]','晴空轟霹靂，官路栽荆棘。',24,'全唐诗/poet.song.190000.json','["晴空轟霹靂，官路栽荆棘。", "沒興遭逢著，前凶後不吉。"]'),
('c3362fe1-aca5-491f-8af6-ca22dcde04f1','頌古三首  其三','釋師範','宋','宋诗','song-poetry','','[]','失脚溪橋兩眼枯，錯將魚目作明珠。',32,'全唐诗/poet.song.190000.json','["失脚溪橋兩眼枯，錯將魚目作明珠。", "直饒塵盡光生也，照破山河夢見無。"]'),
('6dd9c238-9b3e-4f33-b2ab-0f4468af0cc8','天神二首  其一','釋師範','宋','宋诗','song-poetry','','[]','天下梅花主，扶桑文字祖。',24,'全唐诗/poet.song.190000.json','["天下梅花主，扶桑文字祖。", "這個正法眼，雲門答道普。"]'),
('8b9a946f-0179-4ca8-885d-2517b2a95a2a','天神二首  其二','釋師範','宋','宋诗','song-poetry','','[]','菅君本不假凡胎，直自靈山會上來。',32,'全唐诗/poet.song.190000.json','["菅君本不假凡胎，直自靈山會上來。", "五百年間無識者，扶桑佛法一枝梅。"]'),
('f67ac4fa-afef-4f16-938e-4cbd503d8061','中秋','廣利寺僧','宋','宋诗','song-poetry','','[]','吾心似秋月，碧潭清皎潔。',24,'全唐诗/poet.song.190000.json','["吾心似秋月，碧潭清皎潔。", "無物堪比倫，教我如何說。"]'),
('4864e98f-d0dc-41bf-8f0a-c993035d9b2b','解夏小參問無準禪師','僧某','宋','宋诗','song-poetry','','[]','選佛場開日，叢林氣象新。',24,'全唐诗/poet.song.190000.json','["選佛場開日，叢林氣象新。", "心空及第者，畢竟是何人。"]'),
('f16a7a79-bd41-4d5a-83f3-92092fefaf10','讀柳子厚集','秦綱','宋','宋诗','song-poetry','','[]','嶄然頭角異，年少銳功名。',48,'全唐诗/poet.song.190000.json','["嶄然頭角異，年少銳功名。", "身爲才高累，名因宦謫成。", "山川助奇氣，騷雅變遺聲。", "千古羅池祀，昌黎報友情。"]'),
('221b05c3-0d4b-4565-8f02-731aa4cce902','偈','釋妙堪','宋','宋诗','song-poetry','','[]','大荼毒鼓，轟天震地。',20,'全唐诗/poet.song.190000.json','["大荼毒鼓，轟天震地。", "轉腦回頭，橫死萬里。"]'),
('32aaa98f-f885-4ba4-98f0-98e183fe0798','頌古','釋妙堪','宋','宋诗','song-poetry','','[]','一人客路如天遠，一箇歸心似箭輕。',32,'全唐诗/poet.song.190000.json','["一人客路如天遠，一箇歸心似箭輕。", "彼此征途雖有異，須知同日到天廷。"]'),
('e6d186c1-da94-4502-a0ff-d025f6f372d8','遊司空山','李韶','宋','宋诗','song-poetry','','[]','鶴馭凌雲入紫微，水盤山繞五雲飛。',32,'全唐诗/poet.song.190000.json','["鶴馭凌雲入紫微，水盤山繞五雲飛。", "松杉老盡無消息，猶得千年一度歸。"]'),
('314ae943-b9df-4933-b221-027704e539ee','遊虎丘','李韶','宋','宋诗','song-poetry','','[]','望中平坦獨崔嵬，根跨滄溟浪打回。',64,'全唐诗/poet.song.190000.json','["望中平坦獨崔嵬，根跨滄溟浪打回。", "不是巨靈潛擘與，祇應蓬島暗飛來。", "經壇煙染千株石，丹井雲封萬古苔。", "翠色高通蘇郡內，滿城清雅絕塵埃。"]'),
('820c8553-6ffd-4e33-a73a-7b97ce51f7e7','詠史','馮必大','宋','宋诗','song-poetry','','[]','亭長何曾識帝王，入關便解約三章。',32,'全唐诗/poet.song.190000.json','["亭長何曾識帝王，入關便解約三章。", "只消一勺清冷水，冷却秦鍋百沸湯。"]'),
('7fa15084-4375-4794-aa75-9179dbc154c9','題韓侂胄舊第  其一','國子監生','宋','宋诗','song-poetry','','[]','掀天聲勢祗冰山，廣厦空餘十萬間。',32,'全唐诗/poet.song.190000.json','["掀天聲勢祗冰山，廣厦空餘十萬間。", "若使早知明哲計，肯將富貴博清閑。"]'),
('17b48b53-2ebb-47f4-af89-0a53269cc1bb','題韓侂胄舊第  其二','國子監生','宋','宋诗','song-poetry','','[]','花柳依然弄晚風，才郎袖手去無蹤。',32,'全唐诗/poet.song.190000.json','["花柳依然弄晚風，才郎袖手去無蹤。", "不知郿塢金多少，爭似盧門席不重。"]'),
('f3440852-7632-46f9-94e6-93b7716dd4e7','句','無名氏','宋','宋诗','song-poetry','','[]','衆鳥不喜亦不悲，又復別尋高樹枝。',16,'全唐诗/poet.song.190000.json','["衆鳥不喜亦不悲，又復別尋高樹枝。"]'),
('9a878efc-857b-46f7-bd55-7d7ee1bdca07','大滌洞天留題  其一','倪允文','宋','宋诗','song-poetry','','[]','九關深處鎖仙家，縹緲清都定不遐。',32,'全唐诗/poet.song.190000.json','["九關深處鎖仙家，縹緲清都定不遐。", "草木曾留高廟蹕，香燈常带紫宸麻。"]'),
('9d9dff37-fc29-403e-8465-524820227709','大滌洞天留題  其二','倪允文','宋','宋诗','song-poetry','','[]','巢父灘頭甫着鞭，名山入眼驛程邊。',32,'全唐诗/poet.song.190000.json','["巢父灘頭甫着鞭，名山入眼驛程邊。", "迂迴僅費商於地，領袖寧煩一介先。"]'),
('78b1b435-d2e0-4e94-9de1-5e3703fc3471','大滌洞天留題  其三','倪允文','宋','宋诗','song-poetry','','[]','筍輿輕捷繞坡陀，石竇抽關噴决河。',32,'全唐诗/poet.song.190000.json','["筍輿輕捷繞坡陀，石竇抽關噴决河。", "幸許羊腸成坦履，不應狹路響風波。"]'),
('3138c4ed-f971-4ff2-83fd-949e597bb80b','大滌洞天留題  其四','倪允文','宋','宋诗','song-poetry','','[]','洞裏群仙總未逢，天風吹快去匆匆。',32,'全唐诗/poet.song.190000.json','["洞裏群仙總未逢，天風吹快去匆匆。", "儒仙元自留官府，儻借刀圭得聖功。"]'),
('efdbb44f-124f-44c4-b49a-375662356585','獻帥府經歷二首  其一','李申之','宋','宋诗','song-poetry','','[]','一飯感恩無地報，此心許國已天知。',32,'全唐诗/poet.song.190000.json','["一飯感恩無地報，此心許國已天知。", "胸中千古蟠鍾阜，一死鴻毛斷不移。"]'),
('31e52dc4-9424-4261-bbd6-800273034d10','獻帥府經歷二首  其二','李申之','宋','宋诗','song-poetry','','[]','擬把孤忠報主知，主知未報已身疲。',32,'全唐诗/poet.song.190000.json','["擬把孤忠報主知，主知未報已身疲。", "明朝定作長淮鬼，馬革應煩爲裹尸。"]'),
('563eacfb-ae56-4e69-838d-b47e31f7c008','句','李申之','宋','宋诗','song-poetry','','[]','區區已上和親策，安得元戎一點頭。',16,'全唐诗/poet.song.190000.json','["區區已上和親策，安得元戎一點頭。"]'),
('9191a196-9ae1-4a12-958c-26128f648b2f','瓜廬','薛師石','宋','宋诗','song-poetry','','[]','近來有新趣，買得薛能園。',48,'全唐诗/poet.song.190000.json','["近來有新趣，買得薛能園。", "疎壤延瓜蔓，深鋤去草根。", "花時長載酒，月夜正開門。", "最識田家樂，辛勤更不言。"]'),
('0517f102-46e3-4174-8c7d-ece23b8fcfb2','瓜廬至日即事','薛師石','宋','宋诗','song-poetry','','[]','西山起還伏，插入萬丈潭。',48,'全唐诗/poet.song.190000.json','["西山起還伏，插入萬丈潭。", "漁叟操桂棹，樵歌過草菴。", "年荒酒味薄，天旱井泉甘。", "不願丘園賁，惟將易自參。"]'),
('a18dbc0d-0917-466e-b419-9143af0fce44','送趙幾道赴台州錄事','薛師石','宋','宋诗','song-poetry','','[]','廳前綆汲何從來，清流海底通九垓。',128,'全唐诗/poet.song.190000.json','["廳前綆汲何從來，清流海底通九垓。", "天河地脈㶏旋轉，上中下井躔三台。", "滿城桃花二仙種，方廣金殿三門開。", "一時會上幾許人，若匪佛種應仙才。", "于公徒知高其閭，豈識大化非胚胎。", "今茲送言暫相別，詩規筆誨紛崔嵬。", "傅說明星定入夢，方朔跡穢空諧詼。", "不昵不阿予與汝，古交淡淡無嫌猜。"]'),
('791bcd6a-4570-45a0-ad9a-0d824da6132c','寄趙紫芝','薛師石','宋','宋诗','song-poetry','','[]','別後訪消息，傳言一半虛。',48,'全唐诗/poet.song.190000.json','["別後訪消息，傳言一半虛。", "前官已不就，所向定何如。", "苦雨厭羈思，春風欺舊廬。", "懷人閉門夕，專擬寄來書。"]'),
('ebf58e27-b07f-4c64-ba9c-c1eab07302e5','會宿趙紫芝宅','薛師石','宋','宋诗','song-poetry','','[]','郊居無一事，喜見友人來。',48,'全唐诗/poet.song.190000.json','["郊居無一事，喜見友人來。", "促席坐添火，推窗立看梅。", "論詩漏欲盡，煮茗匣重開。", "此夜思徐照，墓松猶未栽。"]'),
('ec9053b3-e17c-4688-bbb5-2f25a42addca','贈達西堂','薛師石','宋','宋诗','song-poetry','','[]','却罷住山緣，歸來又十年。',48,'全唐诗/poet.song.190000.json','["却罷住山緣，歸來又十年。", "自知身是妄，常道鉢休傳。", "塔路脩來直，紗燈影處圓。", "與吾相對坐，語嘿盡通禪。"]'),
('d536354c-3c98-4658-bf9c-06bc5c5c3f65','寄蔡任','薛師石','宋','宋诗','song-poetry','','[]','不見三百日，問君消息多。',48,'全唐诗/poet.song.190000.json','["不見三百日，問君消息多。", "身閒詩有味，水浄月無波。", "琴裏懷孤竹，書中寄永和。", "遥憐一江隔，何計得相過。"]'),
('46aade08-6a7a-42e0-a4b8-a304e566cece','送趙紫芝入金陵幕','薛師石','宋','宋诗','song-poetry','','[]','爲官亦僦居，官況定何如。',48,'全唐诗/poet.song.190000.json','["爲官亦僦居，官況定何如。", "昨夜交遊散，滿湖秋雨疎。", "此邦佳麗久，舊吏拜參初。", "喜是賢侯幕，新年有薦書。"]'),
('e6475e6f-91c4-4861-8627-46209022dc9b','讀劉靖君碑','薛師石','宋','宋诗','song-poetry','','[]','儒生身上事皆成，身外浮華亦甚輕。',64,'全唐诗/poet.song.190000.json','["儒生身上事皆成，身外浮華亦甚輕。", "種竹滿山門徑小，挂冠當路樹枝橫。", "幾於顔子三生壽，分得陶潛一字名。", "何處時令見前輩，只看碑語自心清。"]'),
('5a6252c6-06e8-46f1-8e2b-43d1f5a2055b','漁父詞  其一','薛師石','宋','宋诗','song-poetry','','[]','十載江湖不上船，捲篷高卧月明天。',32,'全唐诗/poet.song.190000.json','["十載江湖不上船，捲篷高卧月明天。", "今夜泊，杏花村，只有笭箵當酒錢。"]'),
('89a42ab0-aeab-4670-8edd-862d52cf29d3','漁父詞  其二','薛師石','宋','宋诗','song-poetry','','[]','鄰家船上小姑兒，相問如何是別離。',32,'全唐诗/poet.song.190000.json','["鄰家船上小姑兒，相問如何是別離。", "雙墮髻，一彎眉，愛看紅鱗比目魚。"]'),
('690be65b-345c-444c-8816-6eb43a6e0c41','漁父詞  其三','薛師石','宋','宋诗','song-poetry','','[]','平明霧靄雨初晴，兒子敲鍼作釣成。',32,'全唐诗/poet.song.190000.json','["平明霧靄雨初晴，兒子敲鍼作釣成。", "香餌小，繭絲輕，釣得魚兒不識名。"]'),
('97424d91-87a4-4bfc-9f6e-b9c8e88aff71','漁父詞  其四','薛師石','宋','宋诗','song-poetry','','[]','繫船蘭沚鱠長鱸，白袷方袍忽訪吾。',32,'全唐诗/poet.song.190000.json','["繫船蘭沚鱠長鱸，白袷方袍忽訪吾。", "神甚爽，貌全枯，莫是當年楚大夫。"]'),
('9551883b-e23c-40f4-9809-705032b62476','漁父詞  其五','薛師石','宋','宋诗','song-poetry','','[]','春融水暖百花開，獨棹扁舟過釣臺。',32,'全唐诗/poet.song.190000.json','["春融水暖百花開，獨棹扁舟過釣臺。", "鷗與鷺，莫相猜，不是逃名不肯來。"]'),
('3f150513-435b-45c5-bbba-563290574962','漁父詞  其六','薛師石','宋','宋诗','song-poetry','','[]','夜來采石渡頭眠，月下相逢李謫仙。',32,'全唐诗/poet.song.190000.json','["夜來采石渡頭眠，月下相逢李謫仙。", "歌一曲，別無言，白鶴飛來雪滿船。"]'),
('52983955-35b2-40e2-9781-cf662c160bcf','漁父詞  其七','薛師石','宋','宋诗','song-poetry','','[]','莫論輕重釣竿頭，伴得船歸即便休。',32,'全唐诗/poet.song.190000.json','["莫論輕重釣竿頭，伴得船歸即便休。", "酒味薄，勝空甌，事事何須著意求。"]'),
('0d752998-9df9-4cef-a7ab-f179ad0ff140','寄謝黄元信惠茶','薛師石','宋','宋诗','song-poetry','','[]','建溪金鋌直幾千，余性所嗜一已偏。',180,'全唐诗/poet.song.190000.json','["建溪金鋌直幾千，余性所嗜一已偏。", "尋常草卉不足進，龍團鳳夸如珉堅。", "長鬚健卒前月到，手提茶器急取煎。", "妻兒攢眉笑苦澀，爲言真味茲天然。", "易牙去已久，吾齒若貝編。", "枵腸豈廢食，睡省非壯年。", "惜此餘香滯喉頰，巡除吟詠聲諓諓。", "詩成寄題建寧郡，主茶官吏俱時賢。", "合同緘印一時畢，進奉飛馳爭春妍。", "天子不敢嘗，薦以寢廟先。", "定自褒嘉到屬郡，趣君密邇玉爐煙。", "一以此味沃天下，邪魔驅掃無留連。"]'),
('256a3022-a991-4805-899a-6c60c4d508e0','送子舒弟之官華亭','薛師石','宋','宋诗','song-poetry','','[]','執手難爲別，愁看去棹孤。',48,'全唐诗/poet.song.190000.json','["執手難爲別，愁看去棹孤。", "船官得閒散，春晚過皇都。", "書附海人便，花添住屋圖。", "有時吟句穩，還憶老兄無。"]'),
('55621305-4d56-440c-821e-ce311f3aad36','送張直翁之筠陽','薛師石','宋','宋诗','song-poetry','','[]','時平民事少，詩句定能清。',48,'全唐诗/poet.song.190000.json','["時平民事少，詩句定能清。", "況作江西去，放教秋水生。", "山花香淡泊，湘竹恨分明。", "朝士多知爾，慈溪舊有聲。"]'),
('b33fe128-7a7b-4717-af3e-3dec05412656','送趙端行廷對少寓期待之意','薛師石','宋','宋诗','song-poetry','','[]','甲科知亦有，難得是家傳。',48,'全唐诗/poet.song.190000.json','["甲科知亦有，難得是家傳。", "定入中朝局，還支內賜錢。", "服青初解褐，班後忽超前。", "獨謝歸廊幕，詩呈第一篇。"]'),
('37da6330-c4d3-4c49-a94a-26a9a64b8f5b','贈葛天民','薛師石','宋','宋诗','song-poetry','','[]','逃禪已得計，易姓豈云非。',48,'全唐诗/poet.song.190000.json','["逃禪已得計，易姓豈云非。", "自說身如幻，常人見亦稀。", "亭邊看荷葉，樓上挂蓑衣。", "幾夜蘇堤月，隨君瘦影歸。"]'),
('ca4da34f-2ca9-4be4-a7ab-477ec399992d','送盧次夔兼柬盧九祕書','薛師石','宋','宋诗','song-poetry','','[]','蔡邕初入直，撰著幾書成。',48,'全唐诗/poet.song.190000.json','["蔡邕初入直，撰著幾書成。", "所取友若此，遥知人至清。", "朝回收疏稿，夜語雜詩情。", "愧我多年別，相煩一寄聲。"]'),
('fcbfc2e2-cdc0-49c1-a1a7-1c3b06abd120','挽陳叔望','薛師石','宋','宋诗','song-poetry','','[]','少年曾是魯諸生，爲立功名別路行。',64,'全唐诗/poet.song.190000.json','["少年曾是魯諸生，爲立功名別路行。", "嘗捉寶刀嚴漢陛，再持符節領江城。", "絕憐詩律雙金在，不見林塘五柳成。", "明日西山歸葬處，踏青人散草初平。"]'),
('08eb4a13-0a47-4dbf-8de1-15a0a5618b4f','送葉季重之官吳門','薛師石','宋','宋诗','song-poetry','','[]','君繼賢人業，試官閶闔門。',120,'全唐诗/poet.song.190000.json','["君繼賢人業，試官閶闔門。", "但問要離墓，莫看真娘墳。", "虎丘寺前生野草，一花一葉皆麗好。", "用心冷淡不此嗜，自有詩禮長探討。", "給旁餘閒庭廡空，小輿應亦上垂虹。", "橋邊風駛寄書便，只寫平安報乃翁。", "我慚空空易疎斥，時亦摳衣侍函席。", "春膏流滑儻寄將，待寫續經藏屋壁。"]'),
('71e3f901-766d-4127-aac6-8a1ef3340215','寄趙叔魯','薛師石','宋','宋诗','song-poetry','','[]','相知言莫盡，別後意如何。',48,'全唐诗/poet.song.190000.json','["相知言莫盡，別後意如何。", "命笑春冰薄，愁因夜雨多。", "全家寓京國，無地著吟哦。", "會得窮通理，從余緝薜蘿。"]'),
('0290122f-51cd-4030-b19f-329ef33eb7e6','酬劉子至','薛師石','宋','宋诗','song-poetry','','[]','寄來書一紙，別後喜安和。',48,'全唐诗/poet.song.190000.json','["寄來書一紙，別後喜安和。", "想見清高極，吟成秋思多。", "山頭靈運立，月下謫仙歌。", "共是江湖客，斜陽各晒蓑。"]'),
('421b9811-ab56-443c-a8f6-2e9416ec8445','賦二十八字','薛師石','宋','宋诗','song-poetry','','[]','水滿溝塍不愁旱，急催租稅却憂貧。',32,'全唐诗/poet.song.190000.json','["水滿溝塍不愁旱，急催租稅却憂貧。", "家人苦不憐予拙，雪袴冰衫要及晨。"]'),
('d159fca6-f56c-4564-bf1a-7425cfc5eb3f','紀夢曲','薛師石','宋','宋诗','song-poetry','','[]','夜夢佳人姱且長，星冠霞帔雲衣裳。',128,'全唐诗/poet.song.190000.json','["夜夢佳人姱且長，星冠霞帔雲衣裳。", "雙眉淺淡畫春色，兩耳炫燿垂珠璫。", "細步逡巡倏相近，世道人情不敢問。", "斂容正笑發一言，不識巫山雲雨恨。", "自從十五學仙經，今年二十身骨清。", "天上有籍昇其名，長聲短聲歌紫瓊。", "紫瓊之章詞宛轉，永與人間風調遠。", "餘聲未竟鐘鼓鳴，霧散煙收人不見。"]'),
('532b19bc-4d94-4630-a7c9-77306c5b1340','水心先生惠顧瓜廬','薛師石','宋','宋诗','song-poetry','','[]','未成三徑已荒蕪，勞動先生枉棹過。',64,'全唐诗/poet.song.190000.json','["未成三徑已荒蕪，勞動先生枉棹過。", "數朵葵榴發深愧，一池鷗鷺避前呵。", "路通矮屋惟添草，橋壓扁舟半沒河。", "再見緇維訪漁父，却無漁父聽清歌。"]'),
('7fd7496b-4872-4967-aefd-7a64b2280ec8','題南塘薛圃','薛師石','宋','宋诗','song-poetry','','[]','門對南塘水亂流，竹根橘柢自成洲。',32,'全唐诗/poet.song.190000.json','["門對南塘水亂流，竹根橘柢自成洲。", "中閒老子隠名姓，只聽漁歌今白頭。"]'),
('05b5cfe6-1029-48f2-b9c0-262597405408','巾山','薛師石','宋','宋诗','song-poetry','','[]','兩峰爭起入雲層，半屬虛空半屬僧。',32,'全唐诗/poet.song.190000.json','["兩峰爭起入雲層，半屬虛空半屬僧。", "斜日滿山人到少，任蕃去後我來登。"]'),
('2b95ed06-3d0a-48f5-995b-a05ade1d02b5','送趙端行','薛師石','宋','宋诗','song-poetry','','[]','紛紛帝族貴，欽茲神秀門。',192,'全唐诗/poet.song.190000.json','["紛紛帝族貴，欽茲神秀門。", "永嘉分奕葉，甚盛二枝蕃。", "吾友天樂翁，實惟游之孫。", "身雖羈旅盡，詩則騷雅存。", "姪行有科第，作尉期高騫。", "是曰提刑後，令聞方騰喧。", "大心欲圖南，小枝不在言。", "十年相聚首，偉論孰敢援。", "交比鮑叔知，志許諸葛論。", "分携乃明發，念我守故園。", "君往夫差國，不遣吳水渾。", "陸靜翫蟾彩，江清烹鮈豚。", "邑宰話鄉曲，官廨如荒村。", "昂藏信多暇，時憶朋友樽。", "窮達委天命，守道無競奔。", "會當春風吹，梅實衆花繁。"]'),
('f2ef6d41-3c25-4113-b5f9-a871f61ae499','挽徐道暉','薛師石','宋','宋诗','song-poetry','','[]','昌黎銘最好，朋友更情深。',48,'全唐诗/poet.song.190000.json','["昌黎銘最好，朋友更情深。", "身沒復何憾，家貧自不禁。", "春山無死草，夏木有清陰。", "爲鬼詩還別，重來何處尋。"]'),
('147a33e2-9197-4074-81f8-e0f343868f1f','漁家','薛師石','宋','宋诗','song-poetry','','[]','小舟輕似葉，曾不畏風濤。',48,'全唐诗/poet.song.190000.json','["小舟輕似葉，曾不畏風濤。", "自說磻溪好，翻疑釣瀨高。", "晚來魚換酒，歸去子持篙。", "定是逃名者，時聞歌楚騷。"]'),
('cc11189d-a067-43c3-9da6-a7a90ced49b5','梅雨','薛師石','宋','宋诗','song-poetry','','[]','梅雨潤兼旬，暑月不知夏。',168,'全唐诗/poet.song.190000.json','["梅雨潤兼旬，暑月不知夏。", "溪流三尺强，舟人驚昨夜。", "余家有瓜田，蘋藻紛揉藉。", "魚蝦失憑依，跳躍至牀下。", "卑溼畏暮年，扶策升臺榭。", "難願方丈食，互市物踴價。", "四隣各淒涼，惟有酒可借。", "五月藉新白，咀嚼勝棗炙。", "閉門人事絕，向晚烏巾卸。", "震雷壓不住，神龍未遑暇。", "或謂蛟爲孽，胡不寧爾舍。", "旱澇政本農，偏惠及閒架。", "皇天無所私，未遽損禾稼。", "一洗天下清，作我聖人化。"]'),
('89c96370-9b22-4d6c-8ad1-7dce1c243084','謝陳水雲寄惠瓜廬字','薛師石','宋','宋诗','song-poetry','','[]','我向村中住，無人知姓名。',48,'全唐诗/poet.song.190000.json','["我向村中住，無人知姓名。", "結廬難得就，種樹幾時成。", "扁榜龍蛇動，飛簷燕雀驚。", "自憐幽僻地，因此亦敷榮。"]'),
('e646d4c1-5f43-496e-88a4-8278a9104028','和梅氏西澗韵','薛師石','宋','宋诗','song-poetry','','[]','此處宜新月，開門必向西。',48,'全唐诗/poet.song.190000.json','["此處宜新月，開門必向西。", "近江潮有信，初種樹猶低。", "何日尋梅隠，移船繫柳堤。", "詩篇滿窗戶，留壁待余題。"]'),
('54fb58d6-06a8-4ceb-a101-742cfe6add81','秋晚寄趙紫芝','薛師石','宋','宋诗','song-poetry','','[]','數日秋風冷，丘園獨自身。',48,'全唐诗/poet.song.190000.json','["數日秋風冷，丘園獨自身。", "閒看籬下菊，忽憶社中人。", "苦詠肩常瘦，移家債又新。", "極知君淡泊，十載得相親。"]'),
('a3ab90d9-8a87-4882-a435-c936df6f767a','送王成叟先生訪丁子植','薛師石','宋','宋诗','song-poetry','','[]','老懶無拘檢，一年身耐貧。',48,'全唐诗/poet.song.190000.json','["老懶無拘檢，一年身耐貧。", "還思溫嶺去，別我苦吟人。", "柳色行三月，雩風浴暮春。", "舊時同學友，迎拜綠袍新。"]'),
('3f41123d-b557-4e41-b451-1c2732a89fb1','和葛天民','薛師石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','賈島文章懷素書，得來讀罷卷還舒。',64,'全唐诗/poet.song.190000.json','["賈島文章懷素書，得來讀罷卷還舒。", "西湖柳下爲君宅，東海雲邊是我廬。", "千里江山常若此，一生心抱欲何如。", "相思唯有加餐食，不暇逢人寄鯉魚。"]'),
('4e292eb8-294c-4efe-b30d-bdde72238765','戲贈趙天樂','薛師石','宋','宋诗','song-poetry','','[]','問隠當時意已深，近來全廢是清吟。',64,'全唐诗/poet.song.190000.json','["問隠當時意已深，近來全廢是清吟。", "一春祗爲風雷變，盡日閒觀天地心。", "聞道丹爐初候火，能教瓦礫化成金。", "果然成得知何用，不似瓜廬種紫蔘。"]'),
('f259c357-d2f1-4baa-b9f8-4e31738eddc9','孤山','薛師石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不到西湖今幾時，十年雙鬢欲如絲。',32,'全唐诗/poet.song.190000.json','["不到西湖今幾時，十年雙鬢欲如絲。", "難尋和靖題詩處，空見梅花成老枝。"]'),
('5e09bd6b-3f39-46b6-8c7a-a217fd2442a2','望夫石','薛師石','宋','宋诗','song-poetry','','[]','望夫一望幾千年，蒼蘚何曾似翠鈿。',32,'全唐诗/poet.song.190000.json','["望夫一望幾千年，蒼蘚何曾似翠鈿。", "却是春深更風雨，滿身吹淚使人憐。"]'),
('925816a8-4510-455e-adf3-93e5d92fc511','喜翁卷歸','薛師石','宋','宋诗','song-poetry','','[]','我老寡儔侶，年荒值冬迫。',168,'全唐诗/poet.song.190000.json','["我老寡儔侶，年荒值冬迫。", "膝下有啼寒，瓶中無儲積。", "豈不展轉思，自欠經營策。", "儒冠匪謬誤，賦性素褊窄。", "淵明疑夙世，荷鋤心便適。", "嗟余四友朋，驚見三化魄。", "一翁尚淒涼，六秩困行役。", "家貧病難愈，詩苦髮全白。", "昨來叩我門，偶往比鄰宅。", "聞語亟倒屣，已去倏無迹。", "知君懷百憂，雖出難久客。", "從今幸安居，況有舊泉石。", "清晨過窮廬，竟夕話疇昔。", "逝者已云遠，相期守枯瘠。"]'),
('fce246e7-3497-48f4-bf71-f1f5fde93ee5','寄題趙十四知縣聽雨堂','薛師石','宋','宋诗','song-poetry','','[]','誰彈石上琴，涓涓流水響。',48,'全唐诗/poet.song.190000.json','["誰彈石上琴，涓涓流水響。", "主人性清曠，靜夜發幽想。", "何心指蓬閬，取近對湫蕩。", "應有可人來，煙蓑曳雙槳。"]'),
('c431e5ac-5161-417b-8efa-8c2521d9b20b','塔山和徐道暉壁間韵','薛師石','宋','宋诗','song-poetry','','[]','寺在一山頂，江分兩岸田。',48,'全唐诗/poet.song.190000.json','["寺在一山頂，江分兩岸田。", "憑何發詩興，題字古廊邊。", "近地今埋骨，閒人亦助錢。", "昨宵留宿意，不忍上歸船。"]'),
('a06e518f-283b-4bec-9a68-65a769ea527c','送葉宰赴豐城','薛師石','宋','宋诗','song-poetry','','[]','君往爲官處，江西寇已平。',48,'全唐诗/poet.song.190000.json','["君往爲官處，江西寇已平。", "獄閒空劍氣，堂靜響琴聲。", "有法催常稅，無私得衆情。", "時方急賢路，名定達公卿。"]'),
('a741ffd3-f711-4379-926c-3185f4915556','喜徐璣至','薛師石','宋','宋诗','song-poetry','','[]','榮滿自南歸，曾過秦系廬。',48,'全唐诗/poet.song.190000.json','["榮滿自南歸，曾過秦系廬。", "無心緣見道，會面只如初。", "詩好多人說，官清得薦書。", "柴門勞顧訪，未覺四年疎。"]'),
('ee6f2724-5166-44bb-bc64-4f3396945a70','送蔣肖韓','薛師石','宋','宋诗','song-poetry','','[]','岳陽有仙跡，君去頗相宜。',48,'全唐诗/poet.song.190000.json','["岳陽有仙跡，君去頗相宜。", "已料官閒日，多吟湘水詩。", "高風琴斷裂，白月酒漣漪。", "無意求人薦，惟應我自知。"]'),
('392d0ff1-bc7d-409e-bd8b-e99eb7fdfe54','懷趙紫芝','薛師石','宋','宋诗','song-poetry','','[]','日沈月上暝煙斜，收拾漁竿恰到家。',32,'全唐诗/poet.song.190000.json','["日沈月上暝煙斜，收拾漁竿恰到家。", "爲憶城南清瘦友，寒宵夢裏見梅花。"]'),
('9d8ce20d-6841-4e79-ac24-4590c8513ec8','至日遊湖','薛師石','宋','宋诗','song-poetry','','[]','此心全剝落，今日一陽生。',48,'全唐诗/poet.song.190000.json','["此心全剝落，今日一陽生。", "自分安身計，難逃素隠名。", "貧中聞道徹，閒裏作詩清。", "別有求魚者，笑余憂思盈。"]'),
('700b2b4e-5acc-41db-9bf4-0fad95f05648','自題','薛師石','宋','宋诗','song-poetry','','[]','半生作計在田廬，習懶何曾好讀書。',32,'全唐诗/poet.song.190000.json','["半生作計在田廬，習懶何曾好讀書。", "誰却畫作古人樣，旁邊還是欠犂鉏。"]'),
('edb360a1-f054-473f-8275-66202bff8e78','送謝强學主建德簿','薛師石','宋','宋诗','song-poetry','','[]','少年初試吏，濯印富春亭。',48,'全唐诗/poet.song.190000.json','["少年初試吏，濯印富春亭。", "水可清人骨，山曾隠客星。", "俸廉專母養，政簡靜公庭。", "守是賢侯子，應看薦墨青。"]'),
('93296a2e-f3ea-495e-bc85-ef36b3abf0f7','寄題趙紫芝墓','薛師石','宋','宋诗','song-poetry','','["\u897f\u6e56"]','辛未聯詩別，九年成恍惚。',108,'全唐诗/poet.song.190000.json','["辛未聯詩別，九年成恍惚。", "大星墜地旋無光，君身入土名不沒。", "吳越之水相交流，寂寞詩魂何處遊。", "不聞孤鶴喚人醒，空見梅花似人影。", "無復東巖招謝客，應住西湖伴和靖。", "世上如今一句無，一靈獨存勢欲孤。", "我有生芻來未得，只愁宿草易荒蕪。"]'),
('2f8d5ff7-dfd5-4173-9a48-c33231676f22','贈奭山人','薛師石','宋','宋诗','song-poetry','','[]','何人養道得如君，房接高樓半入雲。',64,'全唐诗/poet.song.190000.json','["何人養道得如君，房接高樓半入雲。", "山地栽梅寒蘂瘦，瓦爐留火夜香熏。", "看經尋義心逾靜，默坐觀身耳不聞。", "莫道門前是廛市，須知喧寂此中分。"]'),
('6fa04db3-051a-4c79-926a-183f54639bac','哀徐致中','薛師石','宋','宋诗','song-poetry','','[]','亡友如今隔杳冥，畫身只見病時形。',64,'全唐诗/poet.song.190000.json','["亡友如今隔杳冥，畫身只見病時形。", "書窗閉久梅添潤，花徑荒來草又青。", "一卷詩編空就緒，兩年文會覺凋零。", "幾迴行過深深巷，不忍登堂不扣扃。"]'),
('53f2ee9b-1b18-46b6-be63-e429e6a95872','送薛泳','薛師石','宋','宋诗','song-poetry','','[]','病裏風光總虛擲，岸花園柳雨中休。',32,'全唐诗/poet.song.190000.json','["病裏風光總虛擲，岸花園柳雨中休。", "無端好客隨春去，送酒吟詩一併愁。"]'),
('968c2623-f87b-497e-ac8e-4654fd2f79ec','楊柳枝  其一','薛師石','宋','宋诗','song-poetry','','[]','門前楊柳君莫折，長於折處生兩枝。',32,'全唐诗/poet.song.190000.json','["門前楊柳君莫折，長於折處生兩枝。", "兩枝難作一枝合，一心分作兩心時。"]'),
('0a8c019c-c921-49e8-beb6-3e0b98b80228','楊柳枝  其二','薛師石','宋','宋诗','song-poetry','','[]','唯有高枝高莫攀，不堪攀處只堪看。',32,'全唐诗/poet.song.190000.json','["唯有高枝高莫攀，不堪攀處只堪看。", "怪得樓頭畫眉婦，春朝長自凭闌干。"]'),
('94833aaa-6235-4c22-a45b-2810b4ac3f6d','楊柳枝  其三','薛師石','宋','宋诗','song-poetry','','[]','獨於高處接陽和，占得春風分外多。',32,'全唐诗/poet.song.190000.json','["獨於高處接陽和，占得春風分外多。", "須信繁華易摧折，不如柔弱拂江河。"]'),
('019f825d-3293-42fa-8d84-90b66ccec02f','楊柳枝  其四','薛師石','宋','宋诗','song-poetry','','[]','汴水堤邊薪可束，永豐巷口綠成堆。',32,'全唐诗/poet.song.190000.json','["汴水堤邊薪可束，永豐巷口綠成堆。", "盛衰到底皆惆悵，何不移根種馬嵬。"]'),
('adf736a3-6d94-468a-b0fc-11f90e42eafc','橫參樓和老杜韵','薛師石','宋','宋诗','song-poetry','','[]','僻懶便幽處，江湖稱隠心。',120,'全唐诗/poet.song.190000.json','["僻懶便幽處，江湖稱隠心。", "地偏欣改觀，樓豁喜初臨。", "暖日低輕帽，良朋接短襟。", "潮聲全有韵，帆影半回陰。", "翠麓添重色，鱸風出淺林。", "嶼頭煙瘴遠，沙觜浪痕深。", "寂靜雲歸壑，瓓珊月近參。", "人家已鼾睡，漁父尚謳吟。", "造化由來久，周迴忽見今。", "愛他斜日照，顛倒數山沈。"]'),
('721200ad-d5b8-4acf-a864-feb22b1dfd5e','湖上','薛師石','宋','宋诗','song-poetry','','[]','勢利絕交初，瞿然卧隠廬。',48,'全唐诗/poet.song.190000.json','["勢利絕交初，瞿然卧隠廬。", "無營心淡泊，見客禮生疎。", "遊有漁樵伴，看多佛老書。", "春深草易長，忘却倩人鋤。"]'),
('4c7dfa1c-a123-45bc-97fe-a79a0537505d','宿瞿溪','薛師石','宋','宋诗','song-poetry','','[]','船泊溪西岸，人家見晚舂。',48,'全唐诗/poet.song.190000.json','["船泊溪西岸，人家見晚舂。", "疎星寒有鴈，村寺夜無鐘。", "竹徑通新店，茅柴煖病容。", "農夫不相識，問我欲何從。"]'),
('302f4201-4aff-4f8f-9dac-ec122dc23de6','送從善雲遊','薛師石','宋','宋诗','song-poetry','','[]','鴈蕩天台去，閒尋倚杖藤。',48,'全唐诗/poet.song.190000.json','["鴈蕩天台去，閒尋倚杖藤。", "路邊應得句，禪坐似無能。", "頂笠偏愁雪，山猿不畏僧。", "儻逢清塞伴，休願入傳燈。"]'),
('648d02cd-a931-466e-b5a2-517a13385df5','多景樓','薛師石','宋','宋诗','song-poetry','','[]','跨浙連淮是潤州，好山全對此江樓。',32,'全唐诗/poet.song.190000.json','["跨浙連淮是潤州，好山全對此江樓。", "少年志氣慚霜鬢，猶憶曾看打陣舟。"]'),
('e5498d2b-5ac7-4261-8564-7adbce0ca68a','送法照','薛師石','宋','宋诗','song-poetry','','[]','論著天台教，詩參左緯來。',48,'全唐诗/poet.song.190000.json','["論著天台教，詩參左緯來。", "閒行過蓬蓽，相對坐莓苔。", "講席虛前月，重遊約後迴。", "仍聞藏禊帖，應許爲吾開。"]'),
('f5d09f33-7f1e-4a9f-92bb-43cf4f1c4815','送子舒弟赴金陵兼柬宋君輔','薛師石','宋','宋诗','song-poetry','','[]','祿仕何方好，金陵總莫如。',48,'全唐诗/poet.song.190000.json','["祿仕何方好，金陵總莫如。", "廟存元帝像，家有二王書。", "羽檄時方急，文才用有餘。", "功名收拾了，歸食會昌魚。"]'),
('a20edf40-ba6d-4a2c-a325-27998bd428fb','送夏肯父','薛師石','宋','宋诗','song-poetry','','[]','霜晴鴈蕩白，五日計鄉程。',48,'全唐诗/poet.song.190000.json','["霜晴鴈蕩白，五日計鄉程。", "野燒明山店，輕輿憇嶺平。", "乞銘甘久客，愛母起歸情。", "孝極天爲感，師文早晚成。"]'),
('aef58d73-3f35-4b69-9f05-4a39dcb8361c','挽林敬之','薛師石','宋','宋诗','song-poetry','','[]','閉門常讀易，遯世意如何。',48,'全唐诗/poet.song.190000.json','["閉門常讀易，遯世意如何。", "有酒可消悶，無階不種莎。", "閒時尋舊友，月夜步新河。", "我亦逃名者，題碑愧爾多。"]'),
('c57e6258-4bbe-4ac2-ace3-041d76cd8a40','金賢良','薛師石','宋','宋诗','song-poetry','','[]','虛號賢良豈療饑，短衣結袖竟何爲。',64,'全唐诗/poet.song.190000.json','["虛號賢良豈療饑，短衣結袖竟何爲。", "空携痛哭能言策，不遇勤求下詔時。", "老去說詩猶有味，寒來索酒莫教遲。", "家貧身死知無計，自有傍人爲立碑。"]'),
('4651022e-c8ee-44b5-aae1-90aaffb21c11','學海樓和水心先生韵','薛師石','宋','宋诗','song-poetry','','[]','江口潮生夜語喧，月殘唯有數星存。',32,'全唐诗/poet.song.190000.json','["江口潮生夜語喧，月殘唯有數星存。", "更憑高處觀空闊，始悟乾坤是易門。"]'),
('09cd5e17-fce5-4ae1-847f-2deb3320012b','下仙勝因寺有懷','薛師石','宋','宋诗','song-poetry','','[]','山中初寄隠，野寺一天星。',48,'全唐诗/poet.song.190000.json','["山中初寄隠，野寺一天星。", "路遠有如此，客來應未能。", "蛩催寒嫗緯，蟬雜夜僧經。", "忽憶忘形友，微吟自剔燈。"]'),
('43f3a6a0-dec5-4899-87da-e3f7cd24e5e6','趙成子','薛師石','宋','宋诗','song-poetry','','[]','早年名字諸公並，唯有清聲獨至今。',64,'全唐诗/poet.song.190000.json','["早年名字諸公並，唯有清聲獨至今。", "辭却雙旌更何事，自扶靈壽欲閒吟。", "病來便作雲歸岫，死矣猶如鶴在陰。", "終始哀榮了無恨，只愁塵鏁匣中琴。"]'),
('0cc52bfa-321a-4667-b5bc-597caadff402','送文子監草料場','薛師石','宋','宋诗','song-poetry','','[]','坐局何煩聽曉鷄，豆萁苜蓿亦詩題。',64,'全唐诗/poet.song.190000.json','["坐局何煩聽曉鷄，豆萁苜蓿亦詩題。", "好文不愛今人體，色養寧嫌古署低。", "翰苑舊交應顧訪，相門新近事招携。", "歲寒惟有君於我，老去過從許杖藜。"]'),
('ffa96b25-571c-47c7-811d-ea47c65ced70','寄鴈蕩詩僧','薛師石','宋','宋诗','song-poetry','','[]','鴈蕩峰前夜雨晴，空房不住有蟬聲。',64,'全唐诗/poet.song.190000.json','["鴈蕩峰前夜雨晴，空房不住有蟬聲。", "一身閒後髮難白，五字吟來思極清。", "少見出山多入定，還於夏末起秋程。", "何如更待黄花節，顧我來遊計已成。"]'),
('4af24e1c-06f8-45c0-8ca9-19f3aaf0637f','李白墓','薛師石','宋','宋诗','song-poetry','','[]','野火燒殘竹數枝，詩魂飄蕩定何之。',32,'全唐诗/poet.song.190000.json','["野火燒殘竹數枝，詩魂飄蕩定何之。", "娟娟秋月照采石，不在荒墳在水湄。"]'),
('9f06d308-ddf7-4b51-a27c-a000d061b2f1','漁父二首  其一','薛師石','宋','宋诗','song-poetry','','[]','偶來浦口芰荷香，綠葉叢中睡一場。',32,'全唐诗/poet.song.190000.json','["偶來浦口芰荷香，綠葉叢中睡一場。", "須信至人無妄想，不曾有夢見文王。"]'),
('674f0cdd-edc9-4344-a45f-109b589314b0','漁父二首  其二','薛師石','宋','宋诗','song-poetry','','[]','利薄每言隨分過，避名不入愚溪路。',32,'全唐诗/poet.song.190000.json','["利薄每言隨分過，避名不入愚溪路。", "春深雨足釣絲長，夜來又宿蓑衣步。"]'),
('15e90b28-1d7c-4a2d-ae76-90b1fdb1d2f5','州讌席上賦牡丹得日字','薛師石','宋','宋诗','song-poetry','','[]','粉淡與妖紅，占盡陽和出。',48,'全唐诗/poet.song.190000.json','["粉淡與妖紅，占盡陽和出。", "春去在商量，更費吟人筆。", "此是洛陽花，尚带長安日。", "持上使君墀，寶瓶分甲乙。"]'),
('90f18110-a209-49c2-9383-55b28acad8bb','寄龍虎山道士孔野雲','薛師石','宋','宋诗','song-poetry','','[]','上清三十六，院閣皆幽清。',60,'全唐诗/poet.song.190000.json','["上清三十六，院閣皆幽清。", "漱齒泉新汲，晞髮日始昇。", "自除燒墨竈，晝夕誦黄庭。", "所得異疇昔，出山畏逢迎。", "同當知非年，寄詩聊寫情。"]'),
('fbbe9542-db73-4795-b0ac-111a7d87803d','夜坐陳縕靈見訪','薛師石','宋','宋诗','song-poetry','','[]','清夜焚香篆，閒看郊島詩。',48,'全唐诗/poet.song.190000.json','["清夜焚香篆，閒看郊島詩。", "自憐多冷寞，誰足慰衰遲。", "樹雪明窗紙，瓶梅落硯池。", "君心亦無事，相對坐移時。"]'),
('5fb9e3b5-f274-4b02-843c-995e6c7956ec','送翁靈舒閒遊','薛師石','宋','宋诗','song-poetry','','[]','袖有新詩如美玉，知君去意十分濃。',64,'全唐诗/poet.song.190000.json','["袖有新詩如美玉，知君去意十分濃。", "山行見草認靈藥，午歇就陰依古松。", "兩鬢已添蓬蔂色，三年判作飄零蹤。", "羈情夜後更愁絕，深澗斷猿溪寺鐘。"]'),
('0645b8dd-98f1-4fb3-93e9-02ac319f378c','先寄郭子奇','薛師石','宋','宋诗','song-poetry','','[]','世道祗如此，君心我得知。',48,'全唐诗/poet.song.190000.json','["世道祗如此，君心我得知。", "先教栽菊在，預作去官期。", "夢覺秋風起，行吟夜月遲。", "懷人幾十載，欣有扣門時。"]'),
('5be21136-1b28-4fa9-b726-dee8b0351792','喜葉謙夫歸','薛師石','宋','宋诗','song-poetry','','[]','老思忽蕭爽，親朋得意歸。',48,'全唐诗/poet.song.190000.json','["老思忽蕭爽，親朋得意歸。", "菊觴奉親壽，柳色上儒衣。", "宅旺看山勢，門清有釣磯。", "我來聊問字，澹坐月侵扉。"]'),
('1eb286e0-34ac-4cfd-bba6-e00e97cdf377','挽潘母','薛師石','宋','宋诗','song-poetry','','[]','獨翫隔廳月，淒涼三十年。',48,'全唐诗/poet.song.190000.json','["獨翫隔廳月，淒涼三十年。", "渺然儒素業，翻以母儀傳。", "生計無中有，衰齡病後延。", "誰爲市貞石，高刻墓之前。"]'),
('f73f6faf-795e-4071-9326-b45c093de2aa','送趙主簿','薛師石','宋','宋诗','song-poetry','','[]','內地無烽火，詩人入仕林。',48,'全唐诗/poet.song.190000.json','["內地無烽火，詩人入仕林。", "定將詠物意，移作愛民心。", "晤語初同調，分携便不禁。", "卜鄰曾有約，久後得相尋。"]'),
('d458a833-ea03-4f42-b5bb-d6705250fe15','送陳器之赴紹興初官','薛師石','宋','宋诗','song-poetry','','[]','郡古湖如鏡，照人心膽清。',48,'全唐诗/poet.song.190000.json','["郡古湖如鏡，照人心膽清。", "閒曹應事簡，盡日讀書聲。", "府主舊知舉，同僚親弟兄。", "人言遊宦樂，難得比君榮。"]'),
('32de5616-8ce2-44ec-b430-9246d799c525','哭周宗彝','薛師石','宋','宋诗','song-poetry','','[]','已歎交情看漸少，聞君怛化重傷神。',64,'全唐诗/poet.song.190000.json','["已歎交情看漸少，聞君怛化重傷神。", "手栽寒竹惟添笋，堂掩空山不見人。", "舊說媾婚今且置，新懷情悃向誰陳。", "獨憐頭白曾參母，清夜悲號血淚頻。"]'),
('2db82bf2-a7d3-4566-9b86-f90df147777a','送項季約入成都幕','薛師石','宋','宋诗','song-poetry','','[]','閣書入兵幕，束袖學戎裝。',48,'全唐诗/poet.song.190000.json','["閣書入兵幕，束袖學戎裝。", "峽峭艬侵月，秋清猿嗛霜。", "迂程看陣磧，到處宿詩堂。", "若比仲宣樂，輸君髮未蒼。"]'),
('dede2fac-08bc-40e2-bc24-18aec2ff6a92','送郭子奇','薛師石','宋','宋诗','song-poetry','','[]','永嘉官滿後，歸處是仙居。',48,'全唐诗/poet.song.190000.json','["永嘉官滿後，歸處是仙居。", "柳舞陶潛徑，桃迎阮肇車。", "名高唐寺塔，篋滿晉人書。", "看步青雲上，題緘寄隠廬。"]'),
('acae91d5-7153-432f-b2ff-0f09d45c8543','送趙澤民赴酃縣','薛師石','宋','宋诗','song-poetry','','[]','高人爲令尹，政事豈尋常。',48,'全唐诗/poet.song.190000.json','["高人爲令尹，政事豈尋常。", "炎月不避暑，清風心自涼。", "水流衡嶽色，酒带芷蘭香。", "遠想濯纓暇，思予有詠章。"]'),
('71141da4-5993-4d01-baed-03abeb9d05aa','大龍湫','薛師石','宋','宋诗','song-poetry','','[]','昔聞天下山，衡嶽稱崇丘。',240,'全唐诗/poet.song.190000.json','["昔聞天下山，衡嶽稱崇丘。", "又聞天下水，江漢爲巨流。", "古有山海經，歷歷敘九州。", "李唐三百載，詩家無一留。", "及觀酈道元，此地亦不收。", "不知諾矩那，何事能窮搜。", "我來玄妙境，萬丈懸清湫。", "石壁去無極，百里彌道周。", "雲氣冒羣岫，龍宮深以幽。", "輕輿巖壑底，竟日涉溪游。", "陰晴異瞻矚，遠近難搜摟。", "飄如飛素練，粲若散琳璆。", "風掀一潭雨，佛坐四時秋。", "喧呼勢益驟，洶湧聲彌吼。", "變化有如此，溥博誰與儔。", "吾謂神龍力，豈翳人鬼謀。", "稽首荷玄遇，久坐勞雙眸。", "一盃却嵐暑，旋步轟雷稠。", "以吾澹世慮，欻起杞人憂。", "何當騎天狼，滿引射斗牛。"]'),
('267bcc23-be35-4f3a-a287-66593c9af0d8','斷橋','薛師石','宋','宋诗','song-poetry','','[]','獨扶瘦杖欲經過，爲問高僧意若何。',32,'全唐诗/poet.song.190000.json','["獨扶瘦杖欲經過，爲問高僧意若何。", "自倚神通能渡水，却言佛法本無多。"]'),
('9de3f4e2-0a10-4ee7-9b49-0724cca1ca28','寒山寺壞莊産盡爲勢家所奪余遊天台甚爲普賢惜之陳約甫攝郡號不畏彊禦者必能與寒山出氣','薛師石','宋','宋诗','song-poetry','','[]','寒山寺廢佛燈寒，有客來遊欲住難。',32,'全唐诗/poet.song.190000.json','["寒山寺廢佛燈寒，有客來遊欲住難。", "夙世閭丘今攝郡，不妨饒舌似豐干。"]'),
('b82f5e2b-d7b9-4d6f-be6a-a660faea6adf','哭劉詠道','薛師石','宋','宋诗','song-poetry','','[]','案上韓文與杜詩，小齋閒澹亦相宜。',64,'全唐诗/poet.song.190000.json','["案上韓文與杜詩，小齋閒澹亦相宜。", "人憐貧病憂無計，自說文章樂未涯。", "禮合古初山友哭，袝從先世夕郎知。", "生平直諒嗟何往，不是哀辭是誄辭。"]'),
('8d880a60-3bbb-48a2-94f1-b7cf4d5ab56b','送張直翁','薛師石','宋','宋诗','song-poetry','','[]','宰公詩句是騷人，官舍況臨湘水濱。',64,'全唐诗/poet.song.190000.json','["宰公詩句是騷人，官舍況臨湘水濱。", "衡嶽望中思策蹇，滄浪清甚欲垂綸。", "長於一縣花開後，獨訪三閭廟裏頻。", "元亮何曾藉知己，翩然出處自由身。"]'),
('d8642e02-c375-44d1-a8d9-c80ddf5b0b41','送王倅之興化','薛師石','宋','宋诗','song-poetry','','[]','梅溪好源委，流德至今存。',48,'全唐诗/poet.song.190000.json','["梅溪好源委，流德至今存。", "獨繼賢人業，共推君子孫。", "官清五字好，州小貳車尊。", "所歷七閩郡，從茲水不渾。"]'),
('7ad02617-edec-4b6b-b2ce-8cc5f3046b15','挽趙孺人余中表也','薛師石','宋','宋诗','song-poetry','','[]','幼小同羣戲，年加各所之。',48,'全唐诗/poet.song.190000.json','["幼小同羣戲，年加各所之。", "常疑豔花卉，終是易離披。", "夫壻新袍綠，兒男半髮垂。", "送歸蒿里道，興我渭陽思。"]'),
('1199df99-38d1-4dec-a9d8-730ceffc4b30','趙叔魯端行胡象德携酒見顧','薛師石','宋','宋诗','song-poetry','','[]','一賢二公子，枉駕瓜廬丘。',60,'全唐诗/poet.song.190000.json','["一賢二公子，枉駕瓜廬丘。", "烹魚載美酒，竟夕爲我留。", "評詩仍和曲，舉白不計籌。", "情忘覺歡暢，禮厚愧莫酬。", "今朝風雨橫，欲謝出無由。"]'),
('ac695264-0d2a-4060-9641-1b0b0a84e131','挽徐左史','薛師石','宋','宋诗','song-poetry','','[]','左史聲名空復存，如今往事不堪論。',64,'全唐诗/poet.song.190000.json','["左史聲名空復存，如今往事不堪論。", "惟應指佞當前陛，已判身歸老故園。", "驄馬引喪寒有淚，麒麟卧塚寂無言。", "人生遇合萍相似，何處分明怨與恩。"]'),
('9d1d1c3b-66dd-416d-b65e-44b308d97b4a','送鮑份父','薛師石','宋','宋诗','song-poetry','','[]','地僻官仍小，茲行古迹多。',48,'全唐诗/poet.song.190000.json','["地僻官仍小，茲行古迹多。", "矩羅應失笑，龐媼亦經過。", "宦業知餘事，宗風竟若何。", "□□□□□，滿舍是青莎。"]'),
('3d78bae8-8524-441e-a249-8d82dec5d0ea','挽張彥文提舉','薛師石','宋','宋诗','song-poetry','','[]','七十童顔在，翛然物外幽。',48,'全唐诗/poet.song.190000.json','["七十童顔在，翛然物外幽。", "組衣藏蠹篋，散服上漁舟。", "此日移松葬，前時爲菊留。", "山連象浦館，誰記孟家遊。"]'),
('fe0350e1-f06d-47ec-b0fb-96a8a435cf3d','浄光長老極能詩','薛師石','宋','宋诗','song-poetry','','[]','近住城中寺，陰雲漬竹房。',48,'全唐诗/poet.song.190000.json','["近住城中寺，陰雲漬竹房。", "雨多香篆久，春去藥苗芳。", "室裏從人問，吟邊與世忘。", "一身全是道，頭白有何妨。"]'),
('e3044567-9be8-40c1-8683-d866cc716c26','朱清之','薛師石','宋','宋诗','song-poetry','','[]','漈水日夜白，之人信所宜。',48,'全唐诗/poet.song.190000.json','["漈水日夜白，之人信所宜。", "隠於陶令酒，甘謝郗詵枝。", "江渡月偏滿，家庭歲有規。", "不知君沒後，誰主菊花期。"]'),
('fd5d7c99-4c73-4a13-9795-37d880cf65ff','送蔣肖韓赴弋陽','薛師石','宋','宋诗','song-poetry','','[]','弋水橋邊接長官，水晶山色讓清寒。',64,'全唐诗/poet.song.190000.json','["弋水橋邊接長官，水晶山色讓清寒。", "共知彫弊今稱劇，自倚廉勤道不難。", "吏退早衙花谷靜，鶴翔秋戺訟庭寬。", "從來遇事無凝滯，應只憂民勞寸丹。"]'),
('539a9acd-dbcc-47ef-84d4-35992d448f85','送謹師','薛師石','宋','宋诗','song-poetry','','[]','謹師牢絆脚，語別意茫茫。',48,'全唐诗/poet.song.190000.json','["謹師牢絆脚，語別意茫茫。", "入寺春隨杖，當禪月滿牀。", "多因新見解，拋却舊篇章。", "爲我金山去，鉗鎚問一場。"]'),
('7694f4ff-69f1-4cd9-a380-d48ed15e322e','挽宋耆卿','薛師石','宋','宋诗','song-poetry','','[]','人如韞玉操如冰，拾芥推梨世豈能。',64,'全唐诗/poet.song.190000.json','["人如韞玉操如冰，拾芥推梨世豈能。", "案上有琴亡舊響，墓頭無火續寒燈。", "一官祗是幽閒過，百行惟須健筆稱。", "此曲調高知者少，朗吟喚得九原譍。"]'),
('ce6013a6-9bc1-42e5-ba7b-82ed2de71478','送高郵周主簿兼呈陳君端','薛師石','宋','宋诗','song-poetry','','[]','遶縣重湖色，難同主簿清。',48,'全唐诗/poet.song.190000.json','["遶縣重湖色，難同主簿清。", "雖云古郵置，不似近邊城。", "月落淮田闊，風晴隋柳輕。", "鄉人在曹職，相得爲詩情。"]'),
('eb250ead-8c04-4197-a10c-cde1f25aa781','寄守上人歸閩省親','薛師石','宋','宋诗','song-poetry','','[]','從小服緇素，三衣竟不長。',48,'全唐诗/poet.song.190000.json','["從小服緇素，三衣竟不長。", "心空無物礙，頂重有詩囊。", "去與雲相似，來期春未央。", "家山指萱草，微笑奉高堂。"]'),
('47576031-a15f-435f-ac9a-0357a64ca7fc','無題','薛師石','宋','宋诗','song-poetry','','[]','平生愛菊與梅花，菊比淵明梅似逋。',32,'全唐诗/poet.song.190000.json','["平生愛菊與梅花，菊比淵明梅似逋。", "誰知此道今寥落，愛菊愛梅人也無。"]'),
('71fc8275-7ae6-48b0-af5b-3e65ee69857e','戊子七月十一日','薛師石','宋','宋诗','song-poetry','','[]','貧因幾首詩，閒高一著棋。',24,'全唐诗/poet.song.190000.json','["貧因幾首詩，閒高一著棋。", "瓜田常嘿坐，不願有人知。"]'),
('17ea02af-4989-49bd-bd79-ae49a8a0e967','句  其一','薛師石','宋','宋诗','song-poetry','','[]','半洞容千佛，諸峰共一雲。',12,'全唐诗/poet.song.190000.json','["半洞容千佛，諸峰共一雲。"]'),
('545edfaf-2061-40f4-843c-67c3df587c8a','句  其二','薛師石','宋','宋诗','song-poetry','','[]','泉涌龍頻躍，山靈鳥不來。',12,'全唐诗/poet.song.190000.json','["泉涌龍頻躍，山靈鳥不來。"]'),
('6ac357b2-46fb-4880-bf52-411c915867d6','登南嶽山','真德秀','宋','宋诗','song-poetry','','["\u8861\u5c71"]','煙霞本成癖，况復遊名山。',48,'全唐诗/poet.song.190000.json','["煙霞本成癖，况復遊名山。", "舉手招白雲，欲納懷袖間。", "咄哉亦癡絕，有著即名貪。", "振衣遇長風，浩浩天地寬。"]'),
('cd31cfd2-a131-435a-9113-76079283fcfc','題金山','真德秀','宋','宋诗','song-poetry','','[]','江來朱方注之東，海潮怒飛日夕相撞舂。',182,'全唐诗/poet.song.190000.json','["江來朱方注之東，海潮怒飛日夕相撞舂。", "天將古來義士骨，化作狂瀾中央屹立之青峰。", "孤根直下二千尺，動影裊窕沖融中。", "黄金側布蘭若地，鑿翠面面開窗櫳。", "雙橈伊軋破浪屋，恍忽置我高巃嵸。", "是時千山雪新霽，水面月出天清空。", "濤聲四起人籟寂，毛髮蕭爽琉璃宮。", "披衣明發躡煙靄，决眥俯入歸飛鴻。", "襟前渤澥歛暝色，袖裏岷峨吹曉風。", "越南燕北但一氣，塵埃野馬何時窮。", "蒼梧虞舜不可叫，王事更恨歸匆匆。"]'),
('cf4ef281-8919-4818-b614-89401777a74b','送湯伯紀歸安仁','真德秀','宋','宋诗','song-poetry','','[]','交情世豈乏，道合古所難。',180,'全唐诗/poet.song.190000.json','["交情世豈乏，道合古所難。", "自我得此友，清芬襲芝蘭。", "苦語時見箴，微言獲同參。", "相從仁義林，超出名利關。", "此樂未渠央，忽告整征驂。", "索居可柰何，使我喟且嘆。", "至危者人心，易汩惟善端。", "苟無直諒友，戒謹空杅盤。", "重來勿愆期，同盟有青山。", "聖經如杲日，群目仰輝耀。", "利欲滑其中，雲霧隔清照。", "正須澄心源，乃許窺道妙。", "周程千載學，敬靜兩言要。", "幾微察毫芒，根本在奧竅。", "持此當弦韋，迂矣君莫誚。"]'),
('f1721ede-74af-4705-83be-5a2fb3b07f39','送裘司直得請西歸','真德秀','宋','宋诗','song-poetry','','[]','輕舸龍山頭，木蘭作雙櫓。',216,'全唐诗/poet.song.190000.json','["輕舸龍山頭，木蘭作雙櫓。", "飄然裘司直，乘向南昌去。", "問君鵷鸞中，脫身遽如許。", "棲遲三十年，始得官掌故。", "小須上上考，豈不登省戶。", "自言野心性，瞇目九衢霧。", "修竹歲云晚，萱草秋亦暮。", "嗷嗷投林鳥，猶得反其哺。", "江西父母邦，非復昔饒裕。", "蠻煙一腥穢，樂歲且狼顧。", "遺黎空杼軸，行旅窘刀布。", "天門窈萬里，可望不可籲。", "君今佐元帥，精采繫一路。", "瘡痍俟滌濯，畫諾歸佽助。", "先聲路人喜，高節懦夫慕。", "遄當再前席，一正天子度。", "白鷗沒浩蕩，蒼鶻在指呼。", "我亦南陔人，扁舟從此具。"]'),
('a12f680e-12f2-44de-9277-58777bf55564','題八君子圖後','真德秀','宋','宋诗','song-poetry','','[]','劉子出西江，訪我江之東。',96,'全唐诗/poet.song.190000.json','["劉子出西江，訪我江之東。", "何人與偕來，銜袖八鉅公。", "韓歐開濟姿，如晴月生空。", "潞公山嶽重，文正霜檜同。", "玉立者坡仙，天游匪涪翁。", "一朝參我前，毛髮生清風。", "淒其趙韓王，小異凌煙中。", "半山執拗面，亦得傳無窮。"]'),
('35952b8d-1e73-4c0b-9aab-0d714b90c4a5','泉州貢闈慶成','真德秀','宋','宋诗','song-poetry','','[]','維南有州古佛國，選佛場開自疇昔。',224,'全唐诗/poet.song.190000.json','["維南有州古佛國，選佛場開自疇昔。", "誰歟經始梅溪翁，萬桂森森皆手植。", "文風日盛賢材多，粉袍立鵠肩相摩。", "萬間庇士豈不欲，環視柰無餘地何。", "那知吉壤在咫尺，鬼神撝呵天所惜。", "一朝幻出青瑶宮，山靈獻卜龍避席。", "昔虞局促今恢舒，乘黄騁足騰康衢。", "闢新葺舊兩輝映，美哉輪奐雄規橅。", "歲直金虬大魁出，賸喜慶成逢此日。", "來春甲子又一周，天相吾泉真可必。", "蟬聯四坐皆豪英，一樽敬爲諸君傾。", "浮雲富貴靡定態，要看名節留芬馨。", "我今歸作漁樵侶，清夢猶馳筍江滸。", "鳳鳴側耳聽朝陽，把酒空山爲起舞。"]'),
('4bfe63e8-a039-44d9-a35f-72198fa9f402','壬午春社之明日請尊老會于西山之精舍龐眉皓首奕奕相照真吾邦希闊之盛事輒成口號一首併呈諸耆壽且堅異日早退之約云','真德秀','宋','宋诗','song-poetry','','[]','耆年自是國之珍，何間衣冠與隠淪。',64,'全唐诗/poet.song.190000.json','["耆年自是國之珍，何間衣冠與隠淪。", "華髮共成千一歲，清樽相對十三人。", "休談洛社遺風舊，且頌僊游慶事新。", "三徑未荒宜早退，要將壽櫟伴莊椿。"]'),
('380d4e8c-7161-410b-b65d-f23a6e6f9ed3','長沙贈高年陳氏母子','真德秀','宋','宋诗','song-poetry','','[]','陳氏春秋一百一，兒女年皆過七十。',128,'全唐诗/poet.song.190000.json','["陳氏春秋一百一，兒女年皆過七十。", "一門慈孝更雍愉，四老真堪入畫圖。", "長官申聞太守喜，召至階庭加盛禮。", "老萊綵服作兒啼，今視古人更過之。", "老萊一身娛戲耳，况有三兒奉甘旨。", "人言潭俗不古如，君看此事天下無。", "一門高壽何由得，慈孝之人天所惜。", "我願湘民胥傚之，從此九州皆壽域。"]'),
('ec8232d7-d21c-4399-889b-4f80bad32057','長沙新第呈諸學士','真德秀','宋','宋诗','song-poetry','','[]','莫清彼瀟江，莫峻彼衡嶽。',156,'全唐诗/poet.song.190000.json','["莫清彼瀟江，莫峻彼衡嶽。", "澄光挾秀氣，日夜相回薄。", "月吸珠含胎，虹貫玉生璞。", "子方有苗裔，溫然粹而慤。", "一童與三何，雙鳳兩鸑鷟。", "奮身辭草萊，正論吐諤諤。", "彤庭拜恩歸，天香尚盈握。", "良才國之寶，一見我心樂。", "平生功名會，萬里初著脚。", "永肩致主念，更勉經世學。", "錙銖分義利，毫縷辨純駁。", "相期激清風，與俗洗氛濁。", "誰歟指其南，是邦有先覺。"]'),
('1e53629e-fef2-4bd8-bb68-0071ff8f0e66','送林自知自幕中歸常寧','真德秀','宋','宋诗','song-poetry','','[]','始吾與林子，周旋大江東。',228,'全唐诗/poet.song.190000.json','["始吾與林子，周旋大江東。", "子方清且貧，簞瓢屢云空。", "勁氣凜不折，耿耿如長虹。", "明年擢高科，對策大明宮。", "一尉遲五年，出入無奴僮。", "再見湘水濱，凜凜復昔同。", "招徠元戎幕，泛綠依芙蓉。", "小生敢相吏，故人儻相從。", "云胡歲未竟，决去如霜鴻。", "挽之不可留，聊復少從容。", "老我慵且鈍，栽培欠深功。", "子進未可量，德業方崇崇。", "永懷昔君子，和氣填心胸。", "濂溪霽月朗，伊水春風融。", "至今想其人，猶爲起敬恭。", "天資貴强矯，學力無終窮。", "我如石之頑，遲子相磨礲。", "子質雖玉瑩，可廢它山攻。", "雁峰毋久留，來思靈麓峰。"]'),
('196604ff-34d7-40b3-9fbd-3067dd03c243','司理弟之官岳陽相別于定王臺悽然有感爲賦五詩以餞其行  其一','真德秀','宋','宋诗','song-poetry','','[]','定王百尺臺，長安萬里目。',72,'全唐诗/poet.song.190000.json','["定王百尺臺，長安萬里目。", "昔人思親心，山川詎能局。", "於焉共登臨，使我增感觸。", "微霜隕陔蘭，悲風撼庭木。", "銀山在何許，白雲但空谷。", "搔首重徘徊，冥冥江樹綠。"]'),
('c42b7df2-c17b-4e63-a0ba-a651010a2091','司理弟之官岳陽相別于定王臺悽然有感爲賦五詩以餞其行  其二','真德秀','宋','宋诗','song-poetry','','[]','念昔戲綵時，歡娛共晨夕。',72,'全唐诗/poet.song.190000.json','["念昔戲綵時，歡娛共晨夕。", "天風吹驚鴻，一散不並翼。", "相逢重湖南，感歎復悽惻。", "王事不可留，去指重湖北。", "層樓時悵望，茫茫楚天碧。", "數寄平安書，老懷庶寬釋。"]'),
('1912c6f4-c286-4b07-b166-e2d0f6204b0a','司理弟之官岳陽相別于定王臺悽然有感爲賦五詩以餞其行  其三','真德秀','宋','宋诗','song-poetry','','[]','憶我將漕年，適如子今日。',72,'全唐诗/poet.song.190000.json','["憶我將漕年，適如子今日。", "於焉四閏餘，過眼風雨疾。", "壯强豈足恃，進德當汲汲。", "永懷古之人，聞道在四十。", "我慚已過之，因循悼前失。", "子盍猛自鞭，聖門本無柅。"]'),
('0c7595bc-e06a-4945-bd75-a260d7134e6b','司理弟之官岳陽相別于定王臺悽然有感爲賦五詩以餞其行  其四','真德秀','宋','宋诗','song-poetry','','[]','心源本澄靜，皎月懸晴空。',84,'全唐诗/poet.song.190000.json','["心源本澄靜，皎月懸晴空。", "利欲一汩之，晶明變塵矇。", "擾擾千蟯蚘，攢攢萬銛鋒。", "昏冥弗自覺，乃與禽犢同。", "一朝發深省，妙理仍昭融。", "要須大敵勇，鈎援臨崇墉。", "不見簞瓢人，四勿收殊功。"]'),
('996ec508-6aad-4665-becf-9aa80a7d328b','司理弟之官岳陽相別于定王臺悽然有感爲賦五詩以餞其行  其五','真德秀','宋','宋诗','song-poetry','','[]','先民不可見，懷哉金玉音。',84,'全唐诗/poet.song.190000.json','["先民不可見，懷哉金玉音。", "士雖一命微，愛物宜存心。", "矧茲圜扉內，白日變重陰。", "求情箠楚下，冤哉詎能禁。", "謼嘷漫弗省，鬼神爲悲吟。", "子往蒞其職，朝夕惟欽欽。", "謹刑勿留獄，斯語真良箴。"]'),
('92ac6fc2-b498-47a6-aacc-8b6b7ad6cad2','志道生日爲詩勉之','真德秀','宋','宋诗','song-poetry','','[]','我聞洙泗言，惟仁靜而壽。',252,'全唐诗/poet.song.190000.json','["我聞洙泗言，惟仁靜而壽。", "汝欲綿脩齡，斯義盍深究。", "越從開闢來，新故更禪受。", "巍巍獨山嶽，屹立鎮宇宙。", "其體固而安，其形博而厚。", "噓呵雲霧興，涵煦草木茂。", "皆由一靜功，變化生萬有。", "千古無動摇，兩儀等悠久。", "吁嗟人心危，六鑿互攻鬭。", "眇焉方寸微，怵彼羣物誘。", "擾擾無寧期，得不易衰朽。", "汝今志于學，一念貴操守。", "天真浚其源，人僞窒其竇。", "冶容命之斧，妖聲性之寇。", "腊毒由厚味，亂德本醇酎。", "當如禦讎敵，豈但惡惡臭。", "歛然肅襟靈，神物森左右。", "融融湛虛明，役役息紛揉。", "還吾性之仁，萬善此其首。", "但存達德三，可卜與齡九。", "不勝玉女心，持用薦杯酒。"]'),
('553c6080-4f9b-4042-832f-e772d63c2fe5','題全氏三桂堂','真德秀','宋','宋诗','song-poetry','','[]','唐人重科甲，擬以折桂榮。',240,'全唐诗/poet.song.190000.json','["唐人重科甲，擬以折桂榮。", "一登羣仙籍，不羨千佛經。", "終全歲寒姿，乃比秋香清。", "咄彼牛李輩，伊優至公卿。", "迨今齒其人，名字猶臊腥。", "卓哉劉戶曹，直氣霜稜稜。", "一朝脫淡墨，千古揚芬馨。", "鷄峰有名家，奕葉彯儒纓。", "庭中三嘉樹，屹立長寧寧。", "西風正摇落，翠葆黄金英。", "勁節松可友，孤芳梅謂兄。", "丁寧命諸郎，我豈貪浮名。", "愛此臭味同，故以書吾楹。", "爾曹方茂學，志取宮袍青。", "要須勉植立，毋但希騰凌。", "己大外物小，道充人爵輕。", "當如燕山竇，義方垂世評。", "勿效東堂詵，射策矜虛聲。", "懿哉君斯言，可折末俗醒。", "刻詩堂之楣，室觀全氏興。"]'),
('43bfe0b5-7258-4986-9991-af095d25c2c8','壽楊龢父','真德秀','宋','宋诗','song-poetry','','[]','迅雷地中藏，當此沍寒日。',192,'全唐诗/poet.song.190000.json','["迅雷地中藏，當此沍寒日。", "積陰排層空，初陽露微茁。", "而曰天地心，於此見機括。", "良猶勢方升，猶木吐牙枿。", "培壅勿使傷，怒長焉可遏。", "此理之在人，善端實初發。", "熒熒火將燃，涓涓泉欲達。", "吁嗟道心微，物欲易攻奪。", "差之一毫芒，相去舜與桀。", "要須二者間，明辨與精察。", "見義勇必爲，欻如矢之决。", "去惡凜勿疑，剨如刃之割。", "坐令人僞消，但覺天機活。", "四時無非春，八荒皆在闥。", "喜君生茲辰，聊爲演此法。", "願祝君壽長，勿嫌吾詩拙。"]'),
('1f6b310e-5c0e-4e8e-8d9d-4a30244c0e64','舞鶴亭歌','真德秀','宋','宋诗','song-poetry','','[]','舞鶴亭空亭，無鶴胡爲名。',190,'全唐诗/poet.song.190000.json','["舞鶴亭空亭，無鶴胡爲名。", "亦如西山賦招鶴，無鶴可招也不惡。", "何必玄裳縞袖二八真娉婷，想像標致便足使人毛骨清。", "仙翁好鶴非徒爾，鶴德從來比君子。", "坡仙自謂吾不如，今翁與坡豈其殊。", "蒼苔白石有餘樂，一似簞瓢甘澹泊。", "笑殺飛鳶太不靈，貪腥嗜腐譁然爭。", "九臯一唳醒人耳，又如片言之善應千里。", "更笑荒林老木終日號畢逋，說吉說凶誰聽渠。", "仙翁愛鶴愛其德，我讀翁詩三歎息。", "便好從翁痛飲醉倒斯亭邊，振袂起舞學胎仙。"]'),
('7de336c2-28a8-4eb5-88e6-59068b3d10a0','送吳定夫西歸  其一','真德秀','宋','宋诗','song-poetry','','[]','吾衰倦對客，晤語惟青山。',48,'全唐诗/poet.song.190000.json','["吾衰倦對客，晤語惟青山。", "修竹引清風，時爲掩柴關。", "今晨何人來，踏破莓苔斑。", "驚顧復自喜，不妨伴虛閑。"]'),
('b7716e3d-621f-4d99-a8dd-6fc4e1c318ec','送吳定夫西歸  其二','真德秀','宋','宋诗','song-poetry','','[]','世情重聲利，榮途足趨走。',48,'全唐诗/poet.song.190000.json','["世情重聲利，榮途足趨走。", "夫君獨何爲，經年闖林藪。", "東尋金壇翁，南訪玉峰叟。", "借問兩臞仙，來時輕健否。"]'),
('9d39be52-aa60-4763-8608-ecf072dc3e46','送吳定夫西歸  其三','真德秀','宋','宋诗','song-poetry','','[]','慈湖老仙伯，乘雲賓帝鄉。',48,'全唐诗/poet.song.190000.json','["慈湖老仙伯，乘雲賓帝鄉。", "念之每汍瀾，風味不可忘。", "其門多英特，清文照縑緗。", "爲我勖諸賢，佐道當自强。"]'),
('417e1768-4c53-43b9-bc64-5d13dbfdb3b6','送吳定夫西歸  其四','真德秀','宋','宋诗','song-poetry','','[]','麻源在何許，茫茫白雲端。',48,'全唐诗/poet.song.190000.json','["麻源在何許，茫茫白雲端。", "悽其一布裘，何以禦風寒。", "歸來有餘師，興盡當知還。", "便好斸空谷，賸種青琅玕。"]'),
('45fd44dd-4418-4a82-a20b-4336e1f4d45f','詠仁','真德秀','宋','宋诗','song-poetry','','[]','程子精微談穀種，謝公近似喻桃仁。',32,'全唐诗/poet.song.190000.json','["程子精微談穀種，謝公近似喻桃仁。", "要須精別性情異，方識其言親未親。"]'),
('69b70896-06ae-480e-bede-4fdb7a8cabea','題隠者蘇翁事迹','真德秀','宋','宋诗','song-poetry','','[]','魏公孤忠如孔明，赤手能支天柱傾。',64,'全唐诗/poet.song.190000.json','["魏公孤忠如孔明，赤手能支天柱傾。", "蘇公高節如子陵，寸膠解使黄河清。", "等是世間少不得，問津耦耕各其適。", "後人未可輕雌黄，兩翁之心秋月白。"]'),
('9d6f0c42-1d4f-4219-adcf-a34b3f2c5038','題湖山清隠','真德秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖南山和靖廬，西山東湖清隠居。',64,'全唐诗/poet.song.190000.json','["西湖南山和靖廬，西山東湖清隠居。", "皇天從來具老眼，勝地不肯栖凡夫。", "眼中四時風月景，胸次萬古皇王書。", "夫君豈是終隠者，要學川雲時卷舒。"]'),
('cb49f929-3fcb-4792-a39a-3e778b29ae74','新橋行','真德秀','宋','宋诗','song-poetry','','[]','去年壽君時，清溪無梁涉者危。',108,'全唐诗/poet.song.190000.json','["去年壽君時，清溪無梁涉者危。", "今年壽君時，長虹卧波指可期。", "珍材遠林天發隠，文石象玉神效奇。", "蛟龜爲橋頃刻就，又似仙伯工娛嬉。", "官自憂民民自樂，此事更屬無窮思。", "要須移此濟川手，棟我王國無傾欹。", "從今南浦淥波上，惠澤千春同渺瀰。"]'),
('8205229b-81ce-49df-b8f3-2902d3f3b4b8','贈小鐵面王相士','真德秀','宋','宋诗','song-poetry','','[]','君以鐵面名，自謂相人無軟語。',60,'全唐诗/poet.song.190000.json','["君以鐵面名，自謂相人無軟語。", "我亦鐵心人，不把窮通來問汝。", "獨有一事欲扣君，學海無底難窮尋。", "幾時鐵拳透鐵壁，直窺千年賢聖心。"]'),
('50e15853-5f86-4cf2-a424-05c14a324bef','贈岳相師','真德秀','宋','宋诗','song-poetry','','[]','平生慣讀橫渠銘，不讀許負天綱書。',64,'全唐诗/poet.song.190000.json','["平生慣讀橫渠銘，不讀許負天綱書。", "窮通歡戚若有二，天之玉女元非殊。", "但應內省無所疚，何必從君問休咎。", "北窗燕坐寂無言，時聽幽禽哢晴晝。"]'),
('5121e781-9c1e-4669-9441-8ca4042d4250','七峰行爲外舅壽','真德秀','宋','宋诗','song-poetry','','["\u8861\u5c71"]','有崇南岳之五峰，倚天壁立雲濛鴻。',290,'全唐诗/poet.song.190000.json','["有崇南岳之五峰，倚天壁立雲濛鴻。", "我嘗振衣峰頂立，頗似吾鄉好峰七。", "七峰五峰小大雖不齊，氣象峍兀實似之。", "牛首峨峨峙雙闕，蕉嶺楊梅兩奇絕。", "南臺林磵佛世界，百丈煙霞龍洞穴。", "仙人冠劍端且凝，仙源萬疊秋空橫。", "縈青繚白望不斷，好似衡山山下看。", "曏來秀孕兩宗工，文章節操爲世雄。", "百年山川久寂歷，人物今有仙游翁。", "翁才古干將，翁目巖下電。", "千牛解剝刃有餘，萬象妍媸鏡中現。", "可持龍虎節，可運玉帳籌。", "才高驚衆世弗售，祗令遺愛留丹丘。", "丹丘遺愛人人誇，經界寬租惠最多。", "后皇嘉之錫異夢，使汝有子登巍科。", "翁壽當萬千，翁年纔八十。", "視昔殷大夫，僅乃十之一。", "渭川出處付何心，獨探玄關深更深。", "舞鶴山前春色好，靜對七峰長不老。"]'),
('3dcef499-654d-4d2d-ab54-8cb3486f9417','題李立父高遠樓','真德秀','宋','宋诗','song-poetry','','[]','君家百尺樓，近在環堵室。',192,'全唐诗/poet.song.190000.json','["君家百尺樓，近在環堵室。", "室處豈不佳，暑溽厭煩鬰。", "著脚躡層梯，心眼便超軼。", "好風天外來，佳月雲端出。", "清明湛空闊，洞視了孅悉。", "豈徒快登臨，抑可驗學術。", "大哉天地心，昭然本如日。", "世人庳且隘，動以私見窒。", "未能脫塵凡，底處識微密。", "羨君有斯樓，發以靜春筆。", "知崇與禮卑，二義貫于一。", "獨理要高明，履道貴平實。", "庶幾足目俱，不但窺髣髴。", "工夫妙方寸，豈假身外物。", "此境未昭融，此屋空突兀。", "君看希聖徒，陋巷暗蓬蓽。"]'),
('8c66dd05-c607-48d5-876e-8571fd82dbb1','以青氈與志道','真德秀','宋','宋诗','song-poetry','','[]','衝寒暫行役，遺汝以青氈。',48,'全唐诗/poet.song.190000.json','["衝寒暫行役，遺汝以青氈。", "要識夜眠處，當如親膝前。", "凊溫供子職，清白保家傳。", "小令多堪法，毋顓字畫妍。"]'),
('ea74bc0b-c74d-49d7-935f-351a72388c94','壽外舅楊開國','真德秀','宋','宋诗','song-poetry','','[]','大中大夫漢千戶，子男一位周諸侯。',144,'全唐诗/poet.song.190000.json','["大中大夫漢千戶，子男一位周諸侯。", "人生到此不易得，况復寶带懸精鏐。", "雖然三者皆外物，達人睨視如雲浮。", "天公最嗇是眉壽，七十從來已稀有。", "堂堂玉立仙遊翁，歲比磻溪未華首。", "碧瞳射人雙鏡懸，曉窗貝葉聲琅然。", "問渠那得許强健，陰功久在朱陵編。", "願翁遨嬉更千歲，做盡人間方便事。", "却乘白鶴御丹鸞，直上紫清朝玉帝。"]'),
('02ac6df1-599d-4dfc-a21f-9c27cb5102e4','贈旴江張平仲','真德秀','宋','宋诗','song-poetry','','[]','去聖既云遠，至理日以冥。',204,'全唐诗/poet.song.190000.json','["去聖既云遠，至理日以冥。", "言道指虛玄，語性雜精靈。", "正傳久蕪沒，異學得魁橫。", "卓哉周程張，磊隗三代英。", "妙藴發天地，微言昭日星。", "後來紫陽翁，抑又集大成。", "煌煌八書訓，凜凜萬世程。", "學者生此時，坦然有規繩。", "但患舍康莊，自趨柴與荆。", "張君江西來，頗嘗得師承。", "敝衣雖懸鶉，猛志欲掣鯨。", "袖出文一編，其辭峻而清。", "此士不易有，歸歟更研精。", "勿受俗學變，而爲寵辱驚。", "貧者士之常，未合寧躬耕。", "高門謹勿謁，養此氣崢嶸。", "不見商歌人，洋洋金石聲。"]'),
('14352190-e872-47bf-9ba7-ba0cf79dcaaf','送王子文宰昭武  其一','真德秀','宋','宋诗','song-poetry','','[]','樵川古樂國，誰遣生榛菅。',72,'全唐诗/poet.song.190000.json','["樵川古樂國，誰遣生榛菅。", "往事忍復言，念之輒長歎。", "子往字其人，寄任良亦艱。", "傷哉周餘民，十室九孤鰥。", "深心察苛癢，摩手蘇痍瘢。", "願加百倍功，勿作常時觀。"]'),
('b323e0f7-e659-4022-b68e-5a5011945020','送王子文宰昭武  其二','真德秀','宋','宋诗','song-poetry','','[]','熒熒匣中龍，爛爛巖下電。',72,'全唐诗/poet.song.190000.json','["熒熒匣中龍，爛爛巖下電。", "紛綸揮霍間，坐子百千變。", "雖然事幾微，易矚亦易眩。", "誤從快處生，理向靜中現。", "健决要安徐，聰明貴韜歛。", "潛齋有愚言，或可代箴砭。"]'),
('09abdbc8-bd31-4b96-a744-f647a7f84829','送王子文宰昭武  其三','真德秀','宋','宋诗','song-poetry','','[]','百諫或繞指，粹白俄成緇。',72,'全唐诗/poet.song.190000.json','["百諫或繞指，粹白俄成緇。", "有初諒非難，其難在終之。", "道心眇絲粟，易爲群物移。", "不有精一功，誰能勝惟危。", "子今如玉雪，瑩潔亡少疵。", "願言保令德，歲晏以爲期。"]'),
('3e11f29c-7f60-4c18-8a2b-20b0f4f6d507','送王子文宰昭武  其四','真德秀','宋','宋诗','song-poetry','','[]','堂堂先太史，一節貫初終。',72,'全唐诗/poet.song.190000.json','["堂堂先太史，一節貫初終。", "况有壽母賢，切切唯教忠。", "承家諒匪易，負任丘山崇。", "可不日汲汲，仰希前哲蹤。", "敬義兩夾持，師友交磨礲。", "餘事作詩人，毋顓鎪句工。"]'),
('898bdedb-0e06-4f22-9d78-ec78261f295a','送王子文宰昭武  其五','真德秀','宋','宋诗','song-poetry','','[]','平時州縣間，上下意苦異。',72,'全唐诗/poet.song.190000.json','["平時州縣間，上下意苦異。", "善書肘或掣，有志奚由遂。", "子今得所從，展布有餘地。", "兩賢更勠力，萬物應吐氣。", "相期召杜功，奕奕照采世。", "不須峴首碑，自有樵川誌。"]'),
('41190e3a-74ba-4368-a3c0-9537c0894205','浦城勸糶','真德秀','宋','宋诗','song-poetry','','[]','陽和二月春，草木皆生意。',288,'全唐诗/poet.song.190000.json','["陽和二月春，草木皆生意。", "那知田野間，斯人極憔悴。", "殷勤問由來，父老各長喟。", "富室不憐貧，千倉盡封閉。", "只圖價日高，弗念民已弊。", "去年值饑荒，自分無噍類。", "幸哉活至今，且復遇豐歲。", "庶幾一餉樂，養育謝天地。", "豈期新春來，米穀更翔貴。", "况又絕市無，縱有濕且碎。", "何由充饑腸，何由飽孥累。", "恨不死荒年，免復見憂畏。", "我聞父老言，痛切貫心肺。", "行行至平洲，景象頓殊異。", "白粲玉不如，一升纔十四。", "問誰長者家，作此利益事。", "父老合掌言，子文姓陳氏。", "起家本儒生，疇昔樂賑施。", "憶昨艱食時，巨室爭謀利。", "米斗三百餘，獨收七十二。", "三都數千口，受彼更生惠。", "開庫質敝衣，假此賙貧匱。", "取本不取息，所活豈勝計。", "我曹非此翁，久作溝中胔。"]'),
('12de5ffe-abd1-49ae-9c65-c7df50bfbbc1','挹仙亭','真德秀','宋','宋诗','song-poetry','','[]','漢宮葦篋兒呱呱，濟南梓柱陰扶疏。',224,'全唐诗/poet.song.190000.json','["漢宮葦篋兒呱呱，濟南梓柱陰扶疏。", "富平家人正愉樂，安昌帝師工獻諛。", "子真東南一尉耳，黄綬凄凉百僚底。", "手持短疏叩天閽，義激丹衷淚橫眥。", "翩然一朝徑拂衣，愛君無路空依依。", "人傳九江已仙去，吳門再見是邪非。", "神仙茫茫那可測，上帝從來賞忠直。", "天上果有驂鸞人，合領群真朝北極。", "自從舉手謝世間，千年白鶴何時還。", "玉簫聲斷杉檜冷，祇餘丹竈留空山。", "谷口之孫古膚使，亭斸青冥挹仙袂。", "耿耿應懷貫日忠，飄飄豈羨凌雲氣。", "我來快讀華星篇，清徹毛骨風泠然。", "何當結茅最高頂，一榻容我分雲煙。"]'),
('c648556d-a2fe-4596-8f62-5ef3b1d7eae2','贈梓潼袁君西歸','真德秀','宋','宋诗','song-poetry','','[]','君辭萬里蜀，東游海之壖。',216,'全唐诗/poet.song.190000.json','["君辭萬里蜀，東游海之壖。", "所挾大易數，自謂探幽玄。", "縱橫布籌算，妙若蓍之圓。", "殷勤扣其說，得數須得全。", "人生穹壤間，其孰司陶甄。", "短長辨鳬鶴，百一分夔蚿。", "造物初何必，賦受自爾偏。", "數有饒與乏，定命誰能遷。", "理則無虧盈，一性各渾然。", "顔跖偶壽夭，堯桀非愚賢。", "緬懷樂正子，聖門得真傳。", "全生必全歸，此語星日懸。", "予生故多奇，榮枯聽諸天。", "獨有任道心，未死須乾乾。", "君提空囊至，又復垂橐旋。", "豈嘗卜而來，所遇非昔泉。", "術工用乃拙，爲子笑且憐。", "矢詩苦不多，聊壓瞿唐船。"]'),
('c1b33727-9c6f-4f6d-8c3d-2187134fc778','會三山十二縣宰','真德秀','宋','宋诗','song-poetry','','[]','皇皇造化鈞，橐籥生萬彙。',288,'全唐诗/poet.song.190000.json','["皇皇造化鈞，橐籥生萬彙。", "林林滿穹壤，異體實同氣。", "痛癢本相關，彼己當一視。", "矧惟守令職，休戚我焉寄。", "盍推若保心，睠焉撫孩稚。", "橫目事征求，往往學頑痹。", "牀剝膚已侵，鷹擊毛盡摯。", "但期己豐腴，皇恤彼憔悴。", "近來二十年，貪風日滋熾。", "蒲萄得凉州，西園鬨成市。", "環詹郡邑間，太半皆污吏。", "民窮盜乃起，原野厭枯胔。", "哀哉罹禍徒，念之輒揮涕。", "天地忽開張，清飆掃氛曀。", "我乃於此時，擁旄忝爲帥。", "顧慙老儒生，蹇拙乏長技。", "同官爲僚友，努力圖共濟。", "惟閩古大都，星羅邑十二。", "豈無良大夫，與我同厥志。", "要如羔羊直，委蛇自無愧。", "勿爲碩鼠貪，躑躅乃多畏。", "上方明黜陟，我亦公舉刺。", "民言即豐碑，令問疾郵置。", "黄堂一巵酒，殷勤抒至意。"]'),
('d3ebd18b-0f2f-4035-b855-bc29397e18b8','游鼓山','真德秀','宋','宋诗','song-poetry','','[]','嚴宸有追詔，趣上太守符。',276,'全唐诗/poet.song.190000.json','["嚴宸有追詔，趣上太守符。", "疲民未蘇醒，還顧空躊躇。", "來尋靈源盟，喜與佳客俱。", "始酌清泠泉，一浣丹墨洿。", "超然煩溽中，著身在冰壺。", "遲明陟危亭，雲濤渺空虛。", "煙霏倏開闔，峰巒時有無。", "偉哉此絕觀，雄壓東南隅。", "蒼崖萬仞立，四面環瓊琚。", "翠木巧蔽虧，亭午清陰敷。", "令人澹忘歸，似到真華胥。", "憶昨泛蓮日，選勝邀朋徒。", "摩挲巖上刻，慨仰趙與朱。", "舉觴酹且盟，一節期終初。", "重來三十年，恍如隔朝晡。", "並游四五人，存者獨老癯。", "有懷子陳子，感歎爲欷歔。", "子抱明月終，我方長涂趨。", "顛踣懼不免，儆省當何如。", "願言祝同社，著力相携扶。", "禪伯亦可人，新結峰頂廬。", "老我故倦游，軒冕非所娛。", "會須脫塵鞿，來依懶瓚居。"]'),
('9f7eff8b-fac1-4bd1-80b2-bc1b3d4bf8fb','題來青館','真德秀','宋','宋诗','song-poetry','','[]','客夢成時夜向闌，幽泉挾雨響潺潺。',32,'全唐诗/poet.song.190000.json','["客夢成時夜向闌，幽泉挾雨響潺潺。", "清魂便覺超塵世，何况真栖巖石間。"]'),
('36de68a7-c730-436a-a791-71e1ba896eb0','泉州貢院舉梁八詠  其一','真德秀','宋','宋诗','song-poetry','','[]','萬間貢宇舊巍巍，更闢新楹廣舊規。',32,'全唐诗/poet.song.190000.json','["萬間貢宇舊巍巍，更闢新楹廣舊規。", "豈爲儒生决科計，要培宗社太平基。"]'),
('2378f2ce-2a10-4631-ac8f-70d864f5e24c','泉州貢院舉梁八詠  其二','真德秀','宋','宋诗','song-poetry','','[]','雲斤初運日逢甲，虹影乍橫星值奎。',32,'全唐诗/poet.song.190000.json','["雲斤初運日逢甲，虹影乍橫星值奎。", "天相斯文兆先見，不須佳讖指金雞。"]'),
('bf33e17e-03a7-41d8-ab19-75ab32585a4b','泉州貢院舉梁八詠  其三','真德秀','宋','宋诗','song-poetry','','[]','棘闈曾闢大江東，喚起秦淮兩蟄龍。',32,'全唐诗/poet.song.190000.json','["棘闈曾闢大江東，喚起秦淮兩蟄龍。", "况是此邦饒俊彥，何愁盛事不重重。"]'),
('d690ac56-f256-417a-8d72-f7b313e10b8f','泉州貢院舉梁八詠  其四','真德秀','宋','宋诗','song-poetry','','[]','明年丹詔下楓宸，定有英材起海瀕。',32,'全唐诗/poet.song.190000.json','["明年丹詔下楓宸，定有英材起海瀕。", "勉取梁公舊衣鉢，從今人說兩庚辰。"]'),
('515e086c-d7d0-4c0f-b0dc-d3fdf611a1f9','泉州貢院舉梁八詠  其五','真德秀','宋','宋诗','song-poetry','','[]','梁脊伊誰姓氏題，梅溪去後有苕溪。',32,'全唐诗/poet.song.190000.json','["梁脊伊誰姓氏題，梅溪去後有苕溪。", "自慚拙守何爲者，强策駑駘繼駃騠。"]'),
('05f45d88-7efb-4273-8976-1756a75092a1','泉州貢院舉梁八詠  其六','真德秀','宋','宋诗','song-poetry','','[]','憶昔文闈創造初，揮毫紀實有鴻樞。',32,'全唐诗/poet.song.190000.json','["憶昔文闈創造初，揮毫紀實有鴻樞。", "乃今盛觀重輝赫，試問他邦有此無。"]'),
('b1b7ee3a-8ecb-4f6f-91e6-bc3fe3a63b13','泉州貢院舉梁八詠  其七','真德秀','宋','宋诗','song-poetry','','[]','簪橐聯輝三大老，節旄相映四賢侯。',32,'全唐诗/poet.song.190000.json','["簪橐聯輝三大老，節旄相映四賢侯。", "作成後進須先進，引領時流作勝流。"]'),
('7c4c010e-40b2-46b2-a0db-ea2cf77c7a13','泉州貢院舉梁八詠  其八','真德秀','宋','宋诗','song-poetry','','[]','策足巍科亦漫然，當知致遠識爲先。',32,'全唐诗/poet.song.190000.json','["策足巍科亦漫然，當知致遠識爲先。", "丁寧莫負梅溪祝，名節岧嶢共勉旃。"]'),
('109d936a-aee9-40ab-ad08-b79ac5f894b3','和侍讀祕監餞行嚴韵','真德秀','宋','宋诗','song-poetry','','[]','帝里參陪意最親，聯鑣忽此爲交鄰。',64,'全唐诗/poet.song.190000.json','["帝里參陪意最親，聯鑣忽此爲交鄰。", "徐行得接雙飛鳳，驟別難留一角麟。", "歸奏已趨天尺五，寵光仍待月重輪。", "應憐留滯窮邊客，晏歲嚴霜夜夜申。"]'),
('6fed7927-3326-4a6d-8d96-09a922ca1f42','送張曜之  其一','真德秀','宋','宋诗','song-poetry','','[]','風煙千里走淮漘，寄語青油幕裏人。',32,'全唐诗/poet.song.190000.json','["風煙千里走淮漘，寄語青油幕裏人。", "麟閣功名須有意，乃心王室勿謀身。"]'),
('e4e2a47c-3379-41ee-8062-0da51a43854f','送張曜之  其二','真德秀','宋','宋诗','song-poetry','','[]','譚天之外更譚兵，風角孤虛分外精。',32,'全唐诗/poet.song.190000.json','["譚天之外更譚兵，風角孤虛分外精。", "玉帳不妨收拾取，絕勝下客著雞鳴。"]'),
('f43e8051-807a-44da-899e-e04f2ecc5f32','會長沙十二縣宰','真德秀','宋','宋诗','song-poetry','','[]','從來守令與斯民，都是同胞一樣親。',64,'全唐诗/poet.song.190000.json','["從來守令與斯民，都是同胞一樣親。", "豈有脂膏供爾祿，不思痛癢切吾身。", "此邦祗似唐時古，我輩當如漢吏循。", "今夕湘春一巵酒，直煩散作十分春。"]'),
('72b83b8b-87ab-4f52-b9e7-af166ede9ecc','長沙勸耕  其一','真德秀','宋','宋诗','song-poetry','','[]','是州皆有勸農文，父老聽來似不聞。',32,'全唐诗/poet.song.190000.json','["是州皆有勸農文，父老聽來似不聞。", "只爲空言難感動，須將實意寫殷勤。"]'),
('7efe3ed9-474a-48f6-bde8-9801b21d9d37','長沙勸耕  其二','真德秀','宋','宋诗','song-poetry','','[]','使君元起自鋤犂，田野辛勤事總知。',32,'全唐诗/poet.song.190000.json','["使君元起自鋤犂，田野辛勤事總知。", "要爲爾民除十害，肯容苛政奪三時。"]'),
('5872c148-ee1b-4f75-ad9c-aa956036cf27','長沙勸耕  其三','真德秀','宋','宋诗','song-poetry','','[]','已看三白兆年豐，更喜春來雨澤通。',32,'全唐诗/poet.song.190000.json','["已看三白兆年豐，更喜春來雨澤通。", "從昔楚邦農事早，好將人力副天工。"]'),
('81234973-639f-497c-a295-9ebb75577bbd','長沙勸耕  其四','真德秀','宋','宋诗','song-poetry','','[]','田裏工夫著得勤，翻鋤須熟糞須均。',32,'全唐诗/poet.song.190000.json','["田裏工夫著得勤，翻鋤須熟糞須均。", "插秧更要當時節，趁取陽和三月春。"]'),
('827bebc9-c069-4dc9-8cc6-cd4dc2e08703','長沙勸耕  其五','真德秀','宋','宋诗','song-poetry','','[]','聞說陂塘處處多，併工修築莫蹉跎。',32,'全唐诗/poet.song.190000.json','["聞說陂塘處處多，併工修築莫蹉跎。", "十分積取盈堤水，六月驕陽柰汝何。"]'),
('771342f2-12fd-4997-9492-10f39803ca04','長沙勸耕  其六','真德秀','宋','宋诗','song-poetry','','[]','田家拚取一春忙，男力菑畬女課桑。',32,'全唐诗/poet.song.190000.json','["田家拚取一春忙，男力菑畬女課桑。", "隴上黄雲機上雪，暫時辛苦樂時長。"]'),
('7f5cae1e-2c31-408c-b976-daf2f5ee35c0','長沙勸耕  其七','真德秀','宋','宋诗','song-poetry','','[]','鞠育當知父母恩，弟兄更合識卑尊。',32,'全唐诗/poet.song.190000.json','["鞠育當知父母恩，弟兄更合識卑尊。", "孝心盡處通天地，善行多時福子孫。"]'),
('a84b1c14-b311-4f79-8fab-14606ff575ca','長沙勸耕  其八','真德秀','宋','宋诗','song-poetry','','[]','千金難買是鄉鄰，恩意相歡即至親。',32,'全唐诗/poet.song.190000.json','["千金難買是鄉鄰，恩意相歡即至親。", "年若少時宜敬老，家纔足後合憐貧。"]'),
('f900d24a-a472-4a10-9d70-2a26d90e0770','長沙勸耕  其九','真德秀','宋','宋诗','song-poetry','','[]','健訟翻成産禍胎，带刀却是殺身媒。',32,'全唐诗/poet.song.190000.json','["健訟翻成産禍胎，带刀却是殺身媒。", "爭先好勝災偏速，退步饒人福自來。"]'),
('ba206ce8-520b-45be-8fed-4a8a77a53ef2','長沙勸耕  其一○','真德秀','宋','宋诗','song-poetry','','[]','不教言語太艱深，爲要人人可諷吟。',32,'全唐诗/poet.song.190000.json','["不教言語太艱深，爲要人人可諷吟。", "把向田間歌幾遍，兒童亦識使君心。"]'),
('105712f7-4dc7-42d9-b0b1-ec3ede77ee4f','別湯升伯','真德秀','宋','宋诗','song-poetry','','[]','二十年前忝舊遊，論交今日始從頭。',64,'全唐诗/poet.song.190000.json','["二十年前忝舊遊，論交今日始從頭。", "我如潦盡寒潭水，君似天空明月秋。", "夜雨幾時重話舊，故山聞早共歸休。", "臨岐贈別無他祝，莫忘鄒陳爲國憂。"]'),
('3eb1e8bc-c774-4bf1-8654-8bff58ba2abd','和趙章泉','真德秀','宋','宋诗','song-poetry','','[]','天教一老立堂堂，步武媻姍盡未妨。',64,'全唐诗/poet.song.190000.json','["天教一老立堂堂，步武媻姍盡未妨。", "元始故家典刑在，北方正學派流長。", "新恩已煥青藜照，舊德行詢黄髮良。", "多謝寄詩勤問訊，自憐疏懶似嵇康。"]'),
('c5a1c051-1a23-4ad0-abd5-ddfb7d9a7d9b','送永嘉陳有輝','真德秀','宋','宋诗','song-poetry','','[]','深山讀易如康節，白首談玄似子雲。',64,'全唐诗/poet.song.190000.json','["深山讀易如康節，白首談玄似子雲。", "肯學時流誇末技，却於聖處策奇勳。", "二圖君已窺微指，十翼吾方愧淺聞。", "得意春風重過我，綠波清夜話羲文。"]'),
('09242682-1406-4df0-9a24-958d5826367f','題黄氏貧樂齋  其一','真德秀','宋','宋诗','song-poetry','','[]','濂洛相傳無別法，孔顔樂處要精求。',32,'全唐诗/poet.song.190000.json','["濂洛相傳無別法，孔顔樂處要精求。", "須憑實學工夫到，莫作閑談想像休。"]'),
('4b2e2c1d-679c-48cf-a890-99a637d3848d','題黄氏貧樂齋  其二','真德秀','宋','宋诗','song-poetry','','[]','道鄉曾舉龍門話，認作玄關透悟機。',32,'全唐诗/poet.song.190000.json','["道鄉曾舉龍門話，認作玄關透悟機。", "儒佛差殊真眇忽，請君參取是耶非。"]'),
('48d76ddd-9277-4cce-8ecc-42fa2a2c33da','閑吟','真德秀','宋','宋诗','song-poetry','','[]','閑中意趣定何如，靜把陳編自卷舒。',64,'全唐诗/poet.song.190000.json','["閑中意趣定何如，靜把陳編自卷舒。", "希聖希賢真事業，潜天潜地細工夫。", "林泉有分吾生足，鍾鼎無心世味疏。", "政使一貧真到骨，不妨陋巷樂顔癯。"]'),
('388eede5-02e0-418e-a891-6bcb40eab786','凈豁持鉢求度爲說偈言','真德秀','宋','宋诗','song-poetry','','[]','一真不昧人中佛，五戒俱全俗裏僧。',32,'全唐诗/poet.song.190000.json','["一真不昧人中佛，五戒俱全俗裏僧。", "必待方袍與圓頂，維摩龐老又何曾。"]'),
('d45fd439-e9b3-4bd2-b985-df8baf3e3941','賀外舅轉官','真德秀','宋','宋诗','song-poetry','','[]','黄山桃李閙春風，曾見先生化育中。',64,'全唐诗/poet.song.190000.json','["黄山桃李閙春風，曾見先生化育中。", "經界力行師孟子，井田有意復周公。", "幾年凋俗成佳邑，一旦新綸賞舊功。", "明主已知材智美，渭川行起釣璜翁。"]'),
('e5956fdf-e217-448d-b8c7-32def9ebf70f','壽楊龢父','真德秀','宋','宋诗','song-poetry','','[]','壽日將何勸壽巵，不妨拈出去年詩。',64,'全唐诗/poet.song.190000.json','["壽日將何勸壽巵，不妨拈出去年詩。", "大生皆自微陽起，百善端從一念基。", "身欲寧時須主靜，幾纔動處要先知。", "老來自笑無新句，那得仙翁一解頤。"]'),
('3e377ca5-66a0-4d92-b323-74bf4ca74e49','贈夏宗禹  其一','真德秀','宋','宋诗','song-poetry','','[]','虎頭自合取侯封，好爲明時立雋功。',32,'全唐诗/poet.song.190000.json','["虎頭自合取侯封，好爲明時立雋功。", "做了玉關班定遠，却陪芝嶺夏黄公。"]'),
('f91c33cc-95a5-4183-ac9b-f7e6d2356d93','贈夏宗禹  其二','真德秀','宋','宋诗','song-poetry','','[]','丹經千卷浩如林，妙訣無多底處尋。',32,'全唐诗/poet.song.190000.json','["丹經千卷浩如林，妙訣無多底處尋。", "但要靈臺常似水，自然元海會生金。"]'),
('39970568-916c-48f0-8052-ac1387bf80f0','贈葉子仁  其一','真德秀','宋','宋诗','song-poetry','','[]','易象推占妙入神，勸人忠孝更諄諄。',32,'全唐诗/poet.song.190000.json','["易象推占妙入神，勸人忠孝更諄諄。", "只今誰似君平術，唯有南陽賣卜人。"]'),
('9718356d-02c2-4241-9730-069df24a80bd','贈葉子仁  其二','真德秀','宋','宋诗','song-poetry','','[]','花正紛紅俄駭綠，月纔掛壁又沈鉤。',32,'全唐诗/poet.song.190000.json','["花正紛紅俄駭綠，月纔掛壁又沈鉤。", "世間萬事都如此，莫遣雙眉浪自愁。"]'),
('d28bf8dd-f38a-428c-a17f-5b3e970decac','贈葉子仁  其三','真德秀','宋','宋诗','song-poetry','','[]','知天焉用尤臧氏，有命何須主瘠環。',32,'全唐诗/poet.song.190000.json','["知天焉用尤臧氏，有命何須主瘠環。", "若向此中能照破，許君已透利名關。"]'),
('0348e871-e242-4b59-9476-6da8e5a9977d','贈徐碧鑑  其一','真德秀','宋','宋诗','song-poetry','','[]','人言得罪爲狂疏，若論狂疏罪不無。',32,'全唐诗/poet.song.190000.json','["人言得罪爲狂疏，若論狂疏罪不無。", "亦既自呵還自笑，只緣骨相合崎嶇。"]'),
('3ef36946-7072-4231-b806-920e73d55abe','贈徐碧鑑  其二','真德秀','宋','宋诗','song-poetry','','[]','論命豈能修造化，相形那解脫頭顱。',32,'全唐诗/poet.song.190000.json','["論命豈能修造化，相形那解脫頭顱。", "知君藻鑑真超絕，試問窮通改得無。"]'),
('cda2c47e-993e-4ae6-9a9f-80a8264e9766','題黄君貧樂齋','真德秀','宋','宋诗','song-poetry','','[]','飯疏飲水復何求，道在胸中百不憂。',32,'全唐诗/poet.song.190000.json','["飯疏飲水復何求，道在胸中百不憂。", "參取章泉克齋句，底須樓上更安樓。"]'),
('7882f63d-78f4-47fe-ac37-ff3ab497936e','贈張童子  其一','真德秀','宋','宋诗','song-poetry','','[]','虎頭燕頷及鳶肩，自笑都無一事全。',32,'全唐诗/poet.song.190000.json','["虎頭燕頷及鳶肩，自笑都無一事全。", "惟有數條瓜樣骨，尚堪山澤作臞仙。"]'),
('e8f5e4ac-e3c1-4cba-ab80-4f7ba0399699','贈張童子  其二','真德秀','宋','宋诗','song-poetry','','[]','聞君早號張童子，顧我初非韓退之。',32,'全唐诗/poet.song.190000.json','["聞君早號張童子，顧我初非韓退之。", "可惜浪拋洙泗業，只看風鑑學希夷。"]'),
('e5d00036-e0a7-41ba-8d4c-2d422fc01486','贈邵邦傑','真德秀','宋','宋诗','song-poetry','','[]','五寸管能摹造化，七絃琴解寫人心。',32,'全唐诗/poet.song.190000.json','["五寸管能摹造化，七絃琴解寫人心。", "平生不作麒麟夢，且聽高山流水音。"]'),
('e0f912e0-4d5e-4850-b572-94bc275191e2','壽楊龢父','真德秀','宋','宋诗','song-poetry','','[]','誕日娛親始是榮，如君慶事世難并。',64,'全唐诗/poet.song.190000.json','["誕日娛親始是榮，如君慶事世難并。", "名園春滿三三徑，眉壽天開九九齡。", "帝渥頻霑新誥紫，文階重煥舊氈青。", "玉杯從此年年把，笑勸樽前兩福星。"]'),
('f2c62a8f-8cc7-4793-a161-f9c65c5d5213','壽陳宰  其一','真德秀','宋','宋诗','song-poetry','','[]','花種河陽未十旬，和薰四境蚤如春。',32,'全唐诗/poet.song.190000.json','["花種河陽未十旬，和薰四境蚤如春。", "試看條教頻頻下，字字無非育物仁。"]'),
('25e1ff45-bb6b-4931-b839-470444ac27d3','壽陳宰  其二','真德秀','宋','宋诗','song-poetry','','[]','爲民一念徹淵泉，蔬茹餘旬始籲天。',32,'全唐诗/poet.song.190000.json','["爲民一念徹淵泉，蔬茹餘旬始籲天。", "歲事豐登鄰寇熄，乃知感應鼓桴然。"]'),
('f23858aa-6dae-4e4b-a288-a73596fd1b12','詩寄淮西王路分','真德秀','宋','宋诗','song-poetry','','[]','壯哉貔虎三千士，靜掃鯨鯢百萬餘。',32,'全唐诗/poet.song.190000.json','["壯哉貔虎三千士，靜掃鯨鯢百萬餘。", "若使人人似淮右，笑談真可滅狂胡。"]'),
('b0ef7591-133f-4d04-aca3-57cbae45652e','贈吳景雲  其一','真德秀','宋','宋诗','song-poetry','','[]','錕鋙切玉爛成泥，妙手鎸銅亦似之。',32,'全唐诗/poet.song.190000.json','["錕鋙切玉爛成泥，妙手鎸銅亦似之。", "若會此機來學道，石槃木鑽有通時。"]'),
('03ef7c3f-24ab-48b9-9a57-f899f55e4035','贈吳景雲  其二','真德秀','宋','宋诗','song-poetry','','[]','腰間爭佩印纍纍，真印從來少得知。',32,'全唐诗/poet.song.190000.json','["腰間爭佩印纍纍，真印從來少得知。", "不向聖傳中有省，黄金斗大亦何爲。"]'),
('2272e569-25b5-48a1-acf3-d9ef3c56c153','送曹晉伯令尹之官  其一','真德秀','宋','宋诗','song-poetry','','[]','須江壯哉縣，誰遣莽成墟。',48,'全唐诗/poet.song.190000.json','["須江壯哉縣，誰遣莽成墟。", "舊觀嗟難復，罷民苦未紓。", "手摩應切切，鞭算盍徐徐。", "頼有賢邦伯，當令子志攄。"]'),
('da7a5d7a-23b8-4efa-b15b-b815be95530e','送曹晉伯令尹之官  其二','真德秀','宋','宋诗','song-poetry','','[]','此邑吾鄰境，嘗聞歎恨深。',48,'全唐诗/poet.song.190000.json','["此邑吾鄰境，嘗聞歎恨深。", "有田盡增稅，無楮可爲衾。", "願布中和政，毋懷忿疾心。", "歸田當有日，好聽宓生琴。"]'),
('c8d98999-66c5-4a7f-bc6c-3a419d3229be','端午貼子詞 皇帝閣六首 其一','真德秀','宋','宋诗','song-poetry','','[]','庚午仍重午，離明正繼明。',24,'全唐诗/poet.song.190000.json','["庚午仍重午，離明正繼明。", "炎圖千萬歲，從此愈光亨。"]'),
('9a88b4e1-de06-4a61-a177-8b59970ca6cd','端午貼子詞 皇帝閣六首 其二','真德秀','宋','宋诗','song-poetry','','[]','玉帛交鄰後，清陰滿塞榆。',24,'全唐诗/poet.song.190000.json','["玉帛交鄰後，清陰滿塞榆。", "苞桑存至戒，猶佩辟兵符。"]'),
('17aca1e5-91c0-49ea-971c-e84540e0feed','端午貼子詞 皇帝閣六首 其三','真德秀','宋','宋诗','song-poetry','','[]','有意甦民瘼，無心玩物華。',24,'全唐诗/poet.song.190000.json','["有意甦民瘼，無心玩物華。", "祗求三歲艾，休進五時花。"]'),
('83eb3cd5-6281-4139-b88b-1b122b5a8278','端午貼子詞 皇帝閣六首 其四','真德秀','宋','宋诗','song-poetry','','[]','當宁求賢軫慮長，每因佳節憶沉湘。',32,'全唐诗/poet.song.190000.json','["當宁求賢軫慮長，每因佳節憶沉湘。", "不須五色紉成線，自有忠言補舜裳。"]'),
('9fb49075-3859-462b-8fbe-afd8b60c2ff3','端午貼子詞 皇帝閣六首 其五','真德秀','宋','宋诗','song-poetry','','[]','延英晝永汗霑衣，正是君王訪問時。',32,'全唐诗/poet.song.190000.json','["延英晝永汗霑衣，正是君王訪問時。", "應笑開元恣驕樂，粉團爭射學兒嬉。"]'),
('b743ceff-d02a-46e9-9f1e-f506fa77e139','端午貼子詞 皇帝閣六首 其六','真德秀','宋','宋诗','song-poetry','','[]','聖心日日望豐年，清曉鑪熏徹九天。',32,'全唐诗/poet.song.190000.json','["聖心日日望豐年，清曉鑪熏徹九天。", "二麥登場蠶著繭，平疇新綠又連阡。"]'),
('b6eae9f8-dd09-42b6-806f-94e6cbede1ab','端午貼子詞 皇后閣五首 其一','真德秀','宋','宋诗','song-poetry','','[]','仙木浮瓊醴，香菰簇寶槃。',24,'全唐诗/poet.song.190000.json','["仙木浮瓊醴，香菰簇寶槃。", "漢宮三十六，爭奉聖人歡。"]'),
('f66b66ab-01d6-4034-b294-ed27e58244e1','端午貼子詞 皇后閣五首 其二','真德秀','宋','宋诗','song-poetry','','[]','槐影綠成圍，腰輿繭館歸。',24,'全唐诗/poet.song.190000.json','["槐影綠成圍，腰輿繭館歸。", "我躬惟服澣，先織衮龍衣。"]'),
('2943cc8e-550a-4156-bb08-5ac5c60f123f','端午貼子詞 皇后閣五首 其三','真德秀','宋','宋诗','song-poetry','','[]','披香殿裏繡筵開，九節菖蒲七寶杯。',32,'全唐诗/poet.song.190000.json','["披香殿裏繡筵開，九節菖蒲七寶杯。", "應念臣勞如卷耳，欲將厚意酌金罍。"]'),
('cd5d157c-d5a9-4ddb-9496-6e8130ab172e','端午貼子詞 皇后閣五首 其四','真德秀','宋','宋诗','song-poetry','','[]','愛民一念徹淵泉，內府時時出禁錢。',32,'全唐诗/poet.song.190000.json','["愛民一念徹淵泉，內府時時出禁錢。", "只此自添無量壽，何須彩索頌長年。"]'),
('408a3fa5-1db9-4789-a202-f6c2eb21b22f','端午貼子詞 皇后閣五首 其五','真德秀','宋','宋诗','song-poetry','','[]','珠箔輕明暑氣微，靜披圖史監前徽。',32,'全唐诗/poet.song.190000.json','["珠箔輕明暑氣微，靜披圖史監前徽。", "堪嗤唐室耽遊燕，謾借裙襦作妓衣。"]'),
('8607a3c0-c378-4949-b5da-3e70cfba3a59','端午貼子詞 皇太子宮五首 其一','真德秀','宋','宋诗','song-poetry','','[]','彩索金爲縷，香粳玉作團。',24,'全唐诗/poet.song.190000.json','["彩索金爲縷，香粳玉作團。", "從今逢午節，歲歲奉親歡。"]'),
('6e8582bf-024b-44af-9f00-f62521307b9e','端午貼子詞 皇太子宮五首 其二','真德秀','宋','宋诗','song-poetry','','[]','銀榜青宮裏，天風五月秋。',24,'全唐诗/poet.song.190000.json','["銀榜青宮裏，天風五月秋。", "應憐耦耕者，曝背向農疇。"]'),
('7b22bb3a-f59b-4a42-b9f3-b1b57edbb4d0','端午貼子詞 皇太子宮五首 其三','真德秀','宋','宋诗','song-poetry','','[]','午漏遲遲滴玉壺，清陰羃羃布庭除。',32,'全唐诗/poet.song.190000.json','["午漏遲遲滴玉壺，清陰羃羃布庭除。", "只將底事銷長日，大學中庸兩卷書。"]'),
('68c26077-3e94-4ad7-8473-abe474b4f822','端午貼子詞 皇太子宮五首 其四','真德秀','宋','宋诗','song-poetry','','[]','居仁堂上薰風滿，閒把騷章子細看。',32,'全唐诗/poet.song.190000.json','["居仁堂上薰風滿，閒把騷章子細看。", "令節豈徒供黍楝，巧言端欲戒椒蘭。"]'),
