('a5b0f57a-9378-4450-973c-e5f915fc7943','金國賀正旦使人到闕紫宸殿宴致語口號  其一','真德秀','宋','宋诗','song-poetry','','[]','榆關玉塞靜無塵，嘉定如今第四春。',64,'全唐诗/poet.song.190000.json','["榆關玉塞靜無塵，嘉定如今第四春。", "兩國交馳通好使，八荒同作太平人。", "翠鼉鼓奏娛嘉客，白獸樽浮賞諫臣。", "聖歷從茲天共遠，年年玉帛會楓宸。"]'),
('d69bd885-8c62-4a01-a396-9ec1585e1560','金國賀正旦使人到闕紫宸殿宴致語口號  其二','真德秀','宋','宋诗','song-poetry','','[]','六龍扶輦下雲間，紫殿風微響佩環。',64,'全唐诗/poet.song.190000.json','["六龍扶輦下雲間，紫殿風微響佩環。", "朔漠遠馳鄰國信，前星親押外朝班。", "九賓重譯瞻宸極，萬歲三聲繞壽山。", "大史預占年大有，更添喜色上天顔。"]'),
('26431ed3-3a4e-43da-8fb6-f1111b4f7cfc','瑞慶節集英殿宴致語口號','真德秀','宋','宋诗','song-poetry','','[]','皇家卜世過周唐，天啟真人應運翔。',64,'全唐诗/poet.song.190000.json','["皇家卜世過周唐，天啟真人應運翔。", "抱日預占恭邸夢，飛龍曾報皖山祥。", "翠雲影外來金母，紅𩅗香中擁玉皇。", "樂府賤工無以祝，願將金鑑代珠囊。"]'),
('13cb5609-74a4-4d30-a884-e73dfc710a15','金國報登位使人到闕集英殿宴致語口號','真德秀','宋','宋诗','song-poetry','','[]','時平朝野寂無譁，南北歡盟共一家。',64,'全唐诗/poet.song.190000.json','["時平朝野寂無譁，南北歡盟共一家。", "不遣纖塵驚塞上，要將和氣匝天涯。", "星馳琛幣來鄰境，雲擁衣冠會正衙。", "聖澤汪洋天廣大，侍臣何惜醉流霞。"]'),
('ad340aad-23fa-4ebc-8882-1db6685691f2','挽竹齋  其一','真德秀','宋','宋诗','song-poetry','','[]','憶昔摳衣造竹齋，竹聲琴韻兩相諧。',32,'全唐诗/poet.song.190000.json','["憶昔摳衣造竹齋，竹聲琴韻兩相諧。", "重來琴鎖紅塵滿，寒雨蕭蕭滴蘚苔。"]'),
('1716f83e-6edc-44bb-ae3e-f44d458169f7','挽竹齋  其二','真德秀','宋','宋诗','song-poetry','','[]','無奈斯文墜不興，煢煢吾黨又凋零。',32,'全唐诗/poet.song.190000.json','["無奈斯文墜不興，煢煢吾黨又凋零。", "白雲寒鎖洪崖頂，一度翹瞻一愴情。"]'),
('a43aad80-0804-478e-8b59-8078497f89f8','登南嶽上封寺','真德秀','宋','宋诗','song-poetry','','["\u8861\u5c71"]','好風一夜掃陰霖，湧出羣山紫翠深。',32,'全唐诗/poet.song.190000.json','["好風一夜掃陰霖，湧出羣山紫翠深。", "眼界豁然因有覺，六塵空後見真心。"]'),
('38fd0938-6666-442c-97bf-b0ed914d78df','使都梁次韻','真德秀','宋','宋诗','song-poetry','','[]','第一山前路半蕪，憑欄小立撚吟鬚。',64,'全唐诗/poet.song.190000.json','["第一山前路半蕪，憑欄小立撚吟鬚。", "雲橫紫塞無來鴈，冰斷黄流不渡狐。", "此日都梁聊共醉，向來夷甫可長吁。", "淮山那管人間事，依舊青青出畫圖。"]'),
('a8ce8c26-bf56-43a1-a9ee-5524afe00f6e','贈陳子長','真德秀','宋','宋诗','song-poetry','','[]','粉省郎官出把麾，故人何以贈箴規。',64,'全唐诗/poet.song.190000.json','["粉省郎官出把麾，故人何以贈箴規。", "孔門仁恕真心法，漢吏循良乃吏師。", "聽訟莫嫌刀似筆，愛民終見□成碑。", "玉麟夜語如相問，爲說如今兩鬢絲。"]'),
('8bebdde8-4344-4ba1-abbd-22c8468abc3b','題南嶽','真德秀','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u8861\u5c71"]','百年五嶽隔華戎，屏蔽皇家獨祝融。',32,'全唐诗/poet.song.190000.json','["百年五嶽隔華戎，屏蔽皇家獨祝融。", "賸喜嶽靈今有伴，岱宗今入版圖中。"]'),
('481e6c15-9d99-43b6-b4eb-32abf21afef9','跋蔡節齋爲題張生所畫文公像','真德秀','宋','宋诗','song-poetry','','[]','張生父子稱紫陽，於容人物非尋常。',64,'全唐诗/poet.song.190000.json','["張生父子稱紫陽，於容人物非尋常。", "能傳遺像數百本，粹然千載存無忘。", "言學工夫日星皎，無言氣象真難曉。", "後學深明未發時，始信張生功不少。"]'),
('25f8e704-bec9-4d0c-8c07-872912800601','衛生歌','真德秀','宋','宋诗','song-poetry','','[]','天地之間人爲貴，頭象天兮足象地。',384,'全唐诗/poet.song.190000.json','["天地之間人爲貴，頭象天兮足象地。", "父母遺體宜寶之，箕疇五福壽爲最。", "衛生切要知三戒，大怒大慾并大醉。", "三者若還有一焉，須防損失真元氣。", "欲求長生先戒性，火不出兮神自定。", "木還去火不成灰，人能戒性還延命。", "貪慾無窮忘却精，用心不已走元神。", "勞形散盡中和氣，更仗何能保此身。", "心若太費費則竭，形若太勞勞則歇。", "神若太傷傷則虛，氣若太損損則絕。", "世人欲識衛生道，喜樂有常瞋怒少。", "心誠意正思慮除，順理脩身去煩惱。", "春噓明目夏呵心，秋呬冬吹肺腎寧。", "四季長呼脾化食，三焦嘻却熱難停。", "髮宜多梳氣宜鍊，齒宜數叩津宜嚥。", "子欲不死脩崑崙，雙手揩摩常在面。", "春月少酸宜食甘，冬月宜苦不宜鹹。", "夏要增辛聊減苦，秋辛可省但加酸。", "季月少鹹甘略戒，自然五臟保平安。", "若能全減身康健，滋味偏多無病難。", "春寒莫放綿衣薄，夏月汗多須換著。", "秋冬衣冷漸加添，莫待病生纔服藥。", "惟有夏月難調理，內有伏陰忌冰水。", "瓜桃生冷宜少餐，免至秋來成瘧痢。"]'),
('3d311325-93be-4f61-9c57-8a4e35d09438','遊上天竺','真德秀','宋','宋诗','song-poetry','','[]','事事不可了，還須入此山。',48,'全唐诗/poet.song.190000.json','["事事不可了，還須入此山。", "遥尋黄葉路，迥出白雲間。", "瀹茗止煩渴，談空得笑閒。", "飄飄有餘興，歸去掩柴關。"]'),
('cc564d1f-7e6e-4b18-9666-644f6f871f25','題金陵雜興詩後八首  其一','薛師董','宋','宋诗','song-poetry','','[]','舒王不讓杜樊川，二十八字今斷絃。',32,'全唐诗/poet.song.190000.json','["舒王不讓杜樊川，二十八字今斷絃。", "可怪蘇郎呈好手，剪花排錦蔣山前。"]'),
('61c57332-652a-4d06-82ac-b9529dcd0492','題金陵雜興詩後八首  其二','薛師董','宋','宋诗','song-poetry','','[]','劉郎之後更蘇郎，不枉隨人入建康。',32,'全唐诗/poet.song.190000.json','["劉郎之後更蘇郎，不枉隨人入建康。", "秦水鍾山幾相識，前年忽識好文章。"]'),
('464c9d83-dcc6-483c-a6cf-1133f71b5ef4','題金陵雜興詩後八首  其三','薛師董','宋','宋诗','song-poetry','','[]','方泉周四半生癡，語輒驚人不自奇。',32,'全唐诗/poet.song.190000.json','["方泉周四半生癡，語輒驚人不自奇。", "渠句却題君集後，要尋梨木共傳之。"]'),
('ef620ed8-d5ea-440b-8171-999afcd1b30e','題金陵雜興詩後八首  其四','薛師董','宋','宋诗','song-poetry','','[]','交朋存沒八篇詩，自恨論心獨覺遲。',32,'全唐诗/poet.song.190000.json','["交朋存沒八篇詩，自恨論心獨覺遲。", "也記湧金門外別，不蒙登賞忽相思。"]'),
('1b15809b-4050-4bd1-b4a3-94906b4eee6b','題金陵雜興詩後八首  其五','薛師董','宋','宋诗','song-poetry','','[]','掃階楊柳敗荷風，春晚秋初下觀中。',32,'全唐诗/poet.song.190000.json','["掃階楊柳敗荷風，春晚秋初下觀中。", "兩度不能吟一句，愧君且說事匆匆。"]'),
('50191d86-1103-4d28-a822-3f3ecf308dee','題金陵雜興詩後八首  其六','薛師董','宋','宋诗','song-poetry','','[]','定林草木也風騷，曾睡山中聽桔槔。',32,'全唐诗/poet.song.190000.json','["定林草木也風騷，曾睡山中聽桔槔。", "春雨江湖八年事，空腸只憶喫絲糕。"]'),
('73c92eee-71fa-4861-a695-829121d9ec0d','題金陵雜興詩後八首  其七','薛師董','宋','宋诗','song-poetry','','[]','尊嘉堂上崔嵬老，制閫新開欲辟吾。',32,'全唐诗/poet.song.190000.json','["尊嘉堂上崔嵬老，制閫新開欲辟吾。", "又約來遊遊不得，風流輸與五雲蘇。"]'),
('f05c0631-82d8-4dca-9785-c62a99466024','題金陵雜興詩後八首  其八','薛師董','宋','宋诗','song-poetry','','[]','散盡浮軍換鐵緡，香煙何處不氤氳。',32,'全唐诗/poet.song.190000.json','["散盡浮軍換鐵緡，香煙何處不氤氳。", "蘇郎非是諛人者，今日真成說古人。"]'),
('7f304cbc-5a79-42b5-9e61-1e42c4a0b54c','秋風','薛師董','宋','宋诗','song-poetry','','[]','秋風有落枝，天籟動塤箎。',48,'全唐诗/poet.song.190000.json','["秋風有落枝，天籟動塤箎。", "鼓角山河壯，襟懷歲月遲。", "阮生狂一嘯，漢武老多悲。", "雖有秦歌激，終堪理釣絲。"]'),
('def58861-1bcc-4102-943f-d49aae4e5867','後秋風','薛師董','宋','宋诗','song-poetry','','[]','去年病後詠秋風，今日秋風病裏逢。',64,'全唐诗/poet.song.190000.json','["去年病後詠秋風，今日秋風病裏逢。", "好句不曾書落葉，孤燈長自守鳴蛩。", "故人音問天來遠，茅舍光陰睡正濃。", "江上白鷗忙勝我，銜魚引子與潮衝。"]'),
('1489ba0f-cf54-477e-bcf5-1e8304fb7ffa','酬外湖樓詩','薛師董','宋','宋诗','song-poetry','','[]','小雨潤蔬莢，凉風展梧影。',96,'全唐诗/poet.song.190000.json','["小雨潤蔬莢，凉風展梧影。", "雲連沙際白，天開數峰浄。", "湖樓百尺高，坐覺秋日永。", "寬鋤十畝園，餘事一笑領。", "荷枯水却清，桂晚霜未冷。", "誰能悲寒螿，聊忻小蛙黽。", "飽客新荳菹，駕我雙舴艋。", "放浪誠有道，居然惜俄頃。"]'),
('67b4f2ea-f5f1-4c4f-a303-0e2fbb334c4f','薛瓜廬吾宗人也吾不得而見之得見其詩斯可矣太息而題于卷杪','薛美','宋','宋诗','song-poetry','','[]','結廬兄弟近長安，弊却儒冠竟不彈。',64,'全唐诗/poet.song.190000.json','["結廬兄弟近長安，弊却儒冠竟不彈。", "自茹芝來輕漢召，肯將瓜去博唐官。", "貧多樂事清無盡，手寫新詩墨未乾。", "史筆須評隠君傳，姓名應作古人看。"]'),
('5ba47434-0581-4c92-9650-8561e4601987','詠柳','薛美','宋','宋诗','song-poetry','','[]','一撮嬌黄染不成，藏鴉未穩早藏鶑。',32,'全唐诗/poet.song.190000.json','["一撮嬌黄染不成，藏鴉未穩早藏鶑。", "行人自謂傷離別，枉折無情贈有情。"]'),
('592a7ba6-71b7-4a0e-b587-958a24108fdb','答真西山偈','釋凈豁','宋','宋诗','song-poetry','','[]','青編讀後方爲士，黄牒頒時始是官。',32,'全唐诗/poet.song.190000.json','["青編讀後方爲士，黄牒頒時始是官。", "不拜皇朝真爵命，要行所學也應難。"]'),
('fc9af137-fa57-4cd5-8196-e30431c9ae98','海寇趙某伏誅','王亦世','宋','宋诗','song-poetry','','[]','憑陵海若玩波神，怙恃乾坤不殺身。',32,'全唐诗/poet.song.190000.json','["憑陵海若玩波神，怙恃乾坤不殺身。", "刀鋸未加先自殞，陸梁未有白頭人。"]'),
('0b391481-22c9-4729-bda3-6295b88e2176','題西山生祠壁','長沙郡人','宋','宋诗','song-poetry','','[]','舉世知公不愛名，湘人苦欲置丹青。',64,'全唐诗/poet.song.190000.json','["舉世知公不愛名，湘人苦欲置丹青。", "西天又出一活佛，南極添成兩壽星。", "幾百年方鍾間氣，八千春願祝修齡。", "不須更作生祠記，四海蒼生口是銘。"]'),
('2a711ae7-1e6c-431c-88e8-1d850109bcea','寄題雅州胥園','魏了翁','宋','宋诗','song-poetry','','[]','胥君頎然來，錦囊背奚奴。',96,'全唐诗/poet.song.190000.json','["胥君頎然來，錦囊背奚奴。", "探囊發詩卷，一一卿大夫。", "未識胥園面，詩卷自畫圖。", "掃石卧竹影，長鍤斸芋區。", "胥君於此時，林泉傲金朱。", "懶余本丘壑，誤被塵纓縛。", "每逢漫浪友，慚愧紅塵脚。", "會當尋茲盟，酬此一大錯。"]'),
('a44ff500-4d6d-40fc-be9e-aa28aa40633a','登萬象樓和計次陽韻','魏了翁','宋','宋诗','song-poetry','','[]','塵纓羈我身，對景慵著語。',48,'全唐诗/poet.song.190000.json','["塵纓羈我身，對景慵著語。", "青山喚倚欄，壯氣臨潁汝。", "曾雲卷油幕，萬嶺眇煙縷。", "酒闌一橫笛，樓前葉自雨。"]'),
('0ba29fc2-5b78-4679-98a5-2e72c73de8e2','贈章相士','魏了翁','宋','宋诗','song-poetry','','[]','我本三生人，寄身軟紅土。',108,'全唐诗/poet.song.190000.json','["我本三生人，寄身軟紅土。", "方困京華老，誰識新豐旅。", "稠中有章生，道周忽會顧。", "謂余有奇骨，往往私告語。", "許予兩無心，解后適相遇。", "聞余趨集英，一聲聳臚句。", "自謂吾術神，誦言詫儔侶。", "我無百金裝，生無箕帚女。", "沘毫賦此詩，爲生郵梁楚。"]'),
('48c2806d-fe58-4197-a83f-e84819bb9a69','和虞永康美功堂詩','魏了翁','宋','宋诗','song-poetry','','[]','我曾寄徑城南州，果杏纂纂香浮浮。',240,'全唐诗/poet.song.190000.json','["我曾寄徑城南州，果杏纂纂香浮浮。", "雲開千仞雪山白，月照萬古滄江流。", "我時未得江山意，但愛高明甲西州。", "十年重來是邪非，獨覺真意爛不收。", "虞侯著堂發幽悶，豈但清與耳目謀。", "川流衮衮來不斷，雲物亹亹生無休。", "既從靜壽識至樂，復於嘆逝希前修。", "遊人翕翕滿江頭，隨所適處心悠悠。", "童子長佩搴江蘺，女兒縫裙學石榴。", "沒人揚波白魚躍，舟子競渡蒼龍摎。", "田翁野婦看兒戲，詠歸山暝風作秋。", "固亦有志感時節，欲起湘纍問靈脩。", "人人得處自深淺，江山於爾無顯幽。", "堂上主賓亦復爾，各各會意風泠颼。", "宇宙無窮本如此，我亦皓然希天遊。"]'),
('d193d849-079f-4615-bddf-c90a2b55cea2','次韻史少莊竹醉日移竹  其一','魏了翁','宋','宋诗','song-poetry','','[]','豔豔洒粧鬭姚魏，冥冥花影逢石丁。',32,'全唐诗/poet.song.190000.json','["豔豔洒粧鬭姚魏，冥冥花影逢石丁。", "醉生夢死何如竹，三百五十九日醒。"]'),
('730d1ebc-4840-40c6-b5e4-89f6b91895e6','次韻史少莊竹醉日移竹  其二','魏了翁','宋','宋诗','song-poetry','','[]','清如杜叟日卓午，直似姜公詩作丁。',32,'全唐诗/poet.song.190000.json','["清如杜叟日卓午，直似姜公詩作丁。", "冰雪容顔儼相值，霸陵醉尉也須醒。"]'),
('ee7c884a-ddb9-460e-8143-ffd9115cc2ba','次韻史少莊竹醉日移竹  其三','魏了翁','宋','宋诗','song-poetry','','[]','平生自許歲寒操，醉日移來三十丁。',32,'全唐诗/poet.song.190000.json','["平生自許歲寒操，醉日移來三十丁。", "底事此君亦移轉，連明風雨喚教醒。"]'),
('505d4531-eee2-4d33-8377-076c9215bb92','次韻史少莊竹醉日移竹  其四','魏了翁','宋','宋诗','song-poetry','','[]','猩屐常爲醉魂役，驪珠適與睡時丁。',32,'全唐诗/poet.song.190000.json','["猩屐常爲醉魂役，驪珠適與睡時丁。", "外物移人每如此，人心可使不長醒。"]'),
('32c5d681-baff-40ac-9b12-8982df2a61a4','虞永康生日','魏了翁','宋','宋诗','song-poetry','','[]','良知誰不有，靡究復靡屆。',96,'全唐诗/poet.song.190000.json','["良知誰不有，靡究復靡屆。", "寸心日月明，萬里天地解。", "握機洞消長，觀物了成壞。", "推行濟四海，小試未爲隘。", "姓名既轉聞，正恐世網挂。", "相期久遠看，力與支末派。", "建立天地心，透徹義利界。", "即茲奉君壽，行矣良自勱。"]'),
('0f03de2f-4dcd-4791-a641-7fd5bb1556f1','安大使生日','魏了翁','宋','宋诗','song-poetry','','[]','往年天壓西南垂，妖氛內訌胡塵飛。',192,'全唐诗/poet.song.190000.json','["往年天壓西南垂，妖氛內訌胡塵飛。", "梟狐陸梁士扼腕，蜀山慘澹無光輝。", "公以空弮嬰乳虎，漠漠黄雲闇平楚。", "直將天理感人心，徑斬賊頭報明主。", "露布東馳人嘯呼，京師觀者環儲胥。", "天顔有喜近臣賀，大官高爵來須臾。", "中興以來幾變異，宗祏之存如旒綴。", "平江羽檄走凶雛，采石鰍舡戮狂猘。", "至今勛名滿華夷，與公鼎立書旂彝。", "公方退然不自居，憂國之鬢紛如絲。", "天之生公爲社稷，南山不蹇石不泐。", "願公蚤歸相天子，赤舄晨朝容几几。"]'),
('a99c0cf8-a2c7-44cc-a71b-8c4490a94fbe','次韻叔衍兄賀生子','魏了翁','宋','宋诗','song-poetry','','[]','一壑一丘耕且爲，不歆周網應非羆。',64,'全唐诗/poet.song.190000.json','["一壑一丘耕且爲，不歆周網應非羆。", "雲霾障日樹蒙密，草蔓漫天山蔽虧。", "生意正從芽蘗露，善根不逐斧斤斯。", "溶溶此理誰能解，賸喜吾宗有白眉。"]'),
('e46cebc3-441b-4548-aadf-16de58906e9c','餞章郎中以浙東倉歸湖州','魏了翁','宋','宋诗','song-poetry','','[]','武陵城中春事濃，楝花欲開未開風。',144,'全唐诗/poet.song.190000.json','["武陵城中春事濃，楝花欲開未開風。", "常平使者謝朝列，袖有英簜吾將東。", "披孔翠裘上馬去，錦韉昱爚三花驄。", "先携令名作鄉繡，却把仁念爲倉紅。", "世人機淺嗜欲深，便從扶木窮高舂。", "朝余蒼梧夕縣圃，何似緩轡摇冬瓏。", "曩余除官本同署，至自萬里驚燕鴻。", "諸公祖筵亂平湖，復我不往心忡忡。", "君今姑爲粵人行，明年歸朝儻及同。"]'),
('a965a605-c494-43f6-872b-4ce9170a3f1c','送宇文侍郎知廬州','魏了翁','宋','宋诗','song-poetry','','[]','和戎八十年，尺箠不施寸。',288,'全唐诗/poet.song.190000.json','["和戎八十年，尺箠不施寸。", "彼方玄黄篚，此但青紫楦。", "懷榮保妻子，是固人所賤。", "或者倖邊功，橫行請十萬。", "問學不素講，利欲所薰焮。", "紅旗與黄紙，勇怯無定論。", "淮浦唇大江，九重重分閫。", "容臺少常伯，忠孝在寢飯。", "帝謂吾先正，嘗遺蠟書恨。", "汝今其聞孫，未報君父怨。", "九旗下青冥，往爲忠義勸。", "再拜亟祗命，當仁不敢遜。", "黄金絡馬頭，茸纛立憲憲。", "先聲劘塞垣，虜師不足遁。", "鄰里會方山，踈余且有獻。", "裴相昔守淮，董師征洄郾。", "兵端寔蔡啟，深入非始願。", "况今狃承平，士氣方曼曼。", "民力苦剜創，帥債未折券。", "如弱者禦盜，高墉守關楗。", "破羌趙營田，勝楚何繕堰。", "但當强精神，勿與角勇健。", "功名不入眼，兩鬭待其困。", "却携令名歸，太平待公建。"]'),
('356681e3-1a25-4e54-a27d-34da639547b1','題蔡氏叢桂堂','魏了翁','宋','宋诗','song-poetry','','[]','誰銜鷲峰種，託根蔡氏堂。',48,'全唐诗/poet.song.190000.json','["誰銜鷲峰種，託根蔡氏堂。", "勿誇郄林枝，未說燕山芳。", "君看湘江上，千載留晶光。", "但當護根本，歲晚搴幽香。"]'),
('81a71ce7-679c-4230-840a-5f8b38f2c39f','送徐校書知處州','魏了翁','宋','宋诗','song-poetry','','[]','峩峩海中山，十二樓五城。',120,'全唐诗/poet.song.190000.json','["峩峩海中山，十二樓五城。", "僊人駟玉虬，徑上凌紫清。", "中道忽回薄，珪符下玉京。", "彤幨曜白日，錦輿上頭行。", "扶桑攬余轡，緩步寬作程。", "世間行己地，端亦勝蓬瀛。", "誰乎低著身，啞咤聞新鶑。", "何如携令名，歸以見母兄。", "用世無小大，千里亦民氓。", "少施五袴手，竚錄屏風名。"]'),
('81478390-80cb-44c0-ad97-b95f0272e807','送王考功江東漕','魏了翁','宋','宋诗','song-poetry','','[]','分部設將漕，黈旒寄聰明。',132,'全唐诗/poet.song.190000.json','["分部設將漕，黈旒寄聰明。", "直須撼山嶽，亡但採畸贏。", "而况江以東，襟淮翼吳荆。", "民力九十空，所恃人爲城。", "南宮輟望郎，方輸餉連營。", "熒煌鵲錦袍，明日趨遐征。", "陽春脚未到，淑氣先流鶑。", "向來嵇中散，僅試薶九京。", "阿兄亦未究，有書今在楹。", "驅車踏前軌，若木以爲程。", "千里隔香案，洗目觀澄清。"]'),
('8fa26b53-9d95-4a41-82e4-9015abc9c250','送宋常丞知閬州','魏了翁','宋','宋诗','song-poetry','','[]','十年痼丘壑，厭食青山薇。',168,'全唐诗/poet.song.190000.json','["十年痼丘壑，厭食青山薇。", "不作時世粧，短褐懷明璣。", "出門歌一曲，聽者魂爲飛。", "方騎將軍馬，旋闖師氏闈。", "清名滿雙宇，宥畫裨樞機。", "便面障俗塵，不肯緇素衣。", "一朝典儀蕞，雲步方峨巍。", "顧懷錦屏勝，見謂天下稀。", "彤幨下青冥，驄馬黄金鞿。", "假道淛以東，袖有四明歸。", "我來今二年，幾度與客違。", "名位偶君似，臨分重依依。", "風節耐歲晚，富貴倏晨晞。", "相期久遠看，努力踵前徽。"]'),
('090c64c9-1628-46ed-aacc-4948f043bb46','送黄考功廣東運判分韻得漢字','魏了翁','宋','宋诗','song-poetry','','[]','凉風厲蕭辰，秋事已一半。',156,'全唐诗/poet.song.190000.json','["凉風厲蕭辰，秋事已一半。", "同舍多望郎，萍聚復雲散。", "得士良苦艱，引去何浩瀚。", "日日送行人，青衫浹流汗。", "其間白石翁，清廟之圭瓚。", "器采儀周行，詞章輩楚亂。", "秘丘第一官，脩途日未旰。", "掉頭不肯住，持節下霄漢。", "草木識清名，風塵入長算。", "安得此老宿，爲世洗愁嘆。", "同省並門居，昔我綴華貫。", "高標壁千仞，臨分重嗟惋。", "相期紹前徽，歲晚堪把玩。"]'),
('9a485803-8fe0-4563-abe5-1800712ce642','送曾尚右知信州分韻得州字','魏了翁','宋','宋诗','song-poetry','','[]','長安十二門，冠蓋如雲稠。',216,'全唐诗/poet.song.190000.json','["長安十二門，冠蓋如雲稠。", "浮驂不停趨，九衢滔滔流。", "朝握扶桑轡，暮行背椒丘。", "駕言往從之，道左傷吾輈。", "溫陵有佳士，清姿秀琅球。", "蚤疇掄魁望，盛之蓬瀛洲。", "榮進付膜外，寡欲自日休。", "需章臣有母，自詭以一州。", "彤幨下青冥，錦輿居上頭。", "小施活國手，彫瘵會有瘳。", "同省並門居，昔我陪清遊。", "一時四同年，氣味骨肉侔。", "而君堂堂去，別袂挽不留。", "迅商起層旻，候蟲催功裘。", "問學常苦艱，歲月忽忽遒。", "古今同一歧，古豈真難儔。", "願言事穮蔉，勿作刈穫謀。", "會面豈不再，爲君刮雙眸。"]'),
('9c499556-a6cf-4d98-823f-6a747d7adc67','追送劉侍郎以寶制帥湖北','魏了翁','宋','宋诗','song-poetry','','[]','士從西南來，落落僅八九。',132,'全唐诗/poet.song.190000.json','["士從西南來，落落僅八九。", "半年北門道，幾度釂別酒。", "清朝志興復，第一廣英彀。", "采采不及掬，引去遽盈斗。", "矧今忠肅孫，卓犖漢庭右。", "清榘儀班行，高懷局宇宙。", "居然輟邇聯，亟懷荆州綬。", "恩章陟西戺，戎鉞炫春晝。", "世間行己地，隨寓皆不朽。", "著意護本根，虛懷閲忠厚。", "上游屹長城，歸來秉機宥。"]'),
('cc65ff1a-25dd-4e44-a4c4-d45370db0c78','送程左史以右撰知夔州分韻得重字','魏了翁','宋','宋诗','song-poetry','','[]','煙草暝江湖，霜風纈郊壟。',156,'全唐诗/poet.song.190000.json','["煙草暝江湖，霜風纈郊壟。", "黎明北門道，雜遝冠蓋擁。", "程侯倦左墄，引去何太勇。", "瀘江春信回，書殿星極捧。", "帝念夔子國，側耕地荒茸。", "吏饕賦政煩，室罄小人恐。", "申命亟移麾，遬驅毋上冢。", "彤幨下霄漢，環珮鏘璧珙。", "山川洗悽戚，草木企孤聳。", "斧斤刈伐餘，急與護把拱。", "古人爲己學，非以博華寵。", "事業貫千載，富貴不旋踵。", "願言樹風聲，永作蜀山重。"]'),
('ff072510-4245-43f3-9ea6-651746a3b001','題謝耕道一犁春雨圖','魏了翁','宋','宋诗','song-poetry','','[]','床頭夜雨滴到明，村南村北春水生。',64,'全唐诗/poet.song.190000.json','["床頭夜雨滴到明，村南村北春水生。", "老婦携兒出門去，老翁赤脚呵牛耕。", "一雙不借挂木杪，半破夫須衝曉行。", "耕罷洗泥枕犢鼻，卧看人間蠻觸爭。"]'),
('ed1e9c3f-424b-43f0-a857-f6f5196757b4','送陳大著知蘄州分韻得輝字','魏了翁','宋','宋诗','song-poetry','','[]','陳侯海內秀，滿腹貯明璣。',156,'全唐诗/poet.song.190000.json','["陳侯海內秀，滿腹貯明璣。", "十歲能屬文，提筆登王畿。", "上嘉魯論對，亟授九品衣。", "二十隮膴仕，昱昱五采翬。", "三十搴殊科，尋闖師氏闈。", "四十復見徵，雲步何峩巍。", "蓬萊三千丈，徑上陵紫微。", "顧懷蘄春勝，驄馬黄金鞿。", "我來今二年，幾度與客違。", "於君再爲寮，臨分重依依。", "風節耐歲晚，富貴特晨晞。", "前後繼二呂，迄今借光輝。", "相期久遠看，努力追前徽。"]'),
('2dda2f40-1bbb-41b3-b63b-b2213642160e','題石興宗讀書巖','魏了翁','宋','宋诗','song-poetry','','[]','巖頭橘樹經百黄，三少不生諸老亡。',32,'全唐诗/poet.song.190000.json','["巖頭橘樹經百黄，三少不生諸老亡。", "只餘石間元祐脚，谷虛盡日鳴當當。"]'),
('b02fbd76-db71-4843-a0e3-cf7973bb2115','送趙編修知眉州分韻登字','魏了翁','宋','宋诗','song-poetry','','[]','炎煒爍穹昊，火雲助其烝。',144,'全唐诗/poet.song.190000.json','["炎煒爍穹昊，火雲助其烝。", "冠巾拂塵土，庭戶喧蟁蠅。", "便面不停舉，况欲填吾膺。", "其間寂寞人，隨念生凉冰。", "凉意方未透，一夕三四興。", "造物解人意，如叫呼得譍。", "越鄉萬里回，令名作先登。", "固知栖栖者，得喪初何曾。", "賢者於本朝，曉宿垂觚稜。", "今日送樞掾，明日辭禮丞。", "采采不盈掬，引去何如陵。", "百憂結中腸，坐挑短檠燈。"]'),
('e46490b3-9e41-4782-a71e-7187077447d9','送范吏部知崇慶分韻得兮字','魏了翁','宋','宋诗','song-poetry','','[]','陽明迪性分，陰濁生塵泥。',120,'全唐诗/poet.song.190000.json','["陽明迪性分，陰濁生塵泥。", "蛟龍薄九空，高逝縹縹兮。", "使可縶而豢，何異犬與雞。", "長安有狹邪，曲曲復低低。", "主人笑延客，雲棧登作梯。", "客辭以未能，所憂困多蹊。", "乞麾下霄漢，萬里騎青霓。", "去留本常事，渠不喪所齎。", "秋風鏘珮環，家在天之西。", "歸來拜三祖，歸路幸不迷。"]'),
('65ad5b9d-da11-4fa4-bca2-232b6cb75ffc','送蘇大著知吉州分韻得章字','魏了翁','宋','宋诗','song-poetry','','[]','平生蘇太史，清姿秀球琅。',132,'全唐诗/poet.song.190000.json','["平生蘇太史，清姿秀球琅。", "異時玉堂對，歷歷漢興亡。", "直作根本慮，不懷棄捐傷。", "脩名望蓬島，軼軌抹扶桑。", "中道忽回薄，飲馬以相羊。", "昔爲同年友，今爲同舍郎。", "不肯三日別，况各天一方。", "我乞漢嘉綬，君懷廬陵章。", "我無百何闕，君亦千里翔。", "懷賢慨時事，百憂結中腸。", "願言保嘉猷，不愧歐公鄉。"]'),
('9a49c3d1-b053-4c25-96f4-057c33654914','送周架閣以浙東提幹歸平江','魏了翁','宋','宋诗','song-poetry','','[]','共惟仁義心，無賢愚聖狂。',180,'全唐诗/poet.song.190000.json','["共惟仁義心，無賢愚聖狂。", "紛紛萬弓箭，獨以寸鐵當。", "毫氂有不察，居然失其鄉。", "察則我固有，而失豈真亡。", "周君海內秀，清姿競球琅。", "牛刀十九年，猶顧善而藏。", "用世無內外，意行獨安詳。", "乃知旦晝物，特爲弱者彊。", "許時京塵中，解后兩匆忙。", "前日同李郭，它日盟范張。", "豈謂客逢客，乃或得相羊。", "此道日寥落，此意誰平章。", "爲人作生活，悠悠老扶桑。", "勉哉迪嘉猷，歲晚垂令芳。", "我亦從此去，後會丘之陽。"]'),
('334ffb52-4419-46f0-b5d1-91894985166f','題沈氏書堂','魏了翁','宋','宋诗','song-poetry','','[]','吳興沈聲甫，示我書堂圖。',108,'全唐诗/poet.song.190000.json','["吳興沈聲甫，示我書堂圖。", "枕松被脩竹，带江衿浮屠。", "堂上新牙籤，吞天祿石渠。", "出受山水謁，入與聖賢俱。", "兒輩紛華悅，子獨文字娛。", "是心儻無斁，已足光韓畬。", "吾聞學者事，窮理以返初。", "爲人祇禽犢，鑽紙成蠹魚。", "勉哉師友功，千載沈氏書。"]'),
('c14cde94-83b6-462a-8e7e-3ff9ee0bd36c','次韻德先步月答所問語  其一','魏了翁','宋','宋诗','song-poetry','','[]','三更端正月，皎亮直瑶京。',24,'全唐诗/poet.song.190000.json','["三更端正月，皎亮直瑶京。", "客問心之體，無言對太清。"]'),
('bc6ee0c3-5a3c-4122-9ea9-401d573a25ca','次韻德先步月答所問語  其二','魏了翁','宋','宋诗','song-poetry','','[]','夜景湛虛明，浩然無與京。',24,'全唐诗/poet.song.190000.json','["夜景湛虛明，浩然無與京。", "如今蘇氏婦，但指聖人清。"]'),
('f4a4ba02-afb3-46d3-8928-1547d3e99624','次韻德先步月答所問語  其三','魏了翁','宋','宋诗','song-poetry','','[]','霽月光湓浦，吟風歸洛京。',24,'全唐诗/poet.song.190000.json','["霽月光湓浦，吟風歸洛京。", "迥無纖靄翳，千古識真清。"]'),
('c38a8859-f8c6-4ff7-a4ca-00c94cb682a2','次德先韻','魏了翁','宋','宋诗','song-poetry','','[]','二氣同一根，本體浩兮淵。',120,'全唐诗/poet.song.190000.json','["二氣同一根，本體浩兮淵。", "可見川上逝，未發心下泉。", "真機亡停息，果剝根長鮮。", "定理亡將迎，塵境地自偏。", "形神既外發，何者操其權。", "芸芸萬感通，存處元寂然。", "一物一太極，不間大小年。", "隨處無虧缺，井居而用遷。", "至人配天德，知周物之先。", "學者事何事，省察於眇綿。"]'),
('c856beb7-328b-4681-ad5f-c197213692e2','次韻虞永康廬居生芝','魏了翁','宋','宋诗','song-poetry','','[]','河南富貴花，人與譜姓氏。',192,'全唐诗/poet.song.190000.json','["河南富貴花，人與譜姓氏。", "惟茲三秀者，不譜亦名世。", "肖形草木均，出處哲人似。", "無然而致之，朝菌何異此。", "廣陵張氏廬，厥應繄孝祀。", "新豐李興塋，脩柯媲白紫。", "意誠物皆誠，人瑞草亦瑞。", "蕭條羌水瀕，五子服喪禮。", "松壑侑夕悲，竹窗湔曉泪。", "根基由內心，樸實無甃砌。", "一朝堊室左，五色芝薿薿。", "乃知宇宙間，何處非實理。", "誠神本同機，應感不失儷。", "充周徧範圍，存養司諸己。", "是心一息妄，目接猶虛僞。", "若曰信禨祥，我亦爲祝史。"]'),
('a2e1a37a-9def-4b00-bd7f-c42e4ba89290','韓叔沖約客泛舟滄江分韻得落字','魏了翁','宋','宋诗','song-poetry','','[]','炎煒避無所，意行出東郭。',96,'全唐诗/poet.song.190000.json','["炎煒避無所，意行出東郭。", "客以聲氣聚，舟於樹泉泊。", "江動雲意閒，林幽鳥聲樂。", "山川孰流峙，鳶魚自飛躍。", "天分隨所適，豁然無空闊。", "有客猶謂余，底處認真活。", "是心無間斷，本體自呈豁。", "一笑各會心，星河挂碧落。"]'),
('51d2f6a0-1ac6-4f48-a0cd-afc2b3640fc1','贈僧南游','魏了翁','宋','宋诗','song-poetry','','[]','吾少不學佛，吾道聞之嘗。',72,'全唐诗/poet.song.190000.json','["吾少不學佛，吾道聞之嘗。", "虛靈一寸心，無賢愚聖狂。", "人惟不自信，渺渺歧上羊。", "師今緊尋覓，看是真有亡。", "如行人貪程，如久客念鄉。", "一朝眼發明，家山儼成行。"]'),
('b8d5b9e8-3bda-4a0f-954f-9966397ea9d7','寄李考功','魏了翁','宋','宋诗','song-poetry','','[]','虛靈天地心，亹亹萬化機。',72,'全唐诗/poet.song.190000.json','["虛靈天地心，亹亹萬化機。", "幾形有動靜，誠盡無顯微。", "人惟不自信，稷顔有相違。", "居人憚寒暑，遊子行不歸。", "誰知烱然存，彼物乃吾知。", "高人真畏友，聖賢吾師師。"]'),
('e6532add-29f8-43dc-96fa-5af9f5f0d8b4','和李致政花石山詩','魏了翁','宋','宋诗','song-poetry','','[]','春風挽征衣，淑景薦籩實。',120,'全唐诗/poet.song.190000.json','["春風挽征衣，淑景薦籩實。", "山中之奇觀，變態紛襞積。", "或劃然以舒，或蒙然以密。", "或嫵如脩眉，或突如巨迹。", "或鷙鳥將搏，或遊龍偕出。", "一目百奇怪，隨景發詩癖。", "江山昔豈無，萬古閲閒寂。", "而獨陳於今，涸我風月筆。", "便如遺俗士，高卧天一壁。", "人知匪自獻，不知亦奚恤。"]'),
('6627ecb7-50b7-4ce8-af38-cdb52e3a4716','次韻黄侍郎海棠花下怯黄昏七絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','狂風利劍戟，火龍困屠宰。',24,'全唐诗/poet.song.190000.json','["狂風利劍戟，火龍困屠宰。", "莫起落紅愁，生意浩雲海。"]'),
('991da8c4-6980-4443-b006-e646ad2a6f4a','次韻黄侍郎海棠花下怯黄昏七絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','曾訪郊原春，靜觀煙雨妝。',24,'全唐诗/poet.song.190000.json','["曾訪郊原春，靜觀煙雨妝。", "因物得良晤，諒非昔如棠。"]'),
('f1213d5f-ffd0-42e5-bc51-a0d8d2bcce46','次韻黄侍郎海棠花下怯黄昏七絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','唐人春深題，用韻工車斜。',24,'全唐诗/poet.song.190000.json','["唐人春深題，用韻工車斜。", "逐逐語言去，誰歟真識花。"]'),
('c5ed1166-cb50-4910-9e5f-a465423840b9','次韻黄侍郎海棠花下怯黄昏七絕  其四','魏了翁','宋','宋诗','song-poetry','','[]','臨川數落花，康節愛花謝。',24,'全唐诗/poet.song.190000.json','["臨川數落花，康節愛花謝。", "若作榮悴觀，此特花之下。"]'),
('2ccb5f74-364b-4505-b1b9-9be149d59d73','次韻黄侍郎海棠花下怯黄昏七絕  其五','魏了翁','宋','宋诗','song-poetry','','[]','穉綠茁兒拳，老紅面百摺。',24,'全唐诗/poet.song.190000.json','["穉綠茁兒拳，老紅面百摺。", "詩壇更伏波，令我逢敵怯。"]'),
('e7190036-4e18-42a9-be42-995ecd564f39','次韻黄侍郎海棠花下怯黄昏七絕  其六','魏了翁','宋','宋诗','song-poetry','','[]','天運自消息，詩人費平章。',24,'全唐诗/poet.song.190000.json','["天運自消息，詩人費平章。", "何花春不紅，何草冬不黄。"]'),
('2b07d19d-1d5d-44ba-bc8d-3058541f2b78','次韻黄侍郎海棠花下怯黄昏七絕  其七','魏了翁','宋','宋诗','song-poetry','','[]','醉妃索南內，玉奴斃東昏。',24,'全唐诗/poet.song.190000.json','["醉妃索南內，玉奴斃東昏。", "所以觀物心，皇皇妙無門。"]'),
('80717f39-6d53-4fb1-8424-96be9bd7d2ac','題劍門','魏了翁','宋','宋诗','song-poetry','','[]','江有瞿唐限，陸有雙劍蹲。',132,'全唐诗/poet.song.190000.json','["江有瞿唐限，陸有雙劍蹲。", "如熊羆當道，如虎豹守閽。", "屹然東北隅，奠此西南坤。", "昔歲在單閼，白日塵沙昏。", "人心不足倚，恃此兩長垣。", "舟車之出入，筦鑰有司存。", "銜艫下魚復，委轡充劍門。", "藪逋乃如此，天險何足言。", "况於多蹊隧，不逮昔所聞。", "烈烈張睢陽，英英顔平原。", "古之善守國，人心以爲藩。"]'),
('8e9b2f3f-d1e4-4f1c-ac25-b20d440bcaaf','題大安軍楊寶謨旌忠廟','魏了翁','宋','宋诗','song-poetry','','[]','范陽一夕鼙皷鳴，莽然河朔惟孤城。',160,'全唐诗/poet.song.190000.json','["范陽一夕鼙皷鳴，莽然河朔惟孤城。", "姓名徹聞帝猶謂，我乃不識顔真卿。", "人才所用非所養，自昔然矣奚獨神。", "肘間銀黄挂三組，腰間犀玉圍萬釘。", "養癰護疾皆此輩，事危先及城郭臣。", "求仁得仁性情正，可死無死分義明。", "豈徒一時折羣醜，將與萬世開太平。", "我嘗辱交於神者，寤寐精爽如平生。", "過祠解后日端午，昌歜之酒芬兮清。", "要呼湘纍徑同醉，毋使二子稱獨醒。"]'),
('91ee1abf-10f4-4263-9469-cb87f89c8bb1','出劍門後日履危徑戲集轎兵方言','魏了翁','宋','宋诗','song-poetry','','[]','籃輿陟險隘，兀兀不停轍。',132,'全唐诗/poet.song.190000.json','["籃輿陟險隘，兀兀不停轍。", "主人眩頭目，僕夫困唇舌。", "前疑樹梢拂，後慮崖石擦。", "方呼左畔蹺，復叫右竿捺。", "避礙牢挂肘，衝泥輕下脚。", "或荆棘兜挂，或屋簷拐抹。", "或踏高直上，或照下穩踏。", "斯須有不審，僨輿在目睫。", "深淵固可畏，平地尤險絕。", "作詩告僕夫，審諸秋毫末。", "識察既曉然，力行謹無忽。"]'),
('cf90348c-7fa3-4a5c-8205-c12ce975d5ae','過大安軍黑水阻漲憩崇道觀以需漲落乃濟','魏了翁','宋','宋诗','song-poetry','','[]','川遊不停息，雨集有滿除。',24,'全唐诗/poet.song.190000.json','["川遊不停息，雨集有滿除。", "卓哉鄹魯叟，即茲驗功夫。"]'),
('96b9a320-c839-4ab9-91d3-0158d8640158','寄題王才臣南山隠居六首 莊敬日强齋','魏了翁','宋','宋诗','song-poetry','','[]','天以行故健，火以宿故壯。',24,'全唐诗/poet.song.190000.json','["天以行故健，火以宿故壯。", "卓哉主一翁，挈我洙泗上。"]'),
('2ffc8e40-60a7-4637-8e82-c928347a850c','寄題王才臣南山隠居六首 格齋','魏了翁','宋','宋诗','song-poetry','','[]','水非石之鑽，索非木之鋸。',24,'全唐诗/poet.song.190000.json','["水非石之鑽，索非木之鋸。", "一日復一日，會有豁時處。"]'),
('23d2cc07-76a0-492d-946a-0f271f382021','寄題王才臣南山隠居六首 南谷','魏了翁','宋','宋诗','song-poetry','','[]','我行半天下，夢不到南谷。',24,'全唐诗/poet.song.190000.json','["我行半天下，夢不到南谷。", "健讀諸老詩，劃見真面目。"]'),
('129c99ac-5b06-497f-b80d-5d612c7cf975','寄題王才臣南山隠居六首 竹亭','魏了翁','宋','宋诗','song-poetry','','[]','西山抱孤潔，淇水凝寒綠。',24,'全唐诗/poet.song.190000.json','["西山抱孤潔，淇水凝寒綠。", "古來長安道，多少閒草木。"]'),
('72c76013-ba97-4309-b451-8909cc7fa591','寄題王才臣南山隠居六首 松庵','魏了翁','宋','宋诗','song-poetry','','[]','受命獨也正，巋然十八公。',24,'全唐诗/poet.song.190000.json','["受命獨也正，巋然十八公。", "人獨匪正命，胡然不如松。"]'),
('87e395b6-6ef0-4c54-a5d1-29c4c91c1cc7','寄題王才臣南山隠居六首 腴亭','魏了翁','宋','宋诗','song-poetry','','[]','膏雨炯晨沐，和風照春睡。',24,'全唐诗/poet.song.190000.json','["膏雨炯晨沐，和風照春睡。", "誰與驗其機，蔡軒一腴字。"]'),
('15284367-0940-4c88-961b-cbd3987700a1','謝安大使見遺白玉環','魏了翁','宋','宋诗','song-poetry','','[]','寶刀切寒玉，解作環無端。',132,'全唐诗/poet.song.190000.json','["寶刀切寒玉，解作環無端。", "連蜷虹貫日，晶潤晴生煙。", "帝省岷嶓下，冠珮人閒閒。", "迺飭坤之靈，效貢窮山淵。", "不以他物效，以是期公還。", "維公倡德意，地寶弗敢刓。", "玉汝不汝瑕，來墮玻江前。", "因思取予義，僑也辭韓宣。", "落落竟弗合，而此微求旃。", "服之報安所，我無青琅玕。", "圭復以爲謝，不踐如斯環。"]'),
('7bd3f720-8de7-4175-bc3d-6117f25afbfa','送二兄三兄赴廷對','魏了翁','宋','宋诗','song-poetry','','[]','吾家令兄弟，異氏而同氣。',288,'全唐诗/poet.song.190000.json','["吾家令兄弟，異氏而同氣。", "雅知義利分，不作溫飽計。", "天子龍飛春，了翁對軒陛。", "柄臣方擅朝，黨論如鼎沸。", "軋軋不能休，一揮三千字。", "植治貴和平，用人戒偏陂。", "天子擢第一，期以風有位。", "尋寘之三人，仍詔恩禮視。", "後此者三年，東瞻復聯第。", "天子方諒闇，有言不得試。", "歲行在協洽，文翁陳讜議。", "惟知守家學，寧顧觸時忌。", "雖不第甲乙，自謂儻無愧。", "古人爲己學，何有於富貴。", "窮則獨善身，仕將以行義。", "兩兄西南彥，九牧將倒指。", "平生剛直胸，毋以科舉累。", "矧逢主聽寬，寧復懷顧畏。", "厥今果何事，請略陳一二。", "內無王文正，誰與理家事。", "外無韓忠獻，誰與飭戎備。", "熒惑守羽林，震雷詫冬瑞。", "天象已云然，人事猶爾耳。", "劈析爲上言，卓哉朝陽喙。"]'),
('128412da-508f-44d5-b5a6-a82e244c81b8','次韻虞果州泛雪','魏了翁','宋','宋诗','song-poetry','','[]','黄雲靉靆風雪天，欲之霸橋尋浪僊。',224,'全唐诗/poet.song.190000.json','["黄雲靉靆風雪天，欲之霸橋尋浪僊。", "爐中榾柮縶寒客，縱欲燒愁能得然。", "撥灰嚼句不忍吐，竟日南望雙眸穿。", "誰知詩來亦念我，字與六出爭明蠲。", "美人美人呼不來，昭華吹怨樓西偏。", "况有山頭月爲友，觸撥煙痼撩詩顛。", "豈無詠絮謝家集，亦有閉戶袁安眠。", "未如山中之至樂，白玉世界天相連。", "朝看夜聽兩奇絕，靴霜爐雪知誰賢。", "褰裳急理剡溪棹，明月已旁羌江還。", "羌江白雲遶親舍，北山夜雨鳴清川。", "世間真樂不易道，此以意會非言傳。", "惜哉往日不可再，江頭望君如望年。", "研澌筆凍不成報，夢中書劄來翩翩。"]'),
('19643461-4c01-479e-a9ff-73a26118c03f','約眉之寓公飲郡圃梅下分韻得動字','魏了翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','窮陰彫殘年，小雨雜寒凍。',204,'全唐诗/poet.song.190000.json','["窮陰彫殘年，小雨雜寒凍。", "野迥山色枯，木落天宇空。", "殷勤玉雪友，歲歲管賓送。", "孤標耿黄昏，清豔橫螮蝀。", "從渠忌皎潔，孱顔立孤聳。", "半年簿書塵，閒殺果下鞚。", "林端劃見之，撩我潑春甕。", "芳菲惱不徹，喜與良友共。", "花光留夕陰，鳥語嘎清哢。", "羣芳去無蹤，生意正坌涌。", "因懷武陵日，歲上西湖冢。", "粲粲萬玉妃，蕭蕭守翁仲。", "誰知落天涯，惠然復我從。", "暗香踈影句，爲我作詩供。", "心事炯如霜，客遊恍成夢。", "歲窮萬物息，誰此役羣動。", "會取春風心，處處得日用。"]'),
('57f9376c-21ab-4178-8e31-30e5c1b4c69f','虞知府生日','魏了翁','宋','宋诗','song-poetry','','[]','皇天覆后土，藐然吾一身。',168,'全唐诗/poet.song.190000.json','["皇天覆后土，藐然吾一身。", "職職萬同宇，何所非吾仁。", "人惟不自信，私意橫紛綸。", "君侯覽厥初，渾渾川無津。", "百家之精粹，六藝之芳醇。", "挹之未厭斁，欲以警此民。", "天機行日月，大戒明君臣。", "一源顯微貫，萬象曉晦新。", "焉知我爲我，聊以人治人。", "胡然閟厥施，膏澤猶其屯。", "意將楙所養，切磋及茲辰。", "余也峨眉陰，君兮滄江濱。", "生生共茲意，不隔江山春。", "懷哉寧無車，有繫未可巾。"]'),
('6356a959-deea-4b8d-a300-d80043bfa3b6','王總領生日','魏了翁','宋','宋诗','song-poetry','','[]','古來五大不在邊，國家長慮初解絃。',193,'全唐诗/poet.song.190000.json','["古來五大不在邊，國家長慮初解絃。", "西南計臣授鈇鉞，獨以一手擎半天。", "三邊將士趨節制，百城吏民服威惠。", "載宣寬詔問無恙，扶藜往聽翁顔喜。", "我圖爾土居未怡，室家僅葺風雨欺。", "波濤沄沄逐風靡，山色澹澹憂陵夷。", "機空絡緯那可織，徽穿虎豹疇能識。", "秦門夕燧雖平安，燕帳秋弓未休息。", "翁顔且喜舊觀還，尚恐世事愁無端。", "祝公爲民久遠慮，憂顧期使西南寬。", "美官厚祿等閒耳，得君得時不易然。", "君不見富公在青州，多於中令廿四年。"]'),
('1b32b164-2b94-4750-8c4b-0694d5fc67ed','重陽前一日約寓公飲于新開湖之西港有歌詞者其亂曰會與州人飲公遺愛一江醇酎遂以此分韻賦詩某得一字','魏了翁','宋','宋诗','song-poetry','','[]','吾州遠景樓，爲天下第一。',156,'全唐诗/poet.song.190000.json','["吾州遠景樓，爲天下第一。", "下有千尺湖，長虹倚斜日。", "煙雲紛蔽虧，草樹互蒙密。", "人既位通顯，湖猶困遺逸。", "一段雲錦機，割截不成疋。", "我來劃見之，慨然爲拈出。", "凹者豁以舒，凸者疏而溢。", "乃取半山句，以榜湖陰室。", "晨舟亂平渺，日晏未云畢。", "客喜以問余，幻成子何術。", "余非襲而致，彼有是良質。", "牛山木嘗美，茅徑人自窒。", "一笑各會心，凉風送蕭瑟。"]'),
('f0c379f6-738e-4706-9fe8-6a4c06e53f58','次韻李參政湖上雜詠錄寄龍鶴墳廬  其一','魏了翁','宋','宋诗','song-poetry','','[]','龍鶴在吾西，昔年班荆處。',36,'全唐诗/poet.song.190000.json','["龍鶴在吾西，昔年班荆處。", "乃今五斗米，縶之不得去。", "冬夜那何晨，斜河耿高樹。"]'),
('8a76ae64-0e07-4969-87ae-2c8ec9163542','次韻李參政湖上雜詠錄寄龍鶴墳廬  其二','魏了翁','宋','宋诗','song-poetry','','[]','木落天宇空，野迥江水碧。',36,'全唐诗/poet.song.190000.json','["木落天宇空，野迥江水碧。", "誰歟驅四運，昨夕復今夕。", "君看瀛海內，壽考匪金石。"]'),
('83eab212-e65d-45b6-abd5-20ad950157ef','次韻李參政湖上雜詠錄寄龍鶴墳廬  其三','魏了翁','宋','宋诗','song-poetry','','[]','聖死微言湮，千載迷津涯。',36,'全唐诗/poet.song.190000.json','["聖死微言湮，千載迷津涯。", "浮驂徧八極，日暮猶伊鴉。", "大道如掌平，人苦不識家。"]'),
('f6d3edbc-faef-49c1-b9b4-8b60ead84603','次韻李參政湖上雜詠錄寄龍鶴墳廬  其四','魏了翁','宋','宋诗','song-poetry','','[]','南山高崔嵬，草樹蔚喬林。',36,'全唐诗/poet.song.190000.json','["南山高崔嵬，草樹蔚喬林。", "雲橫日曀曀，蟬鳴谷陰陰。", "戛然丹鳳咮，爲我作好音。"]'),
('7f71dad6-e26e-4923-b308-a1fedec74988','次韻李參政湖上雜詠錄寄龍鶴墳廬  其五','魏了翁','宋','宋诗','song-poetry','','[]','西山有佳人，慣踏山下路。',36,'全唐诗/poet.song.190000.json','["西山有佳人，慣踏山下路。", "晨吟澤畔雲，午睡巖前雨。", "莫使兒輩覺，奪我林壑趣。"]'),
('d71a587c-b587-4ff9-909d-52dec839053e','次韻李參政湖上雜詠錄寄龍鶴墳廬  其六','魏了翁','宋','宋诗','song-poetry','','[]','仲尼趨聘召，季路奚不懌。',36,'全唐诗/poet.song.190000.json','["仲尼趨聘召，季路奚不懌。", "分量固爾殊，何傷於遍歷。", "自揣或未能，莫如只堅白。"]'),
('3299c3ae-9d96-421f-906c-56162a69edfc','次韻李參政湖上雜詠錄寄龍鶴墳廬  其七','魏了翁','宋','宋诗','song-poetry','','[]','皇天平四時，先春而後秋。',36,'全唐诗/poet.song.190000.json','["皇天平四時，先春而後秋。", "寒威奪仁氣，慘慘紛百憂。", "康世非我長，自許以一丘。"]'),
('e5aa0c6b-b4bf-4999-b9e3-98cd082997c8','次韻李參政湖上雜詠錄寄龍鶴墳廬  其八','魏了翁','宋','宋诗','song-poetry','','[]','古人爲己學，不以遇不遇。',36,'全唐诗/poet.song.190000.json','["古人爲己學，不以遇不遇。", "學問思辨行，止定靜安慮。", "次序固曉然，人情苦傷遽。"]'),
('331bb8bb-50eb-47b1-9d35-e76d97744a52','次韻李參政湖上雜詠錄寄龍鶴墳廬  其九','魏了翁','宋','宋诗','song-poetry','','[]','百年狐兔窟，汙我黄河流。',36,'全唐诗/poet.song.190000.json','["百年狐兔窟，汙我黄河流。", "槃槃帝王州，僅與甌脫侔。", "秋風壯夫淚，禾黍莽平疇。"]'),
('05ed15de-54b8-49ca-b5d7-60311706fb6f','次韻李參政湖上雜詠錄寄龍鶴墳廬  其一○','魏了翁','宋','宋诗','song-poetry','','[]','江左憂佛狸，荆州忌老瞞。',36,'全唐诗/poet.song.190000.json','["江左憂佛狸，荆州忌老瞞。", "既虞薪下火，又恥泥中蟠。", "不虞復不恥，志士寧無嘆。"]'),
('2e52130e-d476-46df-a518-823c53a1aec9','次韻李參政湖上雜詠錄寄龍鶴墳廬  其一一','魏了翁','宋','宋诗','song-poetry','','[]','大亨惟同人，小知僅私己。',36,'全唐诗/poet.song.190000.json','["大亨惟同人，小知僅私己。", "皇皇萬井封，耽耽百重陛。", "爾痾寔余恫，須知本同體。"]'),
('8e7a5d08-c9e1-4694-88ff-82e0584cde97','次韻李參政湖上雜詠錄寄龍鶴墳廬  其一二','魏了翁','宋','宋诗','song-poetry','','[]','南園鼎盛時，紛紛車馬跡。',36,'全唐诗/poet.song.190000.json','["南園鼎盛時，紛紛車馬跡。", "須臾風景異，樹老春寂歷。", "盛衰那可常，此理最明白。"]'),
('be7907ec-6ab9-42f7-8c46-5ac98c9ba3f0','次韻李參政湖上雜詠錄寄龍鶴墳廬  其一三','魏了翁','宋','宋诗','song-poetry','','[]','世有傀儡棚，帳幙深遮圍。',36,'全唐诗/poet.song.190000.json','["世有傀儡棚，帳幙深遮圍。", "衣冠巧裝飾，觀者迷是非。", "自謂真好手，不知若爲歸。"]'),
('416b6304-d7f2-4acf-b11f-7fe79d10f6f1','續和李參政湖上雜詠  其一','魏了翁','宋','宋诗','song-poetry','','[]','陰陽互推移，氣數有信屈。',36,'全唐诗/poet.song.190000.json','["陰陽互推移，氣數有信屈。", "澗松發貞姿，庭梅睟生色。", "雖無桃李容，桓桓保終吉。"]'),
('154cfc05-0941-44f8-a32d-143bcf64b321','續和李參政湖上雜詠  其二','魏了翁','宋','宋诗','song-poetry','','[]','氣力與運頹，十步九蹉跌。',36,'全唐诗/poet.song.190000.json','["氣力與運頹，十步九蹉跌。", "聞有用我者，掩耳忽不悅。", "吾非嵇康徒，道遠未能涉。"]'),
('ce0cb480-1de8-4e9e-a7e0-2edbd75ee3d5','續和李參政湖上雜詠  其三','魏了翁','宋','宋诗','song-poetry','','[]','虛靈一寸心，攻者十七八。',36,'全唐诗/poet.song.190000.json','["虛靈一寸心，攻者十七八。", "炯然無常存，精粗皆著察。", "衛丘騋牝蕃，魯囿牛羊茁。"]'),
('4a4c6594-0eb5-444e-8c55-e5c10dd89d8c','續和李參政湖上雜詠  其四','魏了翁','宋','宋诗','song-poetry','','[]','古之求仁者，信道不蘄獲。',36,'全唐诗/poet.song.190000.json','["古之求仁者，信道不蘄獲。", "顔生何所樂，寧蹈饑寒厄。", "能知四勿功，六根本非賊。"]'),
('7072478a-6cdb-4e7b-8c8d-f69cd74620e8','續和李參政湖上雜詠  其五','魏了翁','宋','宋诗','song-poetry','','[]','嚴君閑有家，富之以其道。',36,'全唐诗/poet.song.190000.json','["嚴君閑有家，富之以其道。", "幾年困外禦，囊空甑復倒。", "家人良自勉，歲晏願相保。"]'),
('d119eb6f-69dc-4220-be4b-29a906ae0615','續和李參政湖上雜詠  其六','魏了翁','宋','宋诗','song-poetry','','[]','晉當胡運衰，厲世先黜陟。',36,'全唐诗/poet.song.190000.json','["晉當胡運衰，厲世先黜陟。", "當時望塵友，有識所憤疾。", "云何祖士稚，不似劉越石。"]'),
('0690a313-e628-4481-8d81-1d553bfe3667','續和李參政湖上雜詠  其七','魏了翁','宋','宋诗','song-poetry','','[]','人心不可欺，好好而惡惡。',36,'全唐诗/poet.song.190000.json','["人心不可欺，好好而惡惡。", "利欲怵迫之，本心月以落。", "所以古之人，憂在晉其角。"]'),
('f65f2c11-d599-4e69-b7bd-d6864e68cf51','西郊訪梅約李提刑李參政八客分韻得爾字','魏了翁','宋','宋诗','song-poetry','','[]','荒煙散牛羊，落日下城市。',156,'全唐诗/poet.song.190000.json','["荒煙散牛羊，落日下城市。", "天寒萬木脫，歲晏羣動弭。", "西郊有孤芳，獨喚春事起。", "幽光耿參月，清豔明野水。", "欲開未開時，似語不語意。", "或疑春較遲，的皪尚霜蘂。", "誰知春風心，渾在阿堵裏。", "洞霄逍遥公，九隴花月使。", "領客居上頭，蹇予亦婪尾。", "頗懷去年遊，歲月如許駛。", "悠悠竟何成，總被物化使。", "索酒浮大觥，歌商曳窮履。", "真意浩無窮，作詩聊復爾。"]'),
('de65b2b5-acf4-48d4-981d-36112a59516f','梁運判生日','魏了翁','宋','宋诗','song-poetry','','[]','有歌不必歌吳趨，有舞不用陳巴渝。',200,'全唐诗/poet.song.190000.json','["有歌不必歌吳趨，有舞不用陳巴渝。", "試聽天下紫雲曲，著意自與人間殊。", "益州刺史梁大夫，高冠長珮鳴清都。", "秋原方集迎車雉，春風欲送升平烏。", "却思忠獻海棠處，少日曾此扶親輿。", "問天乞英簜，叶氣爲先驅。", "有酒皆郎清，有書皆父腴。", "人逢善旦稱吉祝，六引三調何虛邪。", "勿言商聲苦太勁，爲國綱紀正要渠。", "厥今事勢將何如，鄰家盜起翁無襦。", "乘風縱燎未渠已，我薪未徙屋未塗。", "天之生賢端有意，平治况是公規摹。", "儘將吉德爲壽本，扶桑自昔無榮枯。"]'),
('74e28090-0f82-4ceb-986e-962eff436852','貽廬陵術士馮椿','魏了翁','宋','宋诗','song-poetry','','[]','月宿南斗韓愈生，歲在巳辰鄭玄死。',32,'全唐诗/poet.song.190000.json','["月宿南斗韓愈生，歲在巳辰鄭玄死。", "二人言命是邪非，我欲質疑於孟子。"]'),
('6fc09cd7-0378-47a6-a643-3abfd6c945ba','浣花即席','魏了翁','宋','宋诗','song-poetry','','[]','輕颸濯袢暑，清與耳目謀。',180,'全唐诗/poet.song.190000.json','["輕颸濯袢暑，清與耳目謀。", "江山新容態，真意爛不收。", "榜人以戒余，將事東郊游。", "川后且靜波，馮夷亦安流。", "聯鑣載羣彥，駢筵駕方舟。", "月中亂平渺，高舂尚夷猶。", "俯瞰大江橫，仰看蒼雲浮。", "滔滔去不息，亹亹生無休。", "俯仰三太息，發我心悠悠。", "未省昔之人，曾有此樂不。", "團團轉蘭枻，突見龍棹頭。", "鬨然兩敵國，蒿矢迅不留。", "所爭何爲者，對面如仇讎。", "少須遊人散，天暝風泠颼。", "清興浩無極，洗醆更勸酬。"]'),
('bdd081d1-749e-40c4-adab-ad006e733b34','再和浣花韻呈李彭州李參政','魏了翁','宋','宋诗','song-poetry','','[]','囅然一開口，天也非人謀。',168,'全唐诗/poet.song.190000.json','["囅然一開口，天也非人謀。", "江山自舊管，風景仍新收。", "一門令兄弟，而我從之遊。", "衛玠珠玉側，李膺神僊舟。", "主賓有良晤，兄弟無相猶。", "雨餘白日靜，江遠青天浮。", "相彼宇宙廣，覺我心休休。", "世傳浣溪女，聲跡疑謬悠。", "靈均亦已遠，英烈今在不。", "又懷唐拾遺，泯然哀江頭。", "陵谷幾變遷，屈孟獨長留。", "於此本何負，而以德爲讎。", "因時慨前哲，坐久風飂颼。", "良會惜難再，作詩以相酬。"]'),
('308c509b-5e22-4f11-b805-ed475e177931','送趙茶馬東歸','魏了翁','宋','宋诗','song-poetry','','[]','又因送客朝京闕，意行偶過山之陽。',64,'全唐诗/poet.song.190000.json','["又因送客朝京闕，意行偶過山之陽。", "檻開岷嶺半天雪，簾捲峨眉千丈岡。", "斷霞明空暮江白，密陰藏雨秋原香。", "客歸便可報明主，滿川看看秔雲黄。"]'),
('4adfc168-08bd-452a-8f33-16a11ac41ff7','李參政生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','湖淺霜鴈寒，天高老龍蟄。',120,'全唐诗/poet.song.190000.json','["湖淺霜鴈寒，天高老龍蟄。", "悠悠瀛海間，時運遞消息。", "黄鐘一龠回，槁瘁亦敷澤。", "茹茅趣連征，墐戶同一闢。", "向來屯陰地，有果終不食。", "存之迺天意，斯道古根極。", "公論無消磨，物情自喧寂。", "喧寂安足計，秋雲卷無跡。", "請公護景光，春事勤種植。", "明朝揆初度，萬象好顔色。"]'),
('30f690ab-41a6-4ca3-ab67-60950fc1bc88','李參政生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','二年老翁泉，親酌石林壽。',120,'全唐诗/poet.song.190000.json','["二年老翁泉，親酌石林壽。", "林翁硬如石，跌宕杯舞手。", "酡顔照湖山，麗藻濯花柳。", "牛頭望蟇頤，隔闊幾煙岫。", "江梅驛堪寄，湖水觴可侑。", "林丘一曲閒，事業千載就。", "屢空有真實，萬變無雜揉。", "用之還帝師，歸則赤松友。", "蟠桃堪一嘗，世味不同嗅。", "得書方醉歌，癡絕記前守。"]'),
('fbc498d4-bfe6-4434-9c87-50f1937d7546','次韻郭方叔諸公借胡致堂賞梅至夜賦詩','魏了翁','宋','宋诗','song-poetry','','[]','玄陰作秋冬，殺氣寓風雪。',164,'全唐诗/poet.song.190000.json','["玄陰作秋冬，殺氣寓風雪。", "土深候蟲閉，山靜飛鳥絕。", "誰知無邊春，萬古長不滅。", "或暢然以舒，或凝然以結。", "或聚爲融和，或散爲騷屑。", "又嘗以此觀諸人，生意不斷長如薰。", "咸陽宮殿氣成霧，忽作芒碭山澤雲。", "神爵甘露來紛紛，畫堂已入王政君。", "人從動後觀變態，誰於起處探絪縕。", "淺者若爲見，夜氣長如神。", "儻知起滅幻，便省消息真。", "如何天機之淺者，但識人間桃李春。"]'),
('77a78c9e-8c03-4f62-8b29-9cc2c9c16f62','次韻劉左史王亭觀梅','魏了翁','宋','宋诗','song-poetry','','[]','南山有佳境，天作而地藏。',180,'全唐诗/poet.song.190000.json','["南山有佳境，天作而地藏。", "誰其搜抉之，主者今歐陽。", "時當冬候最，靉靆雲無光。", "爛嚼暗香句，浩歌黄竹章。", "詩成物有主，意遠天無旁。", "衆賓從老守，遥林拱孤芳。", "氣味自爾殊，凡卉不敢香。", "芸芸天壤間，何草冬不黄。", "獨此冰雪質，老氣磨蒼蒼。", "便如身潔人，易知復難忘。", "頗懷熙豐日，羣妍偃冰霜。", "皓然深衣老，春風貯肝腸。", "抉開第一機，還作桃李鄉。", "終然和鼎實，以侑千歲觴。", "三嗅幾而作，臨風倍輕狂。"]'),
('d1574f5d-6d10-4b82-b3d1-e030bcac0381','題潼川倅廳先得月樓','魏了翁','宋','宋诗','song-poetry','','[]','濃雲捲羃衡嚮北，天風不摇萬響息。',64,'全唐诗/poet.song.190000.json','["濃雲捲羃衡嚮北，天風不摇萬響息。", "蟇行爬沙踏科臼，顧菟茫洋長在腹。", "本來全體自分明，日用其間人莫識。", "弄丸之暇劃若逢，笑拍闌干我先得。"]'),
('913e51a2-a0f9-411e-adc0-aba193244b3c','和宇文漢州乞房樓記詩','魏了翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','房公胸中妙刀尺，翦刻玻璃貯寒碧。',192,'全唐诗/poet.song.190000.json','["房公胸中妙刀尺，翦刻玻璃貯寒碧。", "今侯著樓於其上，竹色荷光得良覿。", "詩來殷勤問故侯，別日雖賒情轉密。", "因思當年飛蓋遊，鷗鷺不驚潛鯉出。", "春濃雪絮人影亂，秋老雲松半天屹。", "蘇公二十四橋月，尚愛西湖風月夕。", "江山好處餘戀嫪，縱不即人人自即。", "况今簷撩雲與齊，激楚高歌友朋集。", "向來寒乞翻自嗤，詩掃黄泥已無迹。", "功名老我後加鞭，文字餘人先奪席。", "欲搜萬象供刻畫，自有此湖難此筆。", "終當爲君記斯遊，摹寫蒼顔真六一。"]'),
('d1fba104-17f6-46d2-84c9-e0d9043bdbeb','約許侍郎諸公酒半宋正仲至自都城','魏了翁','宋','宋诗','song-poetry','','[]','人生能得幾回別，一別公來四千日。',192,'全唐诗/poet.song.190000.json','["人生能得幾回別，一別公來四千日。", "我騎紫馬出行春，公指黄扉入當夕。", "誰知行止不關人，解后天涯復同席。", "方看紫陌爛紅英，忽復濃陰顆青實。", "斷霞明空白日靜，過雨穿林亂雲濕。", "如夢如夢夢邪非，曰歸曰歸歸未得。", "僰南山崒東流斷，關西雲霾北風急。", "酒逢故人一吸易，語及新事百憂集。", "試問吾歸將何歸，梓州遂州有何擇。", "况有青山老居士，千騎東來闖然入。", "更得可人高帝孫，又忻末至臨邛客。", "儘判三日作狂酲，要話十年胸愊塞。"]'),
('c2ed742b-87ee-45f0-ac61-ca6ef84c56b4','登元祐閣次韻李左史所和范瀘州詩','魏了翁','宋','宋诗','song-poetry','','[]','飄風吹面酒無力，萬響摇摇不停息。',64,'全唐诗/poet.song.190000.json','["飄風吹面酒無力，萬響摇摇不停息。", "主賓巉然立分鼎，抑抑威儀長不忒。", "冰槃時薦櫻筍香，烏絲快洒薔薇墨。", "夜深山靜天四垂，悠然發我真聞識。"]'),
('98303a40-e2ed-40e1-b6bb-e63a620fe400','臨川過永叔植慈竹義木於庭廼榜其堂曰慈義索余詩','魏了翁','宋','宋诗','song-poetry','','[]','冬笋與霜堇，孝可使之生。',180,'全唐诗/poet.song.190000.json','["冬笋與霜堇，孝可使之生。", "老槐與枯荆，義可使之榮。", "芸芸天壤閒，何物非吾誠。", "根心貫芽枿，影響於形聲。", "過君資孝友，早識真重輕。", "一時東南彥，意氣何相傾。", "虛几隠天籟，深居觀物情。", "慈竹吾父子，義木吾弟兄。", "夜簷月送影，晝戶煙輸晴。", "與我一般意，乃作堂堂名。", "竹根頭𧥄𧥄，下覆復上承。", "木以同本故，葉葉皆相親。", "承覆匪强合，相親誰使令。", "茲有靡不有，斧斤日丁丁。", "願言厚封植，歲晚長青青。"]'),
('296c8eb9-7098-4a51-89a9-eb3065159cdf','潼川憲司拓圃築亭取康節語名以四春得古詩十二韻','魏了翁','宋','宋诗','song-poetry','','[]','皇天平四時，不以秋先春。',144,'全唐诗/poet.song.190000.json','["皇天平四時，不以秋先春。", "仁人奉天職，不以德後刑。", "次序固云然，表裏元相因。", "方春布陽煒，萬物皆精神。", "當秋乃揫歛，黄落山川貧。", "天機之淺者，榮悴爲戚忻。", "誰知天地心，於此常肫肫。", "既嘗驗諸理，又以取諸身。", "四德孰非元，四端孰非仁。", "刑威雖時用，生意固長存。", "四時長有春，吾聞邵子云。", "觸事識初心，乃以名吾亭。"]'),
('04ab59db-80b1-487e-848a-8ce49c536fa1','遂寧社稷壇與風雷雨師之壇混爲一區其間多悖禮者某偶攝郡事因爲隨事釐正','魏了翁','宋','宋诗','song-poetry','','[]','始余求諸社，窮巷窈而曲。',192,'全唐诗/poet.song.190000.json','["始余求諸社，窮巷窈而曲。", "草陰荒蒙茸，林影亂樸樕。", "其中有屋廬，其下主以木。", "社稷風雨雷，皆於此乎告。", "趨闇不求陽，如叢祠而局。", "就簡不辨方，如古墓而族。", "引我拜乎上，高床被茵褥。", "使我視所陳，紙幣薦薌燭。", "爵不以坫寘，酒不以茅縮。", "牲不以碑麗，齋戶不以宿。", "於禮無所稽，承訛已云熟。", "從之則咈余，不從亦違俗。", "是心既不慊，雖暫亦爲瀆。", "屋不受天陽，此豈容有屋。", "先易其甚者，餘事踵相屬。", "其有不逮爲，則以告新牧。"]'),
('fed1e8cb-a4d0-4a27-8bcc-96a18e24c50f','次韻張太博見貽  其一','魏了翁','宋','宋诗','song-poetry','','[]','門前車馬塵滔滔，試問有誰閒似我。',32,'全唐诗/poet.song.190000.json','["門前車馬塵滔滔，試問有誰閒似我。", "夜燈照出千古心，曉窗掣破重玄鎖。"]'),
('0985190c-72aa-4b04-aa98-35aeb014a7e1','次韻張太博見貽  其二','魏了翁','宋','宋诗','song-poetry','','[]','別後幾如隔世人，閒中認得當年我。',32,'全唐诗/poet.song.190000.json','["別後幾如隔世人，閒中認得當年我。", "清風應傍笑譚來，明月不隨門戶鎖。"]'),
('a6ab1bc9-2a2e-438b-a64a-bb2f3a07edc5','再次韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','眇觀千載苦無人，窺見一毫先有我。',32,'全唐诗/poet.song.190000.json','["眇觀千載苦無人，窺見一毫先有我。", "雋敏既爲文采誤，高明又被玄虛鎖。"]'),
('593b93e8-1c3a-4672-b9e3-60866c94f2a0','再次韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','我嘗妄意於古人，子今用力苦先我。',32,'全唐诗/poet.song.190000.json','["我嘗妄意於古人，子今用力苦先我。", "安得從容長似今，借子玉匙發關鎖。"]'),
('4e3493de-3fcb-4913-aa06-a5548703772a','次韻張太博得余所遺二程先生集辯二程戲邵子語','魏了翁','宋','宋诗','song-poetry','','[]','文字未科斗，圖書未龜龍。',264,'全唐诗/poet.song.190000.json','["文字未科斗，圖書未龜龍。", "粲然天地間，此理觸處逢。", "是謂象之祖，而爲數之宗。", "昊犧古神聖，先得人所同。", "文因而繇之，旦出亦並雄。", "訖于我孔聖，天命滋益恭。", "渾然一理貫，密察而從容。", "辭變與象占，四者固所崇。", "推辭以知變，象占在其中。", "荒荒秦漢後，學者昧所從。", "不以災異會，則以虛無通。", "天開周程子，易道乃復東。", "動靜靜復動，終始始而終。", "上承千年緒，下起百世風。", "同時有邵子，講道于伊嵩。", "天地之運化，陰陽之無窮。", "即物驗消長，先幾知吉凶。", "邵子極道數，獨立幾無戎。", "二程自周孔，爲時開夢夢。", "其歸則一耳，昧者結忡忡。", "學之將柰何，矧余倍顓蒙。", "要知羲皇心，須踏周孔蹤。"]'),
('72702d59-b2ee-458e-a353-e8a4b150d79f','虞萬州生日','魏了翁','宋','宋诗','song-poetry','','[]','春風吹我游錦官，客眸飽作滄江觀。',384,'全唐诗/poet.song.190000.json','["春風吹我游錦官，客眸飽作滄江觀。", "鶴飛自由白日靜，山來不斷平野寬。", "主人聞客倒屣迎，案頭點易朱未乾。", "速呼朋儔俾接席，又遣兒女來拜前。", "館中列鼎食客衆，堂後鳴鐘聚指千。", "客來輒留張坐飲，客醉復與開榻眠。", "主人投閒六年久，祿廩不繼胡能然。", "問之主人笑不言，神情散朗心常閒。", "向來曾於我乎貸，至今尚質黄金盤。", "又聞吾兄市橋尉，假五十萬青銅錢。", "橐中似爾空亦屢，門外車馬紛闐闐。", "其間猶有不知者，誤謂公子非儒酸。", "誰知出分本無幾，况復奉賜隨分班。", "知之不知吾何恤，日用飲食於其閒。", "西京相裔平通侯，輕財重義無敢先。", "三年田家未云久，便懷富貴譏南山。", "節侯有子韋少翁，亦以明經世其傳。", "爵之附庸有何薄，徑欲忍愧從夷蠻。", "人於居約視所守，又以久近察所安。", "近而不渝儻可勉，久而無怨良獨難。", "不須遠求漢諸公，姑復近考今時賢。", "雖云暫閒未嘗約，一念長作膏火煎。", "戚然不能以一日，寧復如君之六年。", "泉無晝夜蓋有本，潦有朝夕繄無源。"]'),
('1ab00418-ef48-4aee-803e-9c310750412d','董侍郎生日','魏了翁','宋','宋诗','song-poetry','','[]','后皇一念根至仁，地雖南北民吾民。',392,'全唐诗/poet.song.190000.json','["后皇一念根至仁，地雖南北民吾民。", "一二指搐不可信，彼動此應關諸身。", "人言犬戎相噬吞，彼蚌鷸耳吾漁人。", "大國信誓方重申，時遣升勺蘇窮鱗。", "有狼其心不我恩，囊書赤白驚嚴宸，帝曰可矣予其征。", "臣某奉詔之淮濆，臣某董師留漢濱。", "西南憂顧誰其分，我有從橐之親臣。", "時其動靜制主賓，自闑以外惟將軍。", "邊頭赤子方寢薪，旆旌悠悠鳥烏馴。", "將軍羽扇白綸巾，且將沈靜弭放紛。", "邇來世道波沄沄，士爲欲縛迷天真。", "開禧戎首終身焚，未聞先事人有言。", "大官一唱和者羣，前而和之後云云。", "厥今狂猘先狺狺，事勢不與開禧倫。", "方拯摯獸招饑蚊，此何爲者祇自塵。", "志士憤惋三軍顰，置之不治虎患存。", "治之不勝桃蟲拚，勝之不盡窮獸奔。", "盡矣復與誰爲鄰，譬諸白黑方交枰。", "彼據腹脇吾邊唇，養成持勢猶不均。", "况彼攻奪吾逡巡，局勢往往隨時新。", "不有妙手誰彌綸，人才生世厥有因。", "帝賫天假崧降神，一心可以位乾坤。", "浮雲軒冕何足論，祝公早還要路津。", "并包衆智資多聞，倡明大義清妖氛。"]'),
('4b8ae560-256c-4aee-ab0d-05a598a65f6b','王總領生日','魏了翁','宋','宋诗','song-poetry','','[]','皇天覆后土，藐然中爲人。',252,'全唐诗/poet.song.190000.json','["皇天覆后土，藐然中爲人。", "職職萬同宇，何所非吾仁。", "一二指搐耳，動且關嚬呻。", "置之非害事，尚欲求其信。", "矧今我赤子，犬羊所噬吞。", "養之將遺患，迫之幾寡恩。", "猶以赤子故，未忍窮追奔。", "蠢彼不我德，羽書驚嚴宸。", "帝曰斯可矣，戎首將自焚。", "一軍戍江介，一軍留漢濱。", "雨中徹桑土，火後憂突薪。", "又念蜀上游，擢才餉吾軍。", "蜀力如蝸涎，僅足以濡身。", "云胡走荆楚，坐視空川秦。", "天下本一家，奚必爾我分。", "獨憐去天遠，緩急呼不聞。", "公今從此升，於國擬世臣。", "家有憂民譜，切磋及茲辰。", "直前明分義，却立思本根。", "豈但無怨公，此志長光新。", "抑使蜀父兄，壽公以峨岷。"]'),
('a35c4561-f6bf-4d9b-bb5d-0cb0d16c5e65','歌詩三十五韻送前知隆慶任侯赴召','魏了翁','宋','宋诗','song-poetry','','[]','向來虎豹蹲天關，啄噉人命無敢干。',280,'全唐诗/poet.song.190000.json','["向來虎豹蹲天關，啄噉人命無敢干。", "任侯干時外小官，有筆如刀剚權姦。", "權姦未夷骨先寒，有開天誅亂旋刊。", "寘我宗社于山安，忽焉倚伏不可摶。", "天心克復理好還，是時增秩綸言頒。", "扶聳義烈增壯顔，邇來十載國步艱。", "思以吉士儀清班，侯今以選賜之環。", "進退語默人所瞯，侯以時考以事觀。", "慶元眎今奚易難，浮驂妄轍紛多端。", "大車檻檻長自閒，中原胡塵暗河山。", "行人載書墨未乾，深仁大信而敢奸。", "彼民玄黄走壺簞，我復翦刈如草菅。", "惟皇上帝憫人寰，嗚呼言之鼻辛酸。", "侯兮去去心體胖，允矣直道非俗觀。", "士所欠者非朝冠，要令反覆耐久看。", "前陳亟與攄肺肝，且使志士興長嘆。", "讙言此士嘗譏韓，始終激烈心如丹，寘名大小任公間。"]'),
('e764089a-b5a1-48e4-aeb2-7251fa1c0f3a','領客君子軒木芙蓉盛開分韻得紅字','魏了翁','宋','宋诗','song-poetry','','[]','天公富萬有，盈宇何充充。',120,'全唐诗/poet.song.190000.json','["天公富萬有，盈宇何充充。", "秋風一摇落，所得緣手空。", "忽於臞悴中，覩此寒露叢。", "天然真富貴，送盡人間窮。", "雅傳與騷經，凡卉亦見容。", "胡爲抱昭質，一盼獨未蒙。", "或訝木末褰，或比水間紅。", "至近前上處，至明日方中。", "碩人亦俁俁，於此猶不逢。", "莫我知矣夫，佇立看秋風。"]'),
('84affd8b-5a64-43b9-80d6-155395333383','重九後三日後圃黄華盛開坐客有論近世菊品日繁未經前人賦詠惟明道嘗賦桃花菊外此無聞焉因相與第其品之稍顯者各賦一品某探題得桃花菊','魏了翁','宋','宋诗','song-poetry','','[]','南陽有佳人，被服長脩姱。',132,'全唐诗/poet.song.190000.json','["南陽有佳人，被服長脩姱。", "黄中粲有章，秀外青無華。", "朝飲晉柴桑，夕餐楚長沙。", "惟與高人處，恥作流俗夸。", "玄都有俗士，品格固爾差。", "遺之以潘沐，强欲相塗搽。", "南陽笑謝遣，於此我何加。", "遊女蕩春風，漁人眩紅霞。", "爾比予於是，豈欲相疵瑕。", "卿自用卿法，吾亦愛吾家。", "寄聲謝程子，爲我刪此花。"]'),
('806862b4-e5e7-4dee-bbae-3e0d1094aefe','次韻薛祕書見遺玉臂格謝書則堂扁額','魏了翁','宋','宋诗','song-poetry','','[]','人心之精微，未動孰爲判。',168,'全唐诗/poet.song.190000.json','["人心之精微，未動孰爲判。", "邪正介然形，君子小人斷。", "熙熙大雅歌，洋洋關雎亂。", "或覘時安樂，或識世屯難。", "是惟言出口，矧復書脫腕。", "至著恢人文，至微極幽贊。", "或者藏其心，外飾徒璀璨。", "誰知敬肆間，德之所聚散。", "卓哉符溪老，吾道資禦捍。", "萬殊錯揉中，獨識一理貫。", "反躬事省察，憤世興寤嘆。", "揭堂闡斯則，絕識陋秦漢。", "於余或有所，相謂畫可玩。", "無物報瓊瑶，作詩附筆諫。"]'),
('75ce8545-1ab4-44a9-ade9-8a7005023262','飛雪亭','魏了翁','宋','宋诗','song-poetry','','[]','自荆入蜀路險絕，墨猿聲中膽欲折。',152,'全唐诗/poet.song.190000.json','["自荆入蜀路險絕，墨猿聲中膽欲折。", "萬州江頭舍舟楫，又趣擔簦窮岌嶪。", "危磴連雲如積鐵，亂石砭足十九跌。", "僕夫流汗馬吐舌，遥望盤龍拄天脅。", "懸瀑落巖噴霏屑，中間有亭曰飛雪。", "十里陰風寒入髮，人言此地無六月。", "火雲射地人不暍，誰知利欲所熏灼。", "以身試險車結轍，伐性焚和火如烈。", "試於此亭解羈紲，呼取大斗酌甘潔，一飲令君消內熱。"]'),
('2c36b528-c56e-4ede-a459-5c3a6d0f6648','張義立得古井以木爲甃命曰亨泉而求余詩','魏了翁','宋','宋诗','song-poetry','','[]','井居安其地，井通會其時。',252,'全唐诗/poet.song.190000.json','["井居安其地，井通會其時。", "地維人所宅，時乃天之爲。", "方冬羣動息，水德潛清漪。", "而隨春木升，環頂沃華滋。", "性情固下潤，功用由上齊。", "孰若無事中，一降一騰之。", "是理契天運，達觀正在茲。", "張侯得木井，妙製參皇犧。", "其間相生意，似非俗人知。", "堙廢幾何年，而獨與侯期。", "書來屬共賦，此理難下詞。", "但於井之象，發我深沈思。", "且如初升五，泰通人所資。", "乃於巽入坎，中含兌承離。", "通塞靡自遂，睽遇若有司。", "坎惟生於一，孚實以爲基。", "世途自亨否，我德無成虧。", "屬侯善疏瀹，毋俾纖塵緇。", "不食吾不即，食之吾不私。", "小大隨所汲，辯義而審施。", "客來問出處，爲誦亨泉詩。"]'),
('f9b7cbd0-2f82-4718-acb9-a539e48a2f81','重陽分韻得放字','魏了翁','宋','宋诗','song-poetry','','[]','層雲生夕霏，寒雨濕青嶂。',72,'全唐诗/poet.song.190000.json','["層雲生夕霏，寒雨濕青嶂。", "平生愛九九，誰謂不可仗。", "盈盈黄鞠華，采采鬰金鬯。", "點檢襟袖間，清芬固無恙。", "門前秋陰陰，席上春盎盎。", "惟餘憂時心，忽忽未肯放。"]'),
('1c0e3817-8a97-4834-afdf-f17e309a997b','補和李季允去秋所寄凌霄觀詩','魏了翁','宋','宋诗','song-poetry','','[]','天高山圍坐，露下月滿樓。',288,'全唐诗/poet.song.190000.json','["天高山圍坐，露下月滿樓。", "其間倚闌人，古今入雙眸。", "戒哉後時懊，迨此先民憂。", "匪緣冀求魚，懼易或喪牛。", "瞬息起萬夫，朝暮食千頭。", "金湯蔽遮地，我豈爲一州。", "餘力事層觀，翬飛半空浮。", "簾開六合曉，杯納萬頃秋。", "燈火背城市，煙霖俯林洲。", "遐睎到冥鴻，吟思追馴鷗。", "寄聲鶴山我，奪目珊瑚鈎。", "因思去年夏，狂魂晝羣遊。", "婪酣飽溪壑，磊砢豐渠酋。", "諸公正錯愕，如築于道謀。", "微君且柔之，尚保國邑不。", "岌嶪變怗妥，嚬呻起懽謳。", "宜恢奇傑觀，快此夷懌酬。", "獨憂解成緩，萬古同一流。", "君毋觀上遊，觀上增嘆愁。", "南有壺聚𣟄，西有耕耡耰。", "北有不庭方，東有不寧侯。", "君看此風景，便謂無事休。", "天心果何如，年運不我留。", "相期懋明德，事業貫顯幽。"]'),
('439629c6-e45c-42ba-b442-80a09d0b491e','汪漕使即梅圃作浮月亭追和古詩余亦補和','魏了翁','宋','宋诗','song-poetry','','[]','一元播羣卉，其氣清以馥。',108,'全唐诗/poet.song.190000.json','["一元播羣卉，其氣清以馥。", "詩人競稱許，胡然於梅獨。", "黄宮播雷鼗，玉管動葭轂。", "惟梅命於陽，清豔照樸蔌。", "正冬白堆牆，初夏黄遶屋。", "純乾稟自高，奚止香百斛。", "又從晏陰後，仍作來年復。", "番君爲築亭，揮弄月盈掬。", "可敬不可玩，醉語懼三瀆。"]'),
('8b78d955-6e25-4d05-b4e8-bd22c065b225','約客十有二人汎舟東山分韻得大字','魏了翁','宋','宋诗','song-poetry','','[]','樂莫樂良朋，同胞瀛海內。',132,'全唐诗/poet.song.190000.json','["樂莫樂良朋，同胞瀛海內。", "矧復聚此州，此樂無乃太。", "晨策披曾巔，夕篙汎晴瀨。", "羲和鑒余衷，爲我祛宿靄。", "空碧墮清鏡，帝青倚高蓋。", "明矑照鷗心，遐思絕鵬背。", "信知好乾坤，不出天地外。", "人生兩儀間，豁豁如許大。", "萬古同一流，誰能與心會。", "丁寧黄頭郎，爲我勉乘載。", "直下涪武江，合處看重兌。"]'),
('cc6da01d-b483-4484-b39f-30759a6d38ff','次韻西叔兄日食地震詩','魏了翁','宋','宋诗','song-poetry','','[]','正月太陽食，六月陰萋萋。',216,'全唐诗/poet.song.190000.json','["正月太陽食，六月陰萋萋。", "利沔階成間，桑土爲塗泥。", "破山覆橋閣，灌城壞河堤。", "蜀地五六震，積潦傷農畦。", "梓州暑尤異，我興看朝隮。", "出逢七十翁，履敝衣無綈。", "前行爲余言，老夫齒含齯。", "閲事亦已多，近聞何乖睽。", "去年大官括隠戶，父詈子詛妻悲啼。", "大官深居那得聞，小吏鼻息干雲蜺。", "今年得少休，北風苦凄凄。", "番軍襲江淮，將士驚噬臍。", "四方靡所寄，容身僅坤倪。", "災異又如此，寧保梁益西。", "太守聞此言，惕如履征鼙。", "又見廣文詩，口呿心沈迷。", "力能得爲僅千里，滔滔四海皆餘黎。"]'),
('6b225717-f977-4506-8181-3baab5213018','約書院諸友過石洞津檢校隄役','魏了翁','宋','宋诗','song-poetry','','[]','天闊山頭頭，江空石齒齒。',168,'全唐诗/poet.song.190000.json','["天闊山頭頭，江空石齒齒。", "清霜肅宇宙，物物露根柢。", "是開明年春，萬彙從此始。", "人事胡不然，臨流方識水。", "斷岸百尺懸，赤子命如寄。", "示人亦真切，猶作秦越眎。", "我憂不能釋，人謂我俗吏。", "吏安能俗人，亦人自俗爾。", "神天及遊衍，忠信在參倚。", "是間炯然存，精粗莫非事。", "况逢道義友，眷眷不余棄。", "至理互相發，俗氛安能滓。", "夜寒人欲歸，漁火颭清泚。", "照我方寸心，悠悠發長喟。"]'),
('6a26043a-4083-461e-97e0-6771ad471ac7','至後再見大雪楊尚書約登天開圖畫閣分韻得平字','魏了翁','宋','宋诗','song-poetry','','[]','天公閔赤子，踊爲營杯羹。',132,'全唐诗/poet.song.190000.json','["天公閔赤子，踊爲營杯羹。", "寸白未云厭，賜以一尺平。", "微陽動黄宮，萬寶隨孳萌。", "蝗妖坐遠屏，癘鬼亦就烹。", "東鄰文昌伯，志氣爲我傾。", "携朋樂時豐，舉酒澆空明。", "忻忻各有適，耿耿未忘情。", "不知宇宙內，肯爾同陰晴。", "前時聞帝輦，隨雪登山亭。", "亭高一流盻，淮楚接神京。", "新甿正露立，舊戍方長征。"]'),
('b9f6d439-54ae-407f-94bb-d64b54442782','送劉寺丞赴浙西提舉分韻得霄字鹽官縣以海漂蕩命劉措置','魏了翁','宋','宋诗','song-poetry','','[]','君王位三極，五氣咸宣昭。',120,'全唐诗/poet.song.190000.json','["君王位三極，五氣咸宣昭。", "有一弗余若，引咎自己招。", "如何圻甸閒，靈胥敢爲妖。", "毋謂一指搐，能使身無聊。", "是用選膚使，汝往鋤其驕。", "將指得若人，譴異不足銷。", "水生乎天一，陽實爲根苗。", "疏通乃循軌，壅塞逾驚漂。", "是理與政通，更當省厥徭。", "績成報天子，鳴珮行青霄。"]'),
('33f8c080-e299-420b-9c88-5f86f6f3b8e7','閣學袁侍郎以朝鯉豢龍兩圖見寄索和 朝鯉','魏了翁','宋','宋诗','song-poetry','','[]','物生宇宙間，巨細統有宗。',168,'全唐诗/poet.song.190000.json','["物生宇宙間，巨細統有宗。", "鱗蟲三百餘，厥長稱維龍。", "滃霧彌六合，神淵閟千重。", "維時赤鯉公，坐制纖鱗窮。", "纖鱗何足言，什百來追蹤。", "亦有橫江鱗，望洋喪其雄。", "于于圉圉然，等辨殊卑崇。", "一鱖掉頭去，恝然若將終。", "三公不易介，誰謂惠不恭。", "魯生陋漢儀，商皓嬰秦鋒。", "行吾之所安，匪以驚愚庸。", "又如秦漢後，俗學千載同。", "卓哉無極論，上配禹孟功。", "吾言聊自警，毋誚惟少通。"]'),
('cbbbf103-8803-4ff2-b270-bd39c10df9a2','閣學袁侍郎以朝鯉豢龍兩圖見寄索和 豢龍','魏了翁','宋','宋诗','song-poetry','','[]','乾坤包萬有，納納百囊罟。',216,'全唐诗/poet.song.190000.json','["乾坤包萬有，納納百囊罟。", "人位乎兩間，利與害爲禦。", "一氣貫四時，五風偕十雨。", "神龍以爲畜，擾御不予侮。", "河有背負圖，庭無漦流女。", "義理之不明，人情自疑沮。", "範圍吾職分，往往若違拒。", "同室操戈鋋，一身隔肺腑。", "帝王豢龍意，棄置那復取。", "四靈非不靈，有不得其所。", "生息之相吹，古今鎮如許。", "古人體天意，萬物我其主。", "蟲莫知於龍，拊循如士伍。", "今何故無人，亦足驗胸府。", "聲和鳳來儀，心平轡如組。", "矧伊人中瑞，治亂係嘿語。", "欲入而閉門，誰出不由戶。", "茲事闕人心，作詩附農圃。"]'),
('9d82e551-f86f-4730-b664-868d69ec0f35','送袁都官知徽州','魏了翁','宋','宋诗','song-poetry','','[]','英英蓬省郎，表表秋官屬。',192,'全唐诗/poet.song.190000.json','["英英蓬省郎，表表秋官屬。", "劍佩行青霄，揚且鬢雙綠。", "掉頭不肯住，去作新安牧。", "班班萊氏衣，粲粲學子服。", "歸來拜郎罷，堂前問凉燠。", "新從天上來，猶带書傳馥。", "問汝得人誰，袖有兩圖軸。", "驪龍挾風雨，閃電注兩目。", "甲纍獨何術，能使同豭鶩。", "三十六脩鱗，羣鯫蕩相逐。", "亦有曳其輪，中行而獨復。", "君家名父子，厥理探已熟。", "人生宇宙間，亦在適所欲。", "義精無非事，慮澹不翅足。", "願明消息幾，頤神以養福。", "遲子寬我憂，書來寄陸續。"]'),
('4994e6f4-e173-44de-9abd-344c6393c007','送侯成甫歸蜀','魏了翁','宋','宋诗','song-poetry','','[]','鴈聲砧杵霜滿洲，高桅大舶行清秋。',64,'全唐诗/poet.song.190000.json','["鴈聲砧杵霜滿洲，高桅大舶行清秋。", "長安白日誤雙鬢，故國青山明兩眸。", "前宵大江半歸壑，來歲候蟲已坏宅。", "無蹤天馬常往還，不信人間有終屈。"]'),
('e8f596c8-ab83-4d38-9210-1fad83b6383d','送楊尚書知瀘州','魏了翁','宋','宋诗','song-poetry','','[]','斷鴈懷歸蘆葉秋，離鸞感照菱花羞。',174,'全唐诗/poet.song.190000.json','["斷鴈懷歸蘆葉秋，離鸞感照菱花羞。", "五更呼兒拭殘淚，淹速有命吾歸休。", "殿頭三拜疏，去意浩莫收。", "內前宣辭賜顔色，外間祖帳如雲稠。", "往年長安道，笑談取公侯。", "白璧抵山車斷流，黄金牣屋花滿樓。", "萬釘圍腰笏頭带，廷紳嘖嘖懸兩眸。", "吁嗟此何物，白盡人間頭。", "二十年重來，見此勇退楊瀘州。", "平生志氣未肯傾，卷懷歸洗岷峨愁。", "我往送之門，感事增百憂。", "怱怱別公上車去，怕鬼見笑君奚留。"]'),
('aa57c201-3717-4c5a-ab99-7813001c95c1','送鄭侍郎四川制置分韻得蓋字','魏了翁','宋','宋诗','song-poetry','','[]','恭惟皇上心，納納天同大。',228,'全唐诗/poet.song.190000.json','["恭惟皇上心，納納天同大。", "明命輟禁游，往撫蜀彫瘵。", "蜀山在何許，斜陽點鴉背。", "家住扶桑東復東，却望斜陽鐵山外。", "金頭奴子扼熙秦，銀州兵馬衝蘭會。", "使我六年望烽火，征人穿空枕戈祋。", "使我千里致鐘石，居人轑釜泣粗糲。", "縣官無蓄租，百姓無藏蓋。", "上有蒼蒼之高天，卒然叫呼不可待。", "閫外萬戚休，只以一身佩。", "我於公行無所贈，筮言得咸爲艮兌。", "艮山本中虛，兌澤乃上溉。", "獨於九四論心體，而以朋思爲障礙。", "願公書此象，長於卧興對。", "蜀道青天蜀平地，君侯一心即難易。", "思耕亭前先鄭碑，更看他年後鄭記。"]'),
('cd4a0845-4fb3-4ee4-af1f-6dd9e71c2281','大理曾少卿欲見余近作錄數篇寄之以詩爲謝且云連日瘡瘍作讀余文而愈因次其韻','魏了翁','宋','宋诗','song-poetry','','[]','西風蕭蕭吹鬢急，獨立長空倚天壁。',128,'全唐诗/poet.song.190000.json','["西風蕭蕭吹鬢急，獨立長空倚天壁。", "俯看滄海環九州，仰視青雲行白日。", "夜歸蟋蟀鳴秋床，觸處萬寶西風香。", "而余生世竟何事，孔翠茲影蜉蝣裳。", "冥心宴坐自探測，善利幾微如白黑。", "江西夫子最知心，欲往從之后土濕。", "忽來詩句懸清風，拱揖孔孟麾瘠癰。", "便思載酒巾車童，一夜壯氣干星虹。"]'),
('9c45ff44-2776-41e4-adf7-f34d2a5aaecc','送任大卿知漢州張少卿知眉州','魏了翁','宋','宋诗','song-poetry','','[]','冬卿懷紱行清秋，又送兩卿歸作州。',192,'全唐诗/poet.song.190000.json','["冬卿懷紱行清秋，又送兩卿歸作州。", "寄聲三州之父老，從今安用思故侯。", "朝廷擇守重於昔，親擢名卿畀華職。", "兩卿更是敭歷深，元把麾來復麾出。", "雙騎紫馬去朝天，羈金絡月凌虹煙。", "逡巡似惜錦障泥，急流欲渡不肯前。", "好官豈爲多榮祿，兩卿之歸得吾欲。", "昨夜流星聲撼屋，光芒照人不成宿。", "起看北斗行雲端，驅策四運無停鞭。", "旁穿上透多風寒，九州霜露方漫漫。", "人間分位各有制，行得一分一分是。", "兩卿去矣吾亦歸，多爲天公憐赤子。"]'),
('cb825b9a-9e08-4630-94fd-2af67ab03434','十二月二十日領客登介亭分韻得梅字','魏了翁','宋','宋诗','song-poetry','','[]','晨鑣載賓從，披霧陟崔嵬。',120,'全唐诗/poet.song.190000.json','["晨鑣載賓從，披霧陟崔嵬。", "宇宙歛盈握，江湖大容杯。", "孱顔石丈人，玉立山之隈。", "山前大第宅，馬頭漲黄埃。", "獨此抱昭質，蕭然侶寒梅。", "有客以問余，豫爲地爲雷。", "雷出地爲奮，何取於石哉。", "人以動爲境，沄沄不知回。", "而能介然存，神氣斯有開。", "相對得深省，欲歸重徘徊。"]'),
('27932f14-2b7d-4d26-b639-d8b7962ea814','四月二十日領客尋龍井前盟以雨陰晴未定不果往買舟下西湖步至玉泉觀魚分韻得東字','魏了翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','前期戒賓從，再候蘇長公。',120,'全唐诗/poet.song.190000.json','["前期戒賓從，再候蘇長公。", "晨炊馬亦秣，宿載車既董。", "飛廉何方來，橫出雲半空。", "便將龍井泉，換却西湖風。", "公非閟清境，乃似開其逢。", "煙柳夾大隄，拳荷點清穹。", "水涵亂雲白，露濕殘照紅。", "不是我輩人，此味誰與同。", "神閒等喧寂，意適無西東。", "觀魚滋有發，歸騎春風中。"]'),
('3fdc1887-c45d-41f5-b823-6f17aaa6df57','六月十四日後殿侍立新永康太守成嘉甫朝辭奏事詞氣懇惻上爲嘉納嘗隨筆紀其事今鄉人祖帳分韻得西字遂書以贈行','魏了翁','宋','宋诗','song-poetry','','[]','嚴精伐鼓趨晨雞，龍媒戒仗喑無嘶。',320,'全唐诗/poet.song.190000.json','["嚴精伐鼓趨晨雞，龍媒戒仗喑無嘶。", "宰臣奏事左墄降，史臣曳履東階躋。", "永康太守臣申之，上殿音吐干虹蜺。", "曰臣前領大農簿，試郡得請今當西。", "韃人求通反其使，金人匿壯招吾携。", "勿言殘金繼前好，將貳韃靼摇青齊。", "時將有反事有間，翫歲愒日憂噬臍。", "皇帝瞿然曰是是，伸頤頷首天聽低。", "貼黄更請磔叛將，褒恤死事不可稽。", "陛下亦聞西事否，昔號險阻今多蹊。", "散關皂郊已平地，白環黄牛猶潰隄。", "分臺列閫越秦視，體統渙散人情睽。", "上云私意誤大事，諄諄切切重提撕。", "申之又言故臣丙，昔嘗有德于坤倪。", "上顧指臣曰安丙，申之頓首如含悽。", "紛紛交情異生死，獨此推本祛羣迷。", "臣時張拱立帝傍，螭頭恨無千赫蹏。", "爲王留行力不足，戴目處此羞梁鵜。", "宮無小大莫非事，勇爲天子綏羣黎。", "天如有意聽臣歸，問天重乞青玻瓈。"]'),
('3d9756e0-96ad-474a-b0f6-8770506fb260','楊仲博生日','魏了翁','宋','宋诗','song-poetry','','[]','金街隆隆曉鐘動，倚馬禁門續殘夢。',212,'全唐诗/poet.song.190000.json','["金街隆隆曉鐘動，倚馬禁門續殘夢。", "夢驚風雨摇江霏，恍如秋浦哦詩時。", "覺來絲絲理前緒，猶記平塍蟹魚句。", "是日江風吹倒山，船頭白浪高黏天。", "兩家兒女攬衣出，草草杯盤作生日。", "自從襆被趨帝京，二年不見波濤驚。", "不知風色今安否，但見朝朝侍明主。", "銀鞍白馬上晴空，鳴鞘戒仗天無風。", "朝回爲君慶初度，才上心來到秋浦。", "君今去作什邡侯，歸興如山不可留。", "只虞江上風色惡，不似帝城鎮懽樂。", "高樓大第插雲霓，煙花眩眼明春暉。", "吾儕且可飲，勿問尚書期。", "爲我歌，毋庸歸。"]'),
('ff7106c3-0308-4777-8fcb-91d727553198','送杜兵侍以華文待制知遂寧府','魏了翁','宋','宋诗','song-poetry','','[]','敝貂衝寒馬聲濕，餘杭門外送歸客。',208,'全唐诗/poet.song.190000.json','["敝貂衝寒馬聲濕，餘杭門外送歸客。", "去年曾送六朱幡，今年又送四千石。", "更有三令相後先，采不盈筐去如織。", "濛濛風雪人氣薄，漠漠煙塵劍花蝕。", "獨立長空倚天壁，幾度乞歸歸未得。", "貳卿犖犖天與姿，不肯隨俗相脂韋。", "聲名早落虞舜聰，霞裾雲佩明春暉。", "虞舜已死不復返，雲埋蒼梧天地悲。", "萬物興歇各有期，人生出處寧無時。", "攬裾結佩下霄漢，苟得吾志官無卑。", "史臣昨侍玉皇案，愛民一語何孜孜。", "願公領此深長思，民力竭矣誰其知。", "更須同志共此事，則公且去吾亦歸。"]'),
('7ba99a82-1e3c-4b7c-a254-f5b13b7ab6ca','送楊仲博歸蜀','魏了翁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江頭送客雪初晴，木葉脫盡山空明。',160,'全唐诗/poet.song.190000.json','["江頭送客雪初晴，木葉脫盡山空明。", "天高地迥著行客，昂昂野鶴相似清。", "曉空霜唳三兩聲，扶木枝上陽烏驚。", "豈無枯蚓若殘粒，寧肯俛首雞鶩爭。", "伊人伊人此爲客，不是伊人招不得。", "固有比隣不往來，那能萬里相追逐。", "瀘涪江上初戒舟，荆江夏簟赤壁秋。", "長江鏡滑無纖滓，致君肝鬲爾許侔。", "竟成何事客先發，贏得滿頭樁歲月。", "丈夫身在復何憂，莫作無相見期別。"]'),
('6692df8f-3160-40a8-9a48-5388e390ebc2','送黄宜州之郡','魏了翁','宋','宋诗','song-poetry','','[]','皇帝親政之初旬，史臣了翁侍嚴宸。',224,'全唐诗/poet.song.190000.json','["皇帝親政之初旬，史臣了翁侍嚴宸。", "宜州太守當就國，袖出諫疏前開陳。", "炎荒僻在飛燕外，陛下一眎同吾仁。", "毋云指搐非害事，往往四體爲不信。", "臣請選侯如中州，更飭膚使時咨詢。", "但令正身以率下，炎荒雖遠畿甸均。", "皇帝顧謂汝可往，布宣德意安吾民。", "黄君下殿再拜謝，盡以聖訓關史臣。", "史臣拜手筆之冊，以君所聞還贈君。", "維今貪競習成俗，公私已屈憂方新。", "紀綱法令不敢知，恃以立國維蒼旻。", "蒼旻茫茫不可問，人情忻戚天笑顰。", "願君體此深長思，便以聖訓書諸紳。", "心誠求之莫非事，子苟不欲民無貧。"]'),
('968a5f6c-215d-4c79-93af-ec94d2d2093c','送秦秘監以顯謨知潼川','魏了翁','宋','宋诗','song-poetry','','[]','杜侯歸未幾，又送秦侯歸。',180,'全唐诗/poet.song.190000.json','["杜侯歸未幾，又送秦侯歸。", "錦衣赫相望，里閈生光輝。", "僅存二三士，去意不可羈。", "王張屢乞身，余亦五請祠。", "豈不明主戀，去就各有宜。", "昔歲語杜侯，志得官無卑。", "近忽省前誤，熱突無寒煤。", "君門天九重，赤子命一絲。", "詩書謾脹腹，字字不適時。", "俯瞰大江流，仰看蒼雲移。", "悠悠未有屆，蹙蹙安所馳。", "昊天豈民憎，翻覆不可期。", "願隨力所逮，必以誠求之。", "求之有弗得，况忍相瘠肥。", "臨分重回首，吾匪懷吾私。"]'),
('3d7238cf-94e5-4c6c-b5f9-ce8e2cae7186','送張匠監以秘閣知贛州','魏了翁','宋','宋诗','song-poetry','','[]','西南間氣忠獻公，一生心事天與通。',256,'全唐诗/poet.song.190000.json','["西南間氣忠獻公，一生心事天與通。", "才高志廣無處著，獨倚衡疑望關洛。", "九州風露方漫漫，卷回殘夢歸餘干。", "惟將一念遺孫子，長與世間立人紀。", "宣公端明今在無，我生不識慚非夫。", "寧知中歲遇行甫，歷歷典刑猶父祖。", "試從微處覘經綸，中邊玉潔無纖塵。", "大河滔滔恣羣飲，逡巡獨惜障泥錦。", "曉庭戒仗喑無聲，掣纓振鬣時時鳴。", "京師邸吏自相語，張公立朝我良苦。", "不知書疏何所言，每一論奏人爭傳。", "好名之人能遜國，而於豆羹見詞色。", "反覆耐看不可瑕，此事無素能然邪。", "我從同朝一千日，見公造次皆是物。", "寄聲爲賀贛州民，朝廷爲汝輟爭臣。", "却須更問蕭太傅，中朝外郡誰當慮。"]'),
('46abccbb-b79b-4bb4-9868-9343d39efc20','約漕使泛舟東郊坐客十人分韻得江字','魏了翁','宋','宋诗','song-poetry','','[]','微雨爽晴昊，柔風渙清瀧。',120,'全唐诗/poet.song.190000.json','["微雨爽晴昊，柔風渙清瀧。", "空明山四坐，宇靜天八窗。", "筮言得幽真，此意誰與雙。", "使家我風調，賓友俱同腔。", "高談颭清鏡，勝韻眠空缸。", "東西南北人，偶此同一邦。", "坐數雲皛皛，起看水淙淙。", "古今聚散地，浩浩如此江。", "餘霞照寶瑟，明夜欺銀釭。", "維舟未肯鼓，歸夢驚逢逢。"]'),
('1a4b9c1a-e52a-453f-acab-1386d8fd8347','肩吾摘傍梅讀易之句以名吾亭且爲詩以發之用韻答賦','魏了翁','宋','宋诗','song-poetry','','[]','三時收功還朔易，百川歛盈歸海斥。',192,'全唐诗/poet.song.190000.json','["三時收功還朔易，百川歛盈歸海斥。", "誰將蒼龍挂秋漢，宇宙中間卷無迹。", "人情易感變中化，達者常觀消處息。", "向來未識梅花時，繞谿問訊巡簷索。", "絕憐玉雪倚橫參，又愛青黄弄煙日。", "中年易裏逢梅生，便向根心見華實。", "候蟲奮地桃李妍，野火燒原葭菼茁。", "方從陽壯爭門出，直待陰窮排闥入。", "隨時作計何大癡，爭似此君藏用密。", "人官天地命萬物，二實五殊根則一。", "囿形闢闔渾不知，却把真誠作空寂。", "亭前擬繪九老圖，付與人間子雲識。"]'),
('a16e3cbb-550d-49d4-a497-b35efe17c69e','次韻永平令江叔文鶴山書院落成詩','魏了翁','宋','宋诗','song-poetry','','[]','天運驅人人不覺，古道違時時不學。',384,'全唐诗/poet.song.190000.json','["天運驅人人不覺，古道違時時不學。", "王相隨脛回荆山，昭質依然未經琢。", "因思胥靡逢殷宗，精神動悟聲氣從。", "礪舟霖雨到梅糵，變化氣質天同功。", "朝歌屠叟無與語，一日投綸見明主。", "大車檻檻行周道，輪輻中規箱中矩。", "人生天地同一原，自誠爲聖明爲賢。", "地殊世遠猶合節，矧此同宇相周旋。", "自從澆風散遺直，世不乏材無匠石。", "未能登車習射御，人人自視郵無恤。", "出門浪戰觸與蠻，半生少得須臾間。", "不爲夷甫辱汝水，即似介甫逋鍾山。", "古人灑掃先庭戶，豈問他人莫余顧。", "只憂原頭欠渟滀，才見天根便呈露。", "人言陰濁勝陽清，陽一陰二分三亭。", "誰知陽德本無間，根心枝葉長相親。", "君臣大分雖有止，終不能忘乃天理。", "世無我知將自知，不待雷風問諸史。", "投沙屈賈占所歸，九州博大歸何之。", "雖云忠憤語傷激，律以洙泗猶津迷。", "前村虎嘯晚風起，跕鳶酸嘶雁將子。", "君恩未報臣憂深，暇把壺頭較鄉里。", "江公勸我姑少安，新詩肉好如璧環。", "敢輸憂誠謝慶語，仍戒牘史毋抄傳。"]'),
('fd5d0270-ea2e-40a2-8a72-be17822f9a36','生朝李肩吾貽詩次韻爲謝','魏了翁','宋','宋诗','song-poetry','','[]','肩吾作詩慶五十，矜我顛躋授之縶。',128,'全唐诗/poet.song.190000.json','["肩吾作詩慶五十，矜我顛躋授之縶。", "因思五十義最精，造化機緘斯出入。", "君看五位相生成，前盪後摩如授揖。", "至於五衍宜有窮，澤火趨新承井汲。", "作聖工夫方自茲，爲人生活知非急。", "昔人於此嘆始衰，血氣雖衰義逾集。", "蹇余不學晚知非，方把斯心驗存蟄。", "獨嗟道遠莫致之，願與始終謀不及。"]'),
('08becb1a-40a7-4cfe-a488-7dae654d1667','次韻李肩吾讀易亭山茶梅','魏了翁','宋','宋诗','song-poetry','','[]','梅華鶴羽白，茶華鶴頭紅。',96,'全唐诗/poet.song.190000.json','["梅華鶴羽白，茶華鶴頭紅。", "拱揖鶴山翁，始授宗人同。", "山間兩賓主，窮極造化功。", "易終得未濟，曹末觀豳風。", "或嗟生處遠，不近扶木東。", "誰知天然貴，正在阿堵中。", "喧寂四時耳，寒至窒斯穹。", "冷眼看千古，聲色沈英熊。"]'),
('fbc3cfda-b991-4056-b02d-0cb7e74dc632','再賦','魏了翁','宋','宋诗','song-poetry','','[]','淘金亂川綠，發䓞燒山紅。',96,'全唐诗/poet.song.190000.json','["淘金亂川綠，發䓞燒山紅。", "自爲天一隅，奚翅地十同。", "米賤衣弗費，四民罕全功。", "功夫到華卉，未至澆淳風。", "老梅委林莽，洛珮遺丁東。", "茶華新移根，脫命斤斧中。", "焉知賁然者，秋毫皆蒼穹。", "觀物弗之察，吾欲問黄熊。"]'),
('0ad201f8-f972-428d-8aef-cf2114c643b2','鶴山書院前爲荷塘三即其小嶼築亭久矣春後八日始榜曰夫容州','魏了翁','宋','宋诗','song-poetry','','[]','嚴風吹衣落南土，手批{兒吾}猱藉封虎。',163,'全唐诗/poet.song.190000.json','["嚴風吹衣落南土，手批{兒吾}猱藉封虎。", "緣山跨谷三里城，架竹編茆百家聚。", "天公似爲羈人謀，閉藏佳境城東陬。", "介然用之便成圃，下眎更得夫容州。", "水間木末高下照，名字既同形亦肖。", "自從羸豕伏羣龍，紅白相輝轉明耀。", "人憐風雪拘系之，委棄衰草蟠寒泥。", "誰知烱烱含內美，正於槁瘁生光輝。", "大書三字爲吹送，喚起渠陽百年夢。", "却疑二華癡絕人，身既隠矣名焉用。"]'),
('6680900f-4899-4d2a-813f-5fee9d07e094','再韻','魏了翁','宋','宋诗','song-poetry','','[]','文華滅質甚塵土，物欲戕生劇豺虎。',160,'全唐诗/poet.song.190000.json','["文華滅質甚塵土，物欲戕生劇豺虎。", "三年挂舌坐林臯，日月往來雲散聚。", "夫容自與詩腸謀，雖無顔色媚涂陬。", "夢隨春草撩客兒，手抉雲錦分潮州。", "平生耻作山雞照，對此忘其爲不肖。", "爲華破戒哦七字，殆似五噫發梁耀。", "李君不爲揜覆之，喚取奚錦披封泥。", "繅車引出萬絲緒，衣被山谷春無輝。", "山中華木迭賓送，人把榮枯同幻夢。", "卧看夫容生未生，滿目天機供日用。"]'),
('18f75cdd-24fc-4246-a14e-7a81d8077136','通道朱宰求時齋字李肩吾賦詩次韻','魏了翁','宋','宋诗','song-poetry','','[]','朱君問時齋，爲誦羲文書。',72,'全唐诗/poet.song.190000.json','["朱君問時齋，爲誦羲文書。", "夬終伏剝果，乾始函坤輿。", "坎離互藏宅，遇復更踦閭。", "物理消處息，人謀密中疏。", "即茲貫千古，何所非廣居。", "是以無妄時，不耕穫菑畬。"]'),
('196d1282-0908-4edc-a844-2dc25c38f1a8','撫州崇仁縣玉清觀道士黄石老工古篆以李公父書來問字','魏了翁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','聖學不嗣千餘年，併與小學遺其傳。',304,'全唐诗/poet.song.190000.json','["聖學不嗣千餘年，併與小學遺其傳。", "其間明道寧乏賢，謂書小伎姑舍旃。", "十字九舛不可鎸，楮生墨墨色有冤。", "動以經史爲執言，豈知魏晉幾變遷。", "况今經字宗開元，請觀未有韻書前。", "訓纂字林形相沿，形聲迭推義乃全。", "韻書既作人趨便，未能書法窮根原。", "但以聲韻求諸篇，形存聲亡韻亦牽。", "叔重少溫工磨研，二徐鄭郭相後先。", "書法頼此差綿延，許李焉得無謬愆。", "楚金分韻猶拘攣，若更舍此徇俗妍。", "不學操縵求安弦，玉清道士來臨川。", "用意周鼓兼泰山，携書過我渠江邊。", "試令立柱與畫捲，椳闑畿礎杗桷椽。", "已能諧世而取憐，猶欲度外求方圜。", "眉山夫子思涌泉，相與共講扶其偏。", "道士稇載明當還，更以一語申卷卷。", "能於此處知其端，事事物物誰非天。", "九章八卦莫不然，一毫人力無加焉。"]'),
('6ae60761-eb8e-4fd5-bb43-46805f7a5b3c','題尹商卿自信齋','魏了翁','宋','宋诗','song-poetry','','[]','虛靈一寸心，至遠而至近。',96,'全唐诗/poet.song.190000.json','["虛靈一寸心，至遠而至近。", "真能位天地，信可爲堯舜。", "不以利欲熏，則爲習俗焮。", "怗怗弄文墨，若若誇綬印。", "聖賢豈我輩，位育非吾分。", "亦有識其然，責泉於九仞。", "人言力不足，我謂知不盡。", "商卿聞吾言，其信其不信。"]'),
('c537d596-c1e2-46df-84ca-a8f9e4203c8b','兄子高赴廷對','魏了翁','宋','宋诗','song-poetry','','[]','九十九峰矗天起，家在前峰夕陽裏。',218,'全唐诗/poet.song.190000.json','["九十九峰矗天起，家在前峰夕陽裏。", "蠻徭虎豹斷行人，小市寒城浄如水。", "驩傳有客闖然來，㨫衣視之吾兄子。", "云從諸侯貢，往備天子使。", "來時吾父爲我言，女之靖州問安否。", "靖州苦好脩，女從得師友。", "世方白首聲利場，父詔子承乃如此。", "柳陰花影春風香，喜極無言澹相對。", "家學既爾殊，天資亦云美。", "自菴寂寥無可贈，贈以菴中一箇自。", "吾聞古之人，仕學皆爲己。", "上不可欺其君，下不忍虐其類。", "此豈有爲然，凡以自靖耳。", "我之行止命於天，上下四方難豫擬。", "旦將自靖獻于君，無限功夫歸語爾。"]'),
('c825b298-95e8-49fc-83fd-09b7483cd132','丁大監文伯得余近作讀之疾愈以詩見貽','魏了翁','宋','宋诗','song-poetry','','[]','黔巫之南谿水茲，山粗石惡不可治。',192,'全唐诗/poet.song.190000.json','["黔巫之南谿水茲，山粗石惡不可治。", "崇寧邊臣務廣地，山刊石斷林木斯。", "其間掌許號爲郡，如以土偶安須眉。", "中州人物猶此任，纍臣舍是夫何詞。", "况於風氣少疵癘，且幸習俗無澆漓。", "飽餐賤米溫舊讀，書味雋永忘其疲。", "坐看歲龍度丑戌，幾見秋月弦虛危。", "都梁有吏雲端來，持書火急如符移。", "美人家在九芙蓉，門牆突兀那可窺。", "聯緘累牘夢邪非，一年兩度劃見之。", "我詩但能愈君疾，君解與世醫狂癡。", "乖逢休戚信有命，嘆上不使非知醫。"]'),
('aeaa470a-5b27-4eb7-b123-0dccd590dc68','先立春一日電雷雪交作程叔運賦詩次韻','魏了翁','宋','宋诗','song-poetry','','[]','自從日馭行牽牛，四十五日爲春朝。',208,'全唐诗/poet.song.190000.json','["自從日馭行牽牛，四十五日爲春朝。", "誰驅阿香送劈歷，更遣玉女來姑瑶。", "從來雷雪不兩立，有如臯禹於驩苗。", "闖然方駕朝正月，是反常性皆爲妖。", "陽孳於子達於寅，蟄蟲欲動寒魚跳。", "蒼龍久移舊歲次，朱鳥亦向新年杓。", "如何陽伏不能出，陰氣所沴如沃焦。", "相摩爲電搏爲震，始初隠隠如迢遥。", "剨然一聲到匕箸，驚魂忽忽不可招。", "須臾爲雹又爲雪，寒威挾勝尤宣驕。", "春秋已事且云遠，紹興狄難幾難調。", "乃今此異已累歲，卧制四海由衾裯。", "徒令志士歌且謠，無人采寄觀風軺。"]'),
('92bd6f69-6851-434e-9d77-f810bf813480','朝字韻詩諸丈倡酬未已再次韻','魏了翁','宋','宋诗','song-poetry','','[]','風挾重陰牛戴牛，電雷雹雪來終朝。',208,'全唐诗/poet.song.190000.json','["風挾重陰牛戴牛，電雷雹雪來終朝。", "詩人隠憂寓酬倡，清輝錯落欺琨瑶。", "似驚一日四變異，須省二氣同根苗。", "非陰能勝陽不競，非物能眚人先妖。", "炎精未振剛受畜，睢水晝遁成皋跳。", "一從憤悱剛浸長，斡握地軸旋天杓。", "山中不知此何時，祇睹此象心爲焦。", "累臣九死何足恤，頑雲蒼慘天關遥。", "澤中但知賦鴻鴈，天上無復歌祈招。", "醡頭新酒空似清，牆根新薺花如驕。", "便思傾罍芼鮮鯽，不妄爲取琴徽調。", "江張程子同一醉，芳草爲藉天爲裯。", "干戈滿地不忍見，恐調老弱征商軺。"]'),
('6ace3d9b-051c-4a0a-b280-cf57a29918e9','送程叔運高不妄西歸','魏了翁','宋','宋诗','song-poetry','','[]','平生爲人謀，必以正學進。',240,'全唐诗/poet.song.190000.json','["平生爲人謀，必以正學進。", "必以直道行，聞者或相靳。", "子以正教我，而子坐排擯。", "跕鳶伴羈酸，再見渠陽閏。", "吾心固曉然，其柰無以訓。", "紹定二年夏，臨軒策羣俊。", "似聞甲乙選，參錯吐忠藎。", "其間親與友，斯得及叔運。", "俱負康時略，耻爲諧俗韻。", "後先來過我，雙璧墮清峻。", "從容扣所言，何以承大問。", "聽之不盡篇，胠口復縮頸。", "予方以是黜，子乃以是奮。", "靳者姑勿道，而予益自信。", "人能位天地，人可爲堯舜。", "氣合如塗塗，道同如印印。", "勿憂人不知，長恐己難盡。", "春情撩客夢，歸思不可忍。", "各趨青油幕，新發蒼梧軔。", "正學予所知，申言以爲賮。"]'),
('d4e1ddeb-76a9-47bf-a3ec-d7c59f0d21a5','湖北提刑林寺丞赴召以書索詩','魏了翁','宋','宋诗','song-poetry','','[]','鏦金伐鼓催行舟，攔街祖帳雲如稠。',312,'全唐诗/poet.song.190000.json','["鏦金伐鼓催行舟，攔街祖帳雲如稠。", "祥刑使者入奏事，詔書趣發不可留。", "居人爭門挽衣住，行人十步九回顧。", "公言爲汝五年留，便是數旬終一去。", "居人向前爲公語，情知不是留公處。", "一春風雨寒凄凄，牛羊滿地鴻酸嘶。", "乾坤爾闊無處著，惟有此地恬不知。", "桑麻雞犬桃谿曲，身住主家數椽屋。", "卧聽前江風雨聲，自嗟身是如天福。", "公今歸去作大官，連雲廣厦千萬間。", "我時豈不被公賜，天高卒卒難爲攀。", "吾儕小人腹，不憚再公祝。", "公今攬轡行原隰，澤地相臨看不足。", "明朝歸坐京師宅，深院重門壅休戚。", "願公莫爲一身惜，須念同胞頭戢戢。", "春風湔淚情轉惻，道旁過者聲唶唶。", "我時困卧五谿東，十日八九陰濛濛。", "有來道前事，耳目爲惺愡。", "更將百壺扶醉膽，喜餘鼻息陵煙虹。", "欲輸一言不能措，以公所聞還贈公。"]'),
('8d808d97-a866-4429-aba4-98ea81cf472f','中秋無月分韻得狂字','魏了翁','宋','宋诗','song-poetry','','[]','金低辟老火，月琯行仲商。',84,'全唐诗/poet.song.190000.json','["金低辟老火，月琯行仲商。", "是爲陰之中，正與日相望。", "浮雲橫相掩，人謂妬且狂。", "彼雲初無心，此月亦何傷。", "水月本同體，其中根於陽。", "炯炯含內景，隨時發輝光。", "天機之淺者，爲人作閒忙。"]'),
('e15622cc-5bc1-4b31-88d0-9fac3f81ac9b','九日分韻得寒字','魏了翁','宋','宋诗','song-poetry','','[]','奇月必用重，誰與開其端。',96,'全唐诗/poet.song.190000.json','["奇月必用重，誰與開其端。", "貴陽而賤陰，於此亦可觀。", "况於五陰後，蒼龍挂高寒。", "林疏山骨瘦，宇靜天容寬。", "砉然遇九九，黄菊紛闌斑。", "且開五言城，聊寄一夕懽。", "凄其義熙後，甚矣天寶間。", "陶社千古心，知者良獨難。"]'),
('88ce7cc2-aea7-4e12-b635-ca6e612dacea','送吳門葉元老歸浮光','魏了翁','宋','宋诗','song-poetry','','[]','龍標之南路窮絕，峩峩羣峰倚天脅。',160,'全唐诗/poet.song.190000.json','["龍標之南路窮絕，峩峩羣峰倚天脅。", "頑雲壓谿鳶跕翅，很石橫空馬溝血。", "葉君尺箠度崔嵬，朱霞白鶴雲端來。", "蠻邦自昔少此客，問此胡爲乎來哉。", "曉窗共話羲文易，千古聖賢心歷歷。", "有時舊習未全忘，閒倚銀河弄詩筆。", "銀河化作霜霰飛，蒼龍移入天之西。", "彭城風雨撩客夢，君起謂我吾其歸。", "牛羊凍卧鴻酸嘶，九州博大君安之。", "人生行止各有時，願崇明德慰遠思。"]'),
('1220b746-6a2d-460a-9188-2ec52cbb0da2','題東甌王友直尚友堂','魏了翁','宋','宋诗','song-poetry','','[]','士恨生世晚，不爲三代民。',204,'全唐诗/poet.song.190000.json','["士恨生世晚，不爲三代民。", "誰知伊傅至孔孟，亦學古道嗤時人。", "豈惟三代時，堯舜萬古師。", "猶云若稽古，不知古爲誰。", "氣數有詘信，義理無終窮。", "雖居堯舜地，常有一簣功。", "嗟哉秦漢後，去聖益以久。", "縱有間代英，僅爲時儒首。", "况於隨世就功名，甚者諧俗攫寵榮。", "此於聖門直蛙蠛，已謂斯世無與朋。", "多知正多懼，不知轉矜負。", "亦云知矣恐未然，須驗此心之權度。", "有師舜文學周孔，有擬管樂明申韓。", "亦有是商鞅，亦有趨異端。", "若言氣合即爲善，是中更要分明看。"]'),
('068a341a-50e0-495d-a783-c9aee83ef83e','贈造琴道士劉發雲劉亦解致雷','魏了翁','宋','宋诗','song-poetry','','[]','劉師携琴來，自言有術驅雷霆。',90,'全唐诗/poet.song.190000.json','["劉師携琴來，自言有術驅雷霆。", "聞之囅然笑，人心未動誰爲聲。", "陽居陰位陽行逆，日循陽度日數贏。", "必嘗凝聚乃奮擊，不有降施誰升騰。", "劉師携琴來，爲我鼓，一再行。", "若知雷霆起處起，便知音是人心生。"]'),
('4a9e26d9-83e3-4a64-bb42-0233c9c7a75f','洪士龍以洪舜俞考功所作竹洲精舍記見問','魏了翁','宋','宋诗','song-poetry','','[]','考功記竹洲，所業在淇奧。',156,'全唐诗/poet.song.190000.json','["考功記竹洲，所業在淇奧。", "謂學與自脩，此何取於竹。", "士龍來諗余，試請言其目。", "天地之大端，松篁受命獨。", "陰陽迭盈虛，表裏更見伏。", "厥象肖坎離，厥理寓姤復。", "榆杏柞與檀，四序所宜木。", "此獨貫四時，不受寒暑觸。", "示人人不察，但識霜更綠。", "誰能淇之上，興寓三反覆。", "形氣互發明，顯微相貫屬。", "嗟余粗知方，倚枝看不足。", "安得兩洪君，試同煙露宿。"]'),
('26e0b19f-8f34-45cb-b8e5-6e3e2e24caa8','張永平鎋作亭于渠河之右予請名以觀而通守江君塤賦古詩二十有二韻以落之用韻和答','魏了翁','宋','宋诗','song-poetry','','[]','渠河有水清且漣，弄丸之暇遊其間。',352,'全唐诗/poet.song.190000.json','["渠河有水清且漣，弄丸之暇遊其間。", "風輕沙暖鷗忘機，天開日烜魚逃筌。", "山中不知歲月改，春洲六度聽綿蠻。", "聞人昔遊不到此，岸容山色如有冤。", "永平教孚訟亦簡，爲我卜築河之干。", "臨流興懷嘆不足，因思孔聖感逝川。", "豈無日景自北起，亦有天運從東旋。", "風霆流形草木賁，星辰垂象郊原寬。", "乾坤坎離更見伏，春秋代謝相回環。", "雖將此理醒羣聵，更向川上觀微瀾。", "存神過化義亹亹，行著習察心閒閒。", "子思淵淵達天德，子車混混窮原泉。", "東流不休發呂氏，潺湲遠望悲屈原。", "聖賢分量已差等，後來承誤滋可嘆。", "或嗟年衰勸努力，或謂時逝宜遊盤。", "須看龍見水歸壑，又識雨降雲蒸山。", "陰陽翕闢本無閒，俗儒但作死生觀。", "河南挺生二程子，指示道體鎸冥頑。", "人能於此發深省，致知格物茲其端。", "神徂聖伏二千載，是心長與江瀰漫。", "文通爲揮五色筆，大篇長句垂不刊。", "春風沂泗儼在此，居人莫作渠陽看。"]'),
('39f9e06f-fc27-45e3-8701-0407d1d514e5','次韻廬陵劉時見懷','魏了翁','宋','宋诗','song-poetry','','[]','夬終伏剝果，畜極逢天衢。',96,'全唐诗/poet.song.190000.json','["夬終伏剝果，畜極逢天衢。", "否泰反其類，艮止與動俱。", "此道固曉然，人情不同趨。", "兩目自安障，狂童爲子都。", "羈金絡明月，騏驥旆疲駑。", "靜觀若有得，知非降才殊。", "但傷此道違，獨行嘗寡徒。", "解后知我者，聊足以自娛。"]'),
('ea2bca27-0189-480a-8965-3b9d1fe40b48','贈曾醫','魏了翁','宋','宋诗','song-poetry','','[]','太極分陰陽，物物具兩儀。',144,'全唐诗/poet.song.190000.json','["太極分陰陽，物物具兩儀。", "乾坤互南北，坎離迭東西。", "四時有見伏，晝夜有盪推。", "夫人遷於物，由之而不知。", "六淫一爲沴，大命醫所司。", "或當暑而裘，或御冬而絺。", "或學製而傷，或助苗而萎。", "其間號爲儒，亦以身嘗醫。", "江西有曾君，解后荆江湄。", "暇日與之語，切磋及幽微。", "榜人趣行邁，欲別不忍離。", "乃書所素講，爲詩以贈之。"]'),
('821bd4ae-a254-4db0-8bd6-50b64855e5a5','四川茶馬牛寶章修揚子墨池以書索題詠','魏了翁','宋','宋诗','song-poetry','','[]','子雲一去千餘載，惟有成都墨池在。',384,'全唐诗/poet.song.190000.json','["子雲一去千餘載，惟有成都墨池在。", "草玄此地是邪非，玄文今在人誰知。", "雖逃劉歆醤瓿阸，鼠壤蛛窠蠹魚宅。", "豈無學者工探求，不譏僣聖幾贅肬。", "自從馬邵造玄域，晁氏譜之張氏翼。", "亦云察矣人猶疑，試爲諸老申其辭。", "易書廣大包天地，辭變象占都一致。", "世儒造入各不同，有一于此均爲功。", "况於易玄互相發，不同之同真善學。", "曆家中首先黄鍾，雖以坤復爲初終。", "紀日天正始牛宿，又以日星分左右。", "起從冬至易玄均，玄意欲取臣承君。", "易書八八而用七，玄文九九而存一。", "易分六位中二五，臣志上通君下取。", "玄以一五而爲中，君道君尊臣代終。", "玄文主日易主歲，易書爲經玄爲緯。", "謂玄於易地承天，就中邵子尤知玄。", "或云玄準卦氣圖，是圖疑亦非聖書。", "豈知中復與咸遇，乃是陰陽自然數。", "或云玄倣太初歷，黄鍾之分八十一。", "豈知虛三與虛九，其數雖同其法否。", "或云玄象宗渾天，渾天方象包於圓。", "豈知兼用蓋天說，蓋以輿地承純乾。", "易雖無玄不爲闕，易更得玄滋有發。"]'),
('4bf48f2f-5bf3-44fa-a614-fb77842c8bb1','和靖州判官陳子從山水圖十韻 彭蠡歸舟','魏了翁','宋','宋诗','song-poetry','','[]','外物羈縶人，無退亦無遂。',24,'全唐诗/poet.song.190000.json','["外物羈縶人，無退亦無遂。", "愧彼自由身，朝發夕予至。"]'),
('6f61ee6b-e859-42f9-b378-6aaafec5c1b2','和靖州判官陳子從山水圖十韻 山堂曠望','魏了翁','宋','宋诗','song-poetry','','[]','山堂有何觀，四時互興歇。',24,'全唐诗/poet.song.190000.json','["山堂有何觀，四時互興歇。", "萬物隨天根，東生復西滅。"]'),
('65fa55c4-66d7-4333-97d4-180229d9d4e6','和靖州判官陳子從山水圖十韻 重湖汎月','魏了翁','宋','宋诗','song-poetry','','[]','水月皆內景，入秋倍清暉。',24,'全唐诗/poet.song.190000.json','["水月皆內景，入秋倍清暉。", "世無善觀者，滔滔吾誰歸。"]'),
('23510af2-7781-4836-a0e5-0797f857998b','和靖州判官陳子從山水圖十韻 星灣晚酌','魏了翁','宋','宋诗','song-poetry','','[]','士非耕釣者，而從蓑笠翁。',24,'全唐诗/poet.song.190000.json','["士非耕釣者，而從蓑笠翁。", "人生貴適志，莘渭亦時中。"]'),
('58f64e6a-ee49-4990-a618-614e4098a40d','和靖州判官陳子從山水圖十韻 雨後觀瀑','魏了翁','宋','宋诗','song-poetry','','[]','澤氣蒸前山，起自膚寸微。',24,'全唐诗/poet.song.190000.json','["澤氣蒸前山，起自膚寸微。", "競看千丈瀑，不悟片雲飛。"]'),
('a60f7827-5ffd-49fc-91fe-5c676a00aee8','和靖州判官陳子從山水圖十韻 松徑晚步','魏了翁','宋','宋诗','song-poetry','','[]','松柏不受彫，此亦易知耳。',24,'全唐诗/poet.song.190000.json','["松柏不受彫，此亦易知耳。", "須看竹有筠，與松相表裏。"]'),
('e1f52430-3780-4952-b0d0-5503ca23ffe4','和靖州判官陳子從山水圖十韻 谿上賦詩','魏了翁','宋','宋诗','song-poetry','','[]','莫作谿流看，天命無窮已。',24,'全唐诗/poet.song.190000.json','["莫作谿流看，天命無窮已。", "詩人若知得，千古可坐致。"]'),
('3b5c0d4e-c0e1-4178-b101-db6d8594200f','和靖州判官陳子從山水圖十韻 林下避暑','魏了翁','宋','宋诗','song-poetry','','[]','散髮避炎暑，炎暑苦相尋。',24,'全唐诗/poet.song.190000.json','["散髮避炎暑，炎暑苦相尋。", "云何對大賓，不見汗沾襟。"]'),
('26e34531-96bd-4883-be07-f9c1686d5482','和靖州判官陳子從山水圖十韻 載酒尋梅','魏了翁','宋','宋诗','song-poetry','','[]','松竹貫寒暑，而梅時往來。',24,'全唐诗/poet.song.190000.json','["松竹貫寒暑，而梅時往來。", "不知姤復意，隨人謾徨徊。"]'),
('b720efe4-ea45-4900-894e-d385aba7e64a','和靖州判官陳子從山水圖十韻 雪中訪友','魏了翁','宋','宋诗','song-poetry','','[]','懷人得清晤，此樂浩無期。',24,'全唐诗/poet.song.190000.json','["懷人得清晤，此樂浩無期。", "剡谿興盡返，未喻伐木詩。"]'),
('1cbe6106-4912-4f3d-ab09-161a5cace699','過屈大夫清烈廟下','魏了翁','宋','宋诗','song-poetry','','[]','鸞皇棲高梧，那能顧鴟梟。',288,'全唐诗/poet.song.190000.json','["鸞皇棲高梧，那能顧鴟梟。", "椒蘭自昭質，不肯化艾蕭。", "人生同一初，氣有善不善。", "一爲君子歸，寧受流俗變。", "云何屈大夫，屬意椒蘭芳。", "蘭皋並椒丘，蘭藉薦椒漿。", "騷中與歌首，蘭必以椒對。", "謂椒其不芳，謂蘭不可佩。", "此言混凡草，臭味自爾殊。", "亡何歲時改，二物亦變初。", "以蘭爲可恃，委美而從俗。", "椒亦佞且慆，干進而務入。", "椒蘭信芳草，氣質自堅好。", "胡爲壞於廷，晚節不可保。", "意者王子蘭，與夫大夫椒。", "始亦稍自異，久之竟蕭條。", "迨其習成性，甘心受蕪穢。", "不肯容一原，寧以宗國斃。", "禹皋於共鯀，旦封與鮮度。", "同根復並生，何嘗改其故。", "原非不知人，觀人亦多塗。", "治朝中可上，亂世賢亦愚。", "况原同姓卿，義有不可去。", "所望於兄弟，謂其猶可據。"]'),
('233db26d-1de1-4712-bea8-6f33e4646cf4','至左綿書懷呈榮州綿州二兄','魏了翁','宋','宋诗','song-poetry','','[]','歲行析木予去國，鶉尾之年纔返室。',319,'全唐诗/poet.song.190000.json','["歲行析木予去國，鶉尾之年纔返室。", "東西南北著此身，水陸二千三百日。", "或云子非善謀身，幸生斯世同斯人。", "胡爲嘐嘐苦自好，輕辭富貴重絕貧。", "五谿之濱有何好，兀坐六年不知老。", "夔門待汝有何惡，要把山林易旌纛。", "予聞其言心自語，吾非斯人而誰與。", "獨嗟行止各有時，龍蟄鴻歸亦其所。", "洋州拔將鳩餘民，仰空待救人不聞。", "黎州邊丁戍內郡，空養赤子防西門。", "綿州近阸劍龍路，列雉驚奔渠不顧。", "敘州平蠻亦良苦，卒以憂勞棄予去。", "見危授命理之常，苟得死所庸何傷。", "所憂人己兩無益，燕蝠晨暝徒皇皇。", "鶴山之顛一畝宮，我名吾亭日願豐。", "只祈天心速悔禍，雨禾雨麥蘇民窮。", "有糧餉士可衛民，有民給耕可供軍。", "民相資護關塞，又須監牧長得人。", "規摹便立久安勢，不作目前苟偷計。", "弟兄歸與里父師，長對春風賦常棣。"]'),
('5b03c1f1-fe75-49da-9f22-9199539e5fec','壽四川制置李侍郎','魏了翁','宋','宋诗','song-poetry','','[]','崧高二王德，豐水數世仁。',192,'全唐诗/poet.song.190000.json','["崧高二王德，豐水數世仁。", "一心千古脈，一氣三才根。", "人言通德門，封培知幾春。", "陵州不盡用，雝國非全神。", "厥美鍾在季，魯殿巋然存。", "誰知中興主，流澤被子孫。", "是用遺一老，爲社稷萬人。", "三朝典刑舊，四海觀聽新。", "自公鎮西南，威聲憺胡虜。", "棄地遄歸疆，餘民亦安土。", "便當度雙劍，建大將旗皷。", "進賢黜不衷，討貳誅失伍。", "增屯御驕卒，募耕實邊圄。", "堂堂當道卧，一勇銷百侮。", "願公排羣議，釋我分外慮。", "上流屹長城，却歸輔明主。"]'),
('792951af-736d-4746-87ff-9189de8be733','送高才卿出守嘉定','魏了翁','宋','宋诗','song-poetry','','[]','十年誰遣不寧侯，麕奔鳥散十七州。',128,'全唐诗/poet.song.190000.json','["十年誰遣不寧侯，麕奔鳥散十七州。", "餘州蹙蹙能幾許，史君今作載酒遊。", "諸公飲儁已濡首，眼前百事不挂口。", "震風凌雨揭却屋，左蟹右杯猶在手。", "史君千騎行清秋，豈爲杯酒饞涎流。", "綢繆牖戶既云晚，夢魂不到花繞樓。", "乖逢聚散古來有，而我此時持此酒。", "河梁竚立不知還，插頷青絲半成叟。"]'),
('7c316de2-f7f4-4f8b-a35a-31acb30fe7f5','次韻蘇和父自郫見寄','魏了翁','宋','宋诗','song-poetry','','[]','敬共事明德，懔如槃水持。',288,'全唐诗/poet.song.190000.json','["敬共事明德，懔如槃水持。", "豈惟將弗勝，抑恐濁且茲。", "結髮齒名官，幾被末俗移。", "學睎遷商博，文慕莊騷爲。", "書不記癡龍，詁不通雌霓。", "恥於市朝撻，甚於溝壑擠。", "大道砥如平，阽身蹈囏危。", "迨其閲世久，始識真聞知。", "天命賁草木，生意長萋萋。", "蕃鮮固云樂，槁瘁安足悲。", "陰陽孰信詘，日月誰盪推。", "乾坤奠中極，雷澤周四陲。", "夫人命於誠，地生而天施。", "五行根五事，位育誰司之。", "嬛浮溺于詞，躁輕亂于儀。", "山雞衒清影，祇以速顛躋。", "况彼膜外榮，皇皇復滋滋。", "此於我何加，寒暑自四時。", "蘇公西南彥，儀鴻漸于逵。", "而我坐遠屏，七年墮蠻夷。", "夢思岷山陽，枯筇伴龐眉。", "人才日零落，憔悴西南維。", "大篇忽開予，炯炯晨星垂。", "公來何勇邁，我往何棲遲。"]'),
('35cccadd-35f1-47fa-b2da-694c00c8de0e','七夕南定樓飲同官','魏了翁','宋','宋诗','song-poetry','','[]','誰將明星貼天宇，州國宮垣象官府。',160,'全唐诗/poet.song.190000.json','["誰將明星貼天宇，州國宮垣象官府。", "更將四七隨天旋，常以昏中殷四序。", "迢迢河漢衝秋旻，前有蒼龍履玄武。", "牽牛正向西南來，左右兩旗北河鼓。", "鼓星之側爲天桴，鼓上三星爲織女。", "何年人號天女孫，便把牛郎擬夫婦。", "不知此是天關梁，河漢之津有常度。", "晦明伏見莫非教，肯爲文人給嘲侮。", "班曹庾謝猶讆言，世上兒曹更堪數。", "臨風三誦大東詩，須信詞章有今古。"]'),
('7d5e87a2-40e7-4628-a809-8b82c1644b5e','中秋領客','魏了翁','宋','宋诗','song-poetry','','[]','秋中無常期，月望無常歷。',168,'全唐诗/poet.song.190000.json','["秋中無常期，月望無常歷。", "况於月之房，歲十有二集。", "云胡三五夜，賞翫著今昔。", "我觀魏晉前，未有娛此夕。", "豈由夕月禮，承訛變淫液。", "天行至東北，陽升乃朝日。", "日月向南來，三務趨朔易。", "則於陰之反，順時報陰魄。", "古人敬天運，隨處察消息。", "俗學踵謬迷，更以儗科級。", "廣寒八萬戶，桂樹五千尺。", "文人同一辭，祇以驚俗客。", "墨墨數百年，月如有冤色。", "爲作反騷吟，聊以補載籍。"]'),
('ad2f60bf-80b3-4551-b81e-0479b47764c3','重陽領客以老杜舊日重陽日詩分韻凡賓主十八人得不字','魏了翁','宋','宋诗','song-poetry','','[]','天根歛秋陽，雨畢水歸藪。',120,'全唐诗/poet.song.190000.json','["天根歛秋陽，雨畢水歸藪。", "胡爲爽常度，白晝變昏黝。", "農功將納場，餘秉尚棲畝。", "昨朝告方社，卷去日中蔀。", "羲和鞭六龍，爲我作重九。", "雲頑驅復來，渾未識臧不。", "終然劃劙之，金鎞發矇瞍。", "所忻陽德競，吾豈爲杯酒。", "悠然見南山，陶公意何厚。", "况今祠太宮，羣公正奔走。"]'),
('ab0d0349-805f-4926-9cc9-c4860fb73e24','游北巖之疇昔夢作二詩覺而僅記一聯云鬢髮絲絲半已華猶將文字少年誇明日爲客誦之客十三人請以是爲韻予分鬢字','魏了翁','宋','宋诗','song-poetry','','[]','時事彫壯心，詞華誤雙鬢。',132,'全唐诗/poet.song.190000.json','["時事彫壯心，詞華誤雙鬢。", "昨夢忽儆予，覺來起孤憤。", "五官予所司，此夢乃予訓。", "是心協蓍龜，是氣通祲煇。", "形骸且不察，理性抑難盡。", "曉筇度雲壑，疏林露鷹隼。", "暮歸踏江聲，寒流燭蛟蜃。", "惕思懷襄日，氣勢如項陳。", "天根忽晨見，卷去不盈瞬。", "猶然玩文采，吾果不知分。", "飲儁習未忘，依前賦分韻。"]'),
('99d2012c-2ab3-460d-b0cd-de754a983320','上巳領客','魏了翁','宋','宋诗','song-poetry','','[]','流觴元巳奚所因，更指三日爲良辰。',208,'全唐诗/poet.song.190000.json','["流觴元巳奚所因，更指三日爲良辰。", "山陰坐上皆豪逸，長安水邊多麗人。", "臨流有許豪與麗，元無一個能知津。", "韓嬰何憑指溱洧，束晳胡據誣周秦。", "千年混混同一波，競言此日天氣新。", "其間號曰該洽者，或言鳦降祠高辛。", "春分以後弗無子，往往援引詩生民。", "說雖有稽義猶鑿，况復除日經無文。", "予嘗妄意巳爲火，季春火見疑乘寅。", "寅居漢津火所畏，故以元巳祓水濱。", "一年奇月必用重，三三欲解陽德屯。", "較之前說已云近，終媿俚俗疵吾醇。", "要須挈我沂泗上，回瓢點瑟看長春。"]'),
('af1a5358-9432-4207-ad2a-fadf08065c28','永嘉林君誼父得英石名其室曰矸齋予易以介室','魏了翁','宋','宋诗','song-poetry','','[]','柳侯謂楚南，多石而少人。',72,'全唐诗/poet.song.190000.json','["柳侯謂楚南，多石而少人。", "至今英道閒，異石何嶙峋。", "乃知五行氣，中土爲秀民。", "降才既匪易，自棄奚不仁。", "伾文一日炎，乃以焚其身。", "林君若知此，是石當書紳。"]'),
('f76b81eb-7680-4e2f-8b8e-aa3e92d4ba4d','羅五星善奕棋干詩','魏了翁','宋','宋诗','song-poetry','','[]','少年不識棋，但見剝剝琢琢更相圍。',204,'全唐诗/poet.song.190000.json','["少年不識棋，但見剝剝琢琢更相圍。", "有人指授予，衝關奪角劫復持。", "少年不識星，但見腷腷膊膊還如棋。", "亦有告予者，縮贏伏見元有期。", "七年五谿讀書暇，時把二事相悅怡。", "久之剨然悟，是閒有數人不知。", "三百六十一棋子，此是乾策藏其奇。", "萬有一千五百二十星，若以三十六乘之。", "乘之既盡除坤策，恰與棋數無參差。", "此理極精密，歸後不復思。", "羅生挾二長，過我瀘之湄。", "恍如著我五谿上，欲與之語無閒時。", "此須靜觀乃有得，而我家住西山西。", "生揣我，何時歸。"]'),
('0011c650-8ee2-4afe-a2e9-ec7dab46f525','七夕有賦','魏了翁','宋','宋诗','song-poetry','','[]','經星不動隨天旋，枉被嘲謔千餘年。',176,'全唐诗/poet.song.190000.json','["經星不動隨天旋，枉被嘲謔千餘年。", "無情文象豈此較，獨嗟陋習輕相沿。", "我嘗作詩觝排之，尚有遺恨汙陳編。", "人於萬物爲至靈，聰明照徹天地先。", "其如形氣之所囿，則以學問開蒙顓。", "不知誰爲乞巧者，乃謂天孫執其權。", "天孫能襄不能報，世閒之拙無加焉。", "癡兒騃女競針縷，高樓大第迷管絃。", "漢魏以來用一律，無人出語扶其顛。", "其間假拙濟巧者，又欲託此文姦言。", "敢因良會追往事，更發此義聲餘冤。"]'),
('4112f392-c4bf-4f3e-bf23-3bb7c686b1bb','黄成之求虛舟詩','魏了翁','宋','宋诗','song-poetry','','[]','黄君求我古誠州，求之不得還西遊。',176,'全唐诗/poet.song.190000.json','["黄君求我古誠州，求之不得還西遊。", "所求易予胡不予，渠家自弄莊生舟。", "莊生傳之賈太傅，便將死生同浮休。", "我家舟子與渠別，中孚之象剛包柔。", "仰山俯澤乘巽木，藏離伏坎含坤牛。", "中間至虛若無物，實理備具非空浮。", "此在太玄首黄宮，其於參同居中洲。", "會通古今貫微顯，上下天地同周流。", "人將百年等浮漚，我以千載爲春秋。", "我言似大而非夸，人人皆有不自求。", "黄君不信謂予赫，我自姬孔君莊周。"]'),
('84ce9577-bfee-43de-bbb7-1b017442aeee','中秋有賦','魏了翁','宋','宋诗','song-poetry','','[]','望舒與日元非敵，震受陽光巽成魄。',144,'全唐诗/poet.song.190000.json','["望舒與日元非敵，震受陽光巽成魄。", "六十四象不言月，三百五篇譏月出。", "古道貴陽不貴陰，賓禮卜晝不卜夕。", "世間賞翫起何年，誤却千年醉狂客。", "不知客有肺腸無，更把荒誣作真實。", "我因時序嘗作詩，洗盡兔窟蟾宮迷。", "今年新作東樓成，胡爲尚此窮攀躋。", "人心和平民氣樂，日月昭明天宇豁。", "須知此事與政通，不是詞人閒賞月。"]'),
('e940a677-d8fb-4b6c-8285-7e01a0bae583','送游吏部赴召','魏了翁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天馬周流不停策，青龍挂空山無色。',350,'全唐诗/poet.song.190000.json','["天馬周流不停策，青龍挂空山無色。", "區中物物見根柢，歲年滔滔逐流水。", "籲天求歸歸未獲，客裏隨人送行客。", "鏦金伐鼓行清秋，江頭組練雲如稠。", "道旁老人相與語，主賓聞之愕相顧。", "或云造闕如登僊，一聲謦咳落九天。", "豈知位高勢逾偪，莫向紫宸庭下立。", "非關噉芻解喑嘿，紫宸地禁鳴不得。", "或云敢言儗鳴鳳，千古高名泰山重。", "豈知說著心骨驚，臣名愈重國愈輕。", "或言古人重晚節，元忠子方費分說。", "豈知晚節不難保，却憂攘臂爲人笑。", "三人所贈不皆然，然則子也今何言。", "元祐中年基紹聖，建中靖國何嘗靖。", "若教此事欠講明，直將兩是爲端平。", "是時臣言便休得，臣不憂身却憂國。", "臣願天意開平治，明良長似改元時。", "夬剛未終戒莧陸，姤陰雖微畏羸躅。", "真教世道端且平，寧使臣無赫赫名。", "三人囅然笑，子之所願吾不到。", "吾言必於身，子言望於人，子意雖厚吾言真。", "低頭謝二老，還以告景仁。"]'),
('c0e03ac8-b927-4f85-a327-a4dfc9ae2dac','奉謝資陽謝純天諸友是日三池周季章馮季修許德開資中支仲壬至謝介卿馮清叔廣漢常光父繼至遂寧楊儀斯期而未至','魏了翁','宋','宋诗','song-poetry','','[]','駕言南東畝，捷出西北隅。',180,'全唐诗/poet.song.190000.json','["駕言南東畝，捷出西北隅。", "資陽有八士，持謁要諸塗。", "須臾平泉道，衣冠被林廬。", "問我來何方，過我不適予。", "吾非煩囂避，樂此簡便趨。", "經行三紀後，舊交半丘墟。", "翁仲草沒膝，兒孫霜滿須。", "其間最所懷，劉公真丈夫。", "許張二良友，直氣橫九區。", "堂堂舍我去，顧景霜月孤。", "寒梧陶令宅，宿草黄公壚。", "我豈無肺腸，拊事成嗟吁。", "待到西州門，不如早回車。", "作詩謝諸友，努力崇遠圖。", "三家令子弟，不諒予心乎。"]'),
('eadd9d4c-2ebd-4d1a-966c-1dc05bb1f835','贈畫工王生','魏了翁','宋','宋诗','song-poetry','','[]','七年謫五谿，二年守三瀘。',84,'全唐诗/poet.song.190000.json','["七年謫五谿，二年守三瀘。", "蠻煙瘴雨中，不改舊時吾。", "此來懶看鏡，謂我衰且癯。", "王生忽肖象，氣貌何丰腴。", "悔不賂王生，圖作一病夫。", "庶幾轉而上，聽我歸林廬。", "及此未衰日，更讀幾年書。"]'),
('9002e430-9b85-4e49-82af-e7acc38528ec','次韻趙制置制勝軒詩','魏了翁','宋','宋诗','song-poetry','','[]','何年誤認貙作熊，力小知薄當戎衝。',192,'全唐诗/poet.song.190000.json','["何年誤認貙作熊，力小知薄當戎衝。", "級夷蕃拔牖戶破，至今風色長如冬。", "去年推轂以授公，單車飛度雙劍峰。", "風稜犖犖膽氣雄，臨淮軍壘足跡重。", "夜起攬衣瞻井絡，鑄鐵不知經幾錯。", "朅來談笑上紋楸，龜頭局中虎口著。", "誰將輿柴誤戰塵，天戈一揮如砥平。", "濯征玁狁威蠻荆，捷書夜上白玉京。", "考成軒戶適茲日，一吐十年胸怫鬰。", "看詩又覺饒餘力，要殄餘憂寬旰食。", "書生喜極還太息，天下憂端尚非一。", "經營分表竟何益，盍護本根保成勣。"]'),
('99b7f13e-49de-4410-90a3-36d24746eba7','端平三年春三月戊午朔天子有詔俾臣了翁以僉書樞密院奏事既上還山之請乃休沐日丁丑與賓佐謁濂溪先生祠賓主凡二十有二謂是不可無紀也遂以明道先生雲淡風輕之詩分韻而賦而詩有二言有四言同一韻者則二客賦之了翁得雲字','魏了翁','宋','宋诗','song-poetry','','[]','書生不知分，奉詔行三軍。',156,'全唐诗/poet.song.190000.json','["書生不知分，奉詔行三軍。", "赤手張空弮，幸脫貔虎羣。", "四海蓮華峰，濂溪漲清芬。", "擬求一勺水，浣我三斗塵。", "翠瀲明夕霏，晴雲盪朝氛。", "重上夫子堂，謦咳如有聞。", "池蓮已濯濯，庭草長忻忻。", "重惟夫子書，千古披昏嚚。", "善惡萌於幾，陰陽互而分。", "一落俗儒喙，嘵嘵齒穿齦。", "流傳豈不廣，世道滋放紛。", "書生屢乞骸，歸耕故山雲。", "願言與同志，相期任斯文。"]'),
('94f3ef98-cc7f-4122-87c9-0c9ea7093ff3','江東漕使兄約遊鍾山分韻得泠字','魏了翁','宋','宋诗','song-poetry','','[]','連年飲建業，寤寐北山靈。',144,'全唐诗/poet.song.190000.json','["連年飲建業，寤寐北山靈。", "三過又不入，風雨盲其程。", "一朝决會期，萬籟不敢聲。", "斷潢捲夕潦，列巘浮帝青。", "因思山中人，昔日相熙寧。", "不知學何事，莽制爲周經。", "羣公咸其輔，不悟宗康成。", "相承至章蔡，九州半羶腥。", "歷年百七十，衆寐未全醒。", "三經猶在校，從祀猶在庭。", "追惟禍之首，千古一涕零。", "大鈞窅難問，山雲水泠泠。"]'),
('5238ec47-0efa-4853-a4b1-d53cca739b33','贈畫工王三錫傳神','魏了翁','宋','宋诗','song-poetry','','[]','氣質紛不齊，四海無似人。',132,'全唐诗/poet.song.190000.json','["氣質紛不齊，四海無似人。", "藉令貌相近，氣有醇不醇。", "善觀人品者，儀觀與機神。", "正邪眸子見，善惡眉間分。", "且如若與虎，二人自非倫。", "而俱類孔子，俗眼何昏昏。", "古人有夢遇，便知爲良臣。", "又能記眉目，曉然得其真。", "此須以神會，難與淺者論。", "王生歸爲我，試語司寇君。", "此理充得去，三代同此民。"]'),
('111e4949-1c88-403f-a11f-dac3b4eff5dc','題溫泉','魏了翁','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山一滴水，雕盡詩人腸。',132,'全唐诗/poet.song.190000.json','["廬山一滴水，雕盡詩人腸。", "道傍有溫泉，恝然如遺忘。", "淺夫既閣筆，知士亦括囊。", "或云匪難知，水火互陰陽。", "水根於天一，至陽所潜藏。", "所以井生熒，亦有泉如湯。", "吾嘗謂或言，子語未精詳。", "水實含內景，火乃無寒光。", "水將而不迎，火迎而不將。", "君看月受日，又驗坤含章。", "吾言與邵語，或可補詩亡。"]'),
('d641e482-58f4-43e9-88f0-1a13b4c21cf4','次程少逸餞楊叔禹教授','魏了翁','宋','宋诗','song-poetry','','[]','載酒時從執戟郎，雅知清望稱鴛行。',64,'全唐诗/poet.song.190000.json','["載酒時從執戟郎，雅知清望稱鴛行。", "肯來芹泮提英裁，要取芳編閲舊香。", "玉倚蒹葭方借潤，珠移甓社陡寒光。", "臨來莫恨車無角，疑睇雲霄紫鳳翔。"]'),
('675918f2-eeb3-4cb7-9c9c-7569f41c8b8b','和史少莊登山韻三首  其一','魏了翁','宋','宋诗','song-poetry','','[]','賸喜向前坡，人情奈怯何。',24,'全唐诗/poet.song.190000.json','["賸喜向前坡，人情奈怯何。", "君今高著步，直與陟嶒峨。"]'),
('6de50376-0e79-40de-8edb-3d7d7dd21795','和史少莊登山韻三首  其二','魏了翁','宋','宋诗','song-poetry','','[]','田間逢醉尉，人道誤誰何。',24,'全唐诗/poet.song.190000.json','["田間逢醉尉，人道誤誰何。", "世路日杲杲，冥行宜見呵。"]'),
('a8547a9b-1a55-4f8e-854a-7c22ea9a92c9','和史少莊登山韻三首  其三','魏了翁','宋','宋诗','song-poetry','','[]','毋謂支山險，此山能幾何。',24,'全唐诗/poet.song.191000.json','["毋謂支山險，此山能幾何。", "崎嶔十年夢，知歷幾蹉跎。"]'),
('7e914265-3207-4efb-bae1-9d6bf1a40a78','和李參政龍鶴菴廬二首  其一','魏了翁','宋','宋诗','song-poetry','','[]','落紙新詩萬口傳，逍遥舊夢記坡僊。',64,'全唐诗/poet.song.191000.json','["落紙新詩萬口傳，逍遥舊夢記坡僊。", "明虹短雨下平楚，老鴈長雲橫半天。", "澗底青松不改色，檻前流水謾安筌。", "寄聲多謝無名子，莫攪詩翁禿鬢眠。"]'),
('8c41a454-0551-493f-b405-9fea976d951b','和李參政龍鶴菴廬二首  其二','魏了翁','宋','宋诗','song-poetry','','[]','古往今來一貉丘，行藏有道坎還流。',64,'全唐诗/poet.song.191000.json','["古往今來一貉丘，行藏有道坎還流。", "鳳凰池上春風夢，龍鶴山頭夜月秋。", "閒曳深衣聊獨樂，有懷連璧賦三游。", "何人得與余心會，野水黏天一片鷗。"]'),
('54d6e165-836e-4515-961c-dc2351eaf2a7','和李校書沐川三絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','靜看青山簇髻鬟，動觀碧水漱潺湲。',32,'全唐诗/poet.song.191000.json','["靜看青山簇髻鬟，動觀碧水漱潺湲。", "若教此景來酆鄗，爭奪應成觸與蠻。"]'),
('6a1a0d98-af14-41e5-850c-4f6668f47d82','和李校書沐川三絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','花時乘傳奈邊心，撩弄新詩逼少陵。',32,'全唐诗/poet.song.191000.json','["花時乘傳奈邊心，撩弄新詩逼少陵。", "詩到湖邊春未老，不禁春思也微吟。"]'),
('692d1712-9890-4c97-a5ff-1488858b78b6','和李校書沐川三絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','玉節行邊春正濃，邊頭壯士簸旗紅。',32,'全唐诗/poet.song.191000.json','["玉節行邊春正濃，邊頭壯士簸旗紅。", "何當平賊携諸吏，徑上高寒翦翦風。"]'),
('805a9038-22c2-4b4d-8619-4af375bcd02d','次韻外舅楊崇慶以詩相招  其一','魏了翁','宋','宋诗','song-poetry','','[]','炎威翕翕正鏖人，惟有西風不世情。',32,'全唐诗/poet.song.191000.json','["炎威翕翕正鏖人，惟有西風不世情。", "困卧小窗倦賓客，吹將好語到巖扃。"]'),
('19f5f3d6-9f06-4c80-bbb4-1d4bbd760820','次韻外舅楊崇慶以詩相招  其二','魏了翁','宋','宋诗','song-poetry','','[]','去年湖上看花時，拍檻呼魚酌酒巵。',32,'全唐诗/poet.song.191000.json','["去年湖上看花時，拍檻呼魚酌酒巵。", "魚計主人已非昔，猶驚故處上鈎遲。"]'),
('da846521-2514-48a8-a2a4-14faf68e86a7','次韻外舅楊崇慶以詩相招  其三','魏了翁','宋','宋诗','song-poetry','','[]','寄語荷郎且緩開，山中衣製要君裁。',32,'全唐诗/poet.song.191000.json','["寄語荷郎且緩開，山中衣製要君裁。", "不隨褦襶觸熱去，待學山陰乘興來。"]'),
('98688f4d-2239-4ee2-a4fb-f9ac10cdf668','李參政見招遊龍鶴山歸途有作  其一','魏了翁','宋','宋诗','song-poetry','','[]','上有高峰樹倚天，下臨深澗水生煙。',64,'全唐诗/poet.song.191000.json','["上有高峰樹倚天，下臨深澗水生煙。", "陶鎔泉石山中相，舒卷雲霞地上僊。", "松色呼兒開後檻，筍輿爲客過前川。", "不因同落天涯久，那得巖扉共此緣。"]'),
('9de28b49-1233-47fa-a30a-1c8fde7b61f4','李參政見招遊龍鶴山歸途有作  其二','魏了翁','宋','宋诗','song-poetry','','[]','亂澗穿雲十里閒，好風吹袂出重山。',64,'全唐诗/poet.song.191000.json','["亂澗穿雲十里閒，好風吹袂出重山。", "潺潺流水半歸壑，唧唧候蟲皆閉關。", "興念歲時驚變態，靜觀物化識回環。", "並溪的皪梅花樹，已带明年春事還。"]'),
('6826c1a4-00f7-4a3a-883a-08eaf469ee26','和范少才詠雪  其一','魏了翁','宋','宋诗','song-poetry','','[]','底處呼滕六，催將歲事闌。',48,'全唐诗/poet.song.191000.json','["底處呼滕六，催將歲事闌。", "窗明朝采爛，枝瘦夜光蟠。", "炫晃山林老，模糊天地寬。", "曉琴絃欲折，難忍溧陽酸。"]'),
('04a5f0c7-202f-4a8b-a298-7a4877435be1','和范少才詠雪  其二','魏了翁','宋','宋诗','song-poetry','','[]','隨踏曉巖去，殿頭金井闌。',48,'全唐诗/poet.song.191000.json','["隨踏曉巖去，殿頭金井闌。", "路門圭璧委，雙闕絳青蟠。", "拜手朝紳肅，憂心旰食寬。", "歲糜今有望，寧復厭葅酸。"]'),
('8d766f96-73a8-4880-be59-f9cbe3b3ba52','和范少才詠雪  其三','魏了翁','宋','宋诗','song-poetry','','[]','寒陰彫草木，枯葉委庭闌。',48,'全唐诗/poet.song.191000.json','["寒陰彫草木，枯葉委庭闌。", "蒼聳孤松秀，青敷萬竹蟠。", "封條纔貼妥，見睍復欹寬。", "但使根長在，毋憂風哭酸。"]'),
('017465e2-1d3c-4bf0-8b5e-68e37d8d782a','恭和聞喜宴賜毛自知以下御製','魏了翁','宋','宋诗','song-poetry','','[]','昭代賓賢禮意誠，鎬京設席藹儒纓。',64,'全唐诗/poet.song.191000.json','["昭代賓賢禮意誠，鎬京設席藹儒纓。", "龍飛十二周星紀，鵬運三千擊水程。", "雲漢成章新寵渥，鈞天張樂播和平。", "微臣置饋申規戒，賢網雖恢用欲精。"]'),
('a4f098eb-a3e7-4b9a-97f6-57b5c276861c','和張大著顛字韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','步弱扛豐分疾顛，不將臭腐易芳鮮。',64,'全唐诗/poet.song.191000.json','["步弱扛豐分疾顛，不將臭腐易芳鮮。", "眼前富貴蟻奔垤，膜外功名鷗避船。", "忠憤無因塵乙夜，隠憂深覺負丁年。", "一窗風雨看書卷，三度京梅雪可憐。"]'),
('b22c8871-7156-4485-8a2b-ba9dd0ece62e','和張大著顛字韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','倀倀趨局曉衣顛，妙語飛來墨已鮮。',64,'全唐诗/poet.song.191000.json','["倀倀趨局曉衣顛，妙語飛來墨已鮮。", "太一藜然分夜隙，蓬萊海闊接風船。", "臨邛詞客雖末至，淮海簽書非少年。", "獨抱區區無我察，聯篇重拜玉人憐。"]'),
('308c3b3c-944d-43f9-8852-645d4d6f37bc','張大著以韓持國綠樽紅妓事再和見戲復次韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','世路羊腸幾覆顛，如君操行雪朝鮮。',64,'全唐诗/poet.song.191000.json','["世路羊腸幾覆顛，如君操行雪朝鮮。", "書胸滿貯宣和庫，學力要裝元祐船。", "賸喜孟龍來並世，肯呼禰鶚與忘年。", "閉門笄珥無膏沐，不作傾城馮小憐。"]'),
('8de89945-1909-4340-9439-91653737fc63','張大著以韓持國綠樽紅妓事再和見戲復次韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','壯心十五亦狂顛，十五年來洗濯鮮。',64,'全唐诗/poet.song.191000.json','["壯心十五亦狂顛，十五年來洗濯鮮。", "負郭元無三畝宅，浮家安有五湖船。", "焚香讀易謝來况，飲綠圍紅回長年。", "不是柳桃曾作惱，安知世味有妍憐。"]'),
('d41f235f-86c6-48b1-8a6b-56d1be4febf3','再和顛字韻時方議開邊','魏了翁','宋','宋诗','song-poetry','','[]','鼎象亨調戒在顛，或捐常饌美時鮮。',64,'全唐诗/poet.song.191000.json','["鼎象亨調戒在顛，或捐常饌美時鮮。", "鷙形不匿麏投麓，劍影虛張蛟繞船。", "壯觀要還全盛日，圖回須似中興年。", "掩關雷雹驚春夢，憂國丹心只自憐。"]'),
('b4084a70-7006-4023-b546-d63cc49eec09','和胡秘書學中釋奠','魏了翁','宋','宋诗','song-poetry','','[]','祠官環邃殿，晰燎嚮晨光。',48,'全唐诗/poet.song.191000.json','["祠官環邃殿，晰燎嚮晨光。", "工有歌咸夏，人無問國庠。", "豆籩陳吉饗，磬管奏和鏘。", "盛事留篇什，賡酬愧不揚。"]'),
('ee8e1694-e6a2-4873-a8eb-6bb454fc78fc','題袁追遠亭  其一','魏了翁','宋','宋诗','song-poetry','','[]','朱棗離離實已稀，白雲閒傍隴頭飛。',64,'全唐诗/poet.song.191000.json','["朱棗離離實已稀，白雲閒傍隴頭飛。", "囝思郎罷那得見，父曰子行胡不歸。", "樹靜風號終莫待，桂芳椿老苦相違。", "舍南舍北尋遺響，衰草寒煙夕照晞。"]'),
('e1dcf2e9-f972-422b-8c8e-6421424f2bc1','題袁追遠亭  其二','魏了翁','宋','宋诗','song-poetry','','[]','寶劍初期多擊鮮，嗟嗟何及淚闌干。',64,'全唐诗/poet.song.191000.json','["寶劍初期多擊鮮，嗟嗟何及淚闌干。", "美官孰與承顔樂，豐祀何如啜菽懽。", "已矣親容生死闊，要知好道始終難。", "共惟出自期無忝，留作松楸久遠看。"]'),
('924610a9-0460-4c41-9795-7d2f8e8c02cf','次韻費同叔解嘲  其一','魏了翁','宋','宋诗','song-poetry','','[]','乞得身來作外臣，沖然肺腑自韶鈞。',64,'全唐诗/poet.song.191000.json','["乞得身來作外臣，沖然肺腑自韶鈞。", "鹹酸獨覺水中味，形影相依鏡裏真。", "入戶方聞夫子樂，近前孰試相君嗔。", "昊天明旦司游衍，環堵嚴於百萬人。"]'),
('71d7e5e2-bdc8-484a-89ef-1b76276964ca','次韻費同叔解嘲  其二','魏了翁','宋','宋诗','song-poetry','','[]','低頭涸轍問波臣，沃以嘉言力萬鈞。',64,'全唐诗/poet.song.191000.json','["低頭涸轍問波臣，沃以嘉言力萬鈞。", "逆耳倒言誠愛助，解嘲謝謗返離真。", "若微君告誰能及，幸不吾欺乃敢嗔。", "彼是紛紛姑勿道，所期終誨作全人。"]'),
('ea6f41d9-d46c-4a16-b18e-dec85bea4d75','次韻□丞兄聞丁卯十一月三日朝報  其一','魏了翁','宋','宋诗','song-poetry','','[]','龍章晨下九重關，帝敕元凶出羽山。',64,'全唐诗/poet.song.191000.json','["龍章晨下九重關，帝敕元凶出羽山。", "揭日行空破昏闇，乘風縱燎絕神姦。", "須看文正昭陵日，孰與忠宣元祐間。", "更願和平培治體，儒臣千歲侍天顔。"]'),
('6f86072c-22d7-4a47-a601-e86764c97557','次韻□丞兄聞丁卯十一月三日朝報  其二','魏了翁','宋','宋诗','song-poetry','','[]','儻來得喪本無關，或爲鴻毛加太山。',64,'全唐诗/poet.song.191000.json','["儻來得喪本無關，或爲鴻毛加太山。", "縱昔尹鼯寧有損，及今投裔枉爲姦。", "公私界分分明甚，狂聖途程念慮間。", "初學粗知真富貴，從今克復願睎顔。"]'),
('5f84ea4b-9dd6-4d60-bbad-78066394725d','次韻虞永康題滄江書院','魏了翁','宋','宋诗','song-poetry','','[]','解后滄江半日閒，一川風物闖柴關。',64,'全唐诗/poet.song.191000.json','["解后滄江半日閒，一川風物闖柴關。", "正從逝處識流水，更向靜時觀遠山。", "有詠皆春誰與點，無時不學子睎顔。", "相逢一笑忘言處，月墮波心不記還。"]'),
('af0cee9a-68e8-4048-90a4-9c3e4fdfc402','次韻虞永康讀易有作','魏了翁','宋','宋诗','song-poetry','','[]','室中萬象本寬閒，門戶何曾頃刻關。',64,'全唐诗/poet.song.191000.json','["室中萬象本寬閒，門戶何曾頃刻關。", "未始有時觀太極，不終止處認兼山。", "人文自昔先犧昊，天賦云誰不孔顔。", "有志未能今得友，從今迷路儻知還。"]'),
('d6bba459-2347-4434-ad45-158744158bc8','再次滄江韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','夏畦初雨桔槹閒，讀易幽人晝掩關。',64,'全唐诗/poet.song.191000.json','["夏畦初雨桔槹閒，讀易幽人晝掩關。", "厚築根基方考室，不辭卷撮要爲山。", "賸栽晚歲松筠友，長伴滄江冰雪顔。", "門外斜陽迷客路，屋中行李去家還。"]'),
('cd55d1d4-302b-44b1-850a-48ed16c116a7','再次滄江韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','野迥江空雲意閒，清風喚客度東關。',64,'全唐诗/poet.song.191000.json','["野迥江空雲意閒，清風喚客度東關。", "摻摻竹柏青垂地，炯炯賓朋玉立山。", "酒爲心知一開口，話逢理到兩舒顔。", "嘯吟風月江頭路，此意羲皇向上還。"]'),
('8f2d19a5-aec3-4f00-b728-0c882dd77e10','次韻范少才在峽中寄李季允  其一','魏了翁','宋','宋诗','song-poetry','','[]','蜀艇雲奔下固陵，一壺浮峽便千金。',64,'全唐诗/poet.song.191000.json','["蜀艇雲奔下固陵，一壺浮峽便千金。", "子來我往才交臂，人涉卬須又苦心。", "北向雖無一矢發，西風不受半塵侵。", "是非得喪今休問，喜見戈槍卧綠沈。"]'),
('07de600e-aa17-4a6c-aec5-0240177e4756','次韻范少才在峽中寄李季允  其二','魏了翁','宋','宋诗','song-poetry','','[]','大明臨照職方州，漢沔江淮澹若油。',64,'全唐诗/poet.song.191000.json','["大明臨照職方州，漢沔江淮澹若油。", "剪薙荆榛開蹕路，護持杞梓聳岑樓。", "朝綱人爲諸公喜，國體誰知志士愁。", "讜議胡公不可作，奉常今說有黄侯。"]'),
('6618c7dc-acb9-4b3e-944a-589d61826f3a','次韻虞永康謝余過滄江','魏了翁','宋','宋诗','song-poetry','','[]','雨餘雲簇數峰奇，公子江頭客款扉。',64,'全唐诗/poet.song.191000.json','["雨餘雲簇數峰奇，公子江頭客款扉。", "白舫青簾亂平渺，黄雞濁酒話清微。", "稻畦千頃睟生色，竹日一川摇靜暉。", "坐久東山初月上，恍疑赤壁舊時磯。"]'),
('38f30473-4348-4400-afb1-7b5a5274fe39','和虞永康梅花十絕句  其一','魏了翁','宋','宋诗','song-poetry','','[]','蓬蒿已逐曉霜眠，玉立孤標漢綺園。',32,'全唐诗/poet.song.191000.json','["蓬蒿已逐曉霜眠，玉立孤標漢綺園。", "月澹風輕雲欲壓，精神千古對羲軒。"]'),
('2ec963b6-dd5e-458a-aadc-7bb9a7493951','和虞永康梅花十絕句  其二','魏了翁','宋','宋诗','song-poetry','','[]','不隨妖豔競花期，葉落惟存老樹枝。',32,'全唐诗/poet.song.191000.json','["不隨妖豔競花期，葉落惟存老樹枝。", "林下水邊時一見，相逢頗恨幾年遲。"]'),
('9d652f7e-bb25-4615-9e63-a67b7b53e664','和虞永康梅花十絕句  其三','魏了翁','宋','宋诗','song-poetry','','[]','天然標韻聳高寒，覿面松筠取友端。',32,'全唐诗/poet.song.191000.json','["天然標韻聳高寒，覿面松筠取友端。", "直截語人人不解，等閒只作好花看。"]'),
('cb366309-d1ac-48f6-a4ba-cd6464c27dc9','和虞永康梅花十絕句  其四','魏了翁','宋','宋诗','song-poetry','','[]','遠山雲抹半橫簪，野色昏明水淺深。',32,'全唐诗/poet.song.191000.json','["遠山雲抹半橫簪，野色昏明水淺深。", "庭外沉沉人不到，凜然玉雪對踈林。"]'),
('462d46e8-1cbf-4e73-bc51-a2a5ebc5e5bb','和虞永康梅花十絕句  其五','魏了翁','宋','宋诗','song-poetry','','[]','輕寒玉蓓試新妝，已識微酸一點黄。',32,'全唐诗/poet.song.191000.json','["輕寒玉蓓試新妝，已識微酸一點黄。", "生意溶溶無間斷，何須聞笛爲沾裳。"]'),
('23946c5a-9f2c-4c84-9de1-2e65119bd205','和虞永康梅花十絕句  其六','魏了翁','宋','宋诗','song-poetry','','[]','重陰浩瀚渺無濱，草木摧殘見本真。',32,'全唐诗/poet.song.191000.json','["重陰浩瀚渺無濱，草木摧殘見本真。", "誰識江南一枝信，明年春事正催人。"]'),
('2a1ed07a-912e-4119-8b13-ae0081a6f58c','和虞永康梅花十絕句  其七','魏了翁','宋','宋诗','song-poetry','','[]','滄江卜室數年間，畚築栽培僅息肩。',32,'全唐诗/poet.song.191000.json','["滄江卜室數年間，畚築栽培僅息肩。", "生色油然已如此，箇中自有不須禪。"]'),
('4b8aa063-de61-4259-9aa2-dd37a093ac5e','和虞永康梅花十絕句  其八','魏了翁','宋','宋诗','song-poetry','','[]','樹花禽語恰逢時，真意相關兩絕奇。',32,'全唐诗/poet.song.191000.json','["樹花禽語恰逢時，真意相關兩絕奇。", "獨坐黄昏先得月，呼僮點筆和梅詩。"]'),
('b71ab7c8-4c80-4c25-b75c-a6efa9a7e078','和虞永康梅花十絕句  其九','魏了翁','宋','宋诗','song-poetry','','[]','幽光冷豔照前坡，花下期君不啻過。',32,'全唐诗/poet.song.191000.json','["幽光冷豔照前坡，花下期君不啻過。", "木落江空歲年晚，此詩朋友望西河。"]'),
('733c8606-f9c0-4ff8-8d0f-66a20bd54b7a','和虞永康梅花十絕句  其一○','魏了翁','宋','宋诗','song-poetry','','[]','世間無物可談空，開落榮枯實理同。',32,'全唐诗/poet.song.191000.json','["世間無物可談空，開落榮枯實理同。", "百樹好花一編易，主人立處儼當中。"]'),
('4abf73a5-8ce4-4818-8d39-12a227eb3d86','安大使生日','魏了翁','宋','宋诗','song-poetry','','[]','恭惟天祐宋，奕葉際明良。',288,'全唐诗/poet.song.191000.json','["恭惟天祐宋，奕葉際明良。", "積德由文武，生賢邁漢唐。", "粵稽資殿老，降自皛山陽。", "崧極申函粹，東維傅啟祥。", "堂堂三代直，赫赫萬夫望。", "清廟圭璋璧，明堂楓柞樟。", "詔成來鳳翥，雲滃際龍驤。", "誰誤玄黄篚，爭馳赤白囊。", "攙槍星有耀，晻曀日無光。", "白晝鳴梟獍，長衢縱虎狼。", "公卿失匕筯，帷幄自金湯。", "昔在齊劉豫，前睎石敬瑭。", "久爲虜臣妾，深入漢封疆。", "誰似機籌妙，曾無矢鏃傷。", "邊城長男女，農畝遂耕桑。", "惠澤孚禽獸，威稜憺犬羊。", "報勳隆爵秩，紀績滿旂常。", "事業侔伊呂，功名陋霍張。", "巖巖千仞壁，納納百川航。", "經國般營室，憂民旅念鄉。", "直方坤立德，中正泰包荒。", "天錫公難老，神扶福孔穰。", "沖襟凝日谷，溫語瀉天潢。", "壽域周三蜀，春祺徧一方。"]'),
('89f08350-f3f1-43ab-9462-515c2426de77','次韻李參政見謝遊龍鶴山詩  其一','魏了翁','宋','宋诗','song-poetry','','[]','北山嘗乞草堂靈，娓娓高談析理精。',64,'全唐诗/poet.song.191000.json','["北山嘗乞草堂靈，娓娓高談析理精。", "潑眼溪光無間斷，入懷月色太鮮明。", "寒毛絡石清可數，暝靄蒸山濃欲傾。", "相對悠然無語處，古今成敗一空枰。"]'),
('9bc7ba62-60fe-4c60-8672-a72b4e36df07','次韻李參政見謝遊龍鶴山詩  其二','魏了翁','宋','宋诗','song-poetry','','[]','有鳥雲飛魚躍淵，聖賢見處自天懸。',64,'全唐诗/poet.song.191000.json','["有鳥雲飛魚躍淵，聖賢見處自天懸。", "流陰卒卒謾空過，斯道寥寥誰適傳。", "人境恰逢如擇地，主賓良晤豈非天。", "二章發我無窮思，不慊遺編對聖賢。"]'),
('7c5ffe3b-1a69-4e4a-b503-aaad7037e6fe','次韻虞永康十月海棠  其一','魏了翁','宋','宋诗','song-poetry','','[]','冷淡庭梅儼玉顔，孤高翠竹聳脩鬟。',32,'全唐诗/poet.song.191000.json','["冷淡庭梅儼玉顔，孤高翠竹聳脩鬟。", "如何富貴天然質，猶欲尋盟二友間。"]'),
('04233821-2c70-4c8a-aa2a-4811dca5a7c6','次韻虞永康十月海棠  其二','魏了翁','宋','宋诗','song-poetry','','[]','春意何曾間四時，芸芸靜處錦成帷。',32,'全唐诗/poet.song.191000.json','["春意何曾間四時，芸芸靜處錦成帷。", "非關造化呈新巧，鈞播無心自不知。"]'),
('b89898ce-c6cf-4146-b482-130981b0276b','李德秀致政以其生日前一日約士友至長慶院訪梅花山茶因以爲壽','魏了翁','宋','宋诗','song-poetry','','[]','流年苦被雪霜催，惟有山中自四時。',64,'全唐诗/poet.song.191000.json','["流年苦被雪霜催，惟有山中自四時。", "寒色憗花妝歲晚，曉陰挾霧放春遲。", "似嫌俗客不同調，留與高人共勝期。", "但願多書沖祐考，與君長伴歲寒枝。"]'),
('e854513d-3fbf-4b6b-9bf2-aca2e0fc587b','李德秀致政即席賦五言十韻用韻答之','魏了翁','宋','宋诗','song-poetry','','[]','冬十有二月，朞三百六旬。',120,'全唐诗/poet.song.191000.json','["冬十有二月，朞三百六旬。", "高懷局宇宙，良會惜參辰。", "乘興訪安道，扣窗呼孔賓。", "襲人薰蕙若，奪目爛犀珍。", "風景乾吟筆，林花眩醉裀。", "溪山逢舊識，水竹樂閒人。", "歲籥逡巡換，春煒次第新。", "撫時嗟易失，涉道渺無因。", "循物探天運，冥心觀我身。", "相期共無斁，不與迹同陳。"]'),
('dc520b1c-79ec-49fb-bb0c-bd11934191a7','次韻黄侍郎滄江海棠六絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','妙處東皇可得知，溶溶生意不停機。',32,'全唐诗/poet.song.191000.json','["妙處東皇可得知，溶溶生意不停機。", "雨寒日暴渾無頼，憑仗陽和爲解圍。"]'),
('6dfccd80-91bc-4c82-9d26-bcdcdaf591de','次韻黄侍郎滄江海棠六絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','沙暖花香弄午晴，苦撩詩思浩難禁。',32,'全唐诗/poet.song.191000.json','["沙暖花香弄午晴，苦撩詩思浩難禁。", "偷閒不辦追年少，只有春風會此心。"]'),
('7228f51a-17f2-421f-91fb-060862582e94','次韻黄侍郎滄江海棠六絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','爲憐一片曉雲紅，未放千絲暮雨濃。',32,'全唐诗/poet.song.191000.json','["爲憐一片曉雲紅，未放千絲暮雨濃。", "調燮陰陽賢岳牧，滿川花意得舂容。"]'),
('43efa235-7785-493f-aa03-a7a63571ebeb','次韻黄侍郎滄江海棠六絕  其四','魏了翁','宋','宋诗','song-poetry','','[]','慣踏郊原浩蕩春，重來春與物俱新。',32,'全唐诗/poet.song.191000.json','["慣踏郊原浩蕩春，重來春與物俱新。", "渠雖自有生生意，把握天機是主人。"]'),
('5d370eac-4838-43d1-9774-e26a35ba37a8','次韻黄侍郎滄江海棠六絕  其五','魏了翁','宋','宋诗','song-poetry','','[]','帝恐嘉花不易成，好風遲日故來承。',32,'全唐诗/poet.song.191000.json','["帝恐嘉花不易成，好風遲日故來承。", "繁紅錯眩漁人眼，不識滄江有武陵。"]'),
('69225664-474b-4e85-9cdf-d4e0f5b9d6ce','次韻黄侍郎滄江海棠六絕  其六','魏了翁','宋','宋诗','song-poetry','','[]','指麾紅紫思無濱，抵當丹青筆有神。',32,'全唐诗/poet.song.191000.json','["指麾紅紫思無濱，抵當丹青筆有神。", "百樹花閒一編易，主人意韻鎮長新。"]'),
('68463f4b-37d7-4390-ac57-ca297da67cae','次韻王茶馬海棠四絕','魏了翁','宋','宋诗','song-poetry','','[]','一春風雨亂書堆，挂口林閒未放開。',32,'全唐诗/poet.song.191000.json','["一春風雨亂書堆，挂口林閒未放開。", "浩蕩和風褰客袂，來看大樹簇池臺。"]'),
('4c0381f3-8ac6-40de-a884-8a822ee025f1','次韻王茶馬海棠四絕 清淑堂海棠','魏了翁','宋','宋诗','song-poetry','','[]','善識花人盡倚闌，不將榮悴等閒看。',32,'全唐诗/poet.song.191000.json','["善識花人盡倚闌，不將榮悴等閒看。", "繁華奪目春如醉，獨肯懷人問考槃。"]'),
('80a77244-72b2-4bff-bc29-f29b402497c7','次韻王茶馬海棠四絕 王氏花屋海棠','魏了翁','宋','宋诗','song-poetry','','[]','宅在道傍如寶坊，一奩明玉颺新妝。',32,'全唐诗/poet.song.191000.json','["宅在道傍如寶坊，一奩明玉颺新妝。", "當年共賞人何在，萬里相思夢寐香。"]'),
('5c449406-b123-4d88-a63f-8448cadd6835','次韻王茶馬海棠四絕 燕王宮','魏了翁','宋','宋诗','song-poetry','','[]','二十四番花信風，川原無處著繁紅。',32,'全唐诗/poet.song.191000.json','["二十四番花信風，川原無處著繁紅。", "逢人謾說燕宮舊，廢址荒營暝靄空。"]'),
('d41498b6-897c-4eec-9b2c-936c8a2b4274','次韻黄侍郎生子','魏了翁','宋','宋诗','song-poetry','','[]','未用占呱泣，懸知頭角踈。',48,'全唐诗/poet.song.191000.json','["未用占呱泣，懸知頭角踈。", "芝蘭庭殖殖，梧竹厦渠渠。", "虎子驅黄犢，禽兒駕小車。", "迺翁何以遺，行李五車書。"]'),
('62d579a8-6c26-4c2e-a47f-99b2e60fbbd2','題梓潼廟','魏了翁','宋','宋诗','song-poetry','','[]','士生一世果何事，道喪千年不得傳。',64,'全唐诗/poet.song.191000.json','["士生一世果何事，道喪千年不得傳。", "富貴熏天隨手盡，詞華蓋世爲人妍。", "直將了了聖賢質，只辦區區文字緣。", "神爲斯人扶正學，試教夢者一醒然。"]'),
('853b1fd6-e9d6-4e32-af2a-f0115b75c657','題上亭驛','魏了翁','宋','宋诗','song-poetry','','[]','紅錦䙀盛河北賊，紫金盞酌壽王姬。',32,'全唐诗/poet.song.191000.json','["紅錦䙀盛河北賊，紫金盞酌壽王姬。", "弄成晚歲琅當曲，正是三郎快活時。"]'),
('a5b3b2a2-aedb-4b97-b546-f6205fceca19','九月八日類試別所與同事飲而痁作','魏了翁','宋','宋诗','song-poetry','','[]','彼顓氏子太鴟張，藥裹丹瓢爲汝忙。',64,'全唐诗/poet.song.191000.json','["彼顓氏子太鴟張，藥裹丹瓢爲汝忙。", "堆案文書埋白日，閉門風雨厄重陽。", "酒嘗友我胡爲祟，菊亦愁余未肯黄。", "閒玩羣陰藏九九，花開身健竟須償。"]'),
('4be29375-1834-454b-8a8f-c62345f7a0ae','次韻監試潼川提刑張兵部有懷家山木犀','魏了翁','宋','宋诗','song-poetry','','[]','形安宇泰即吾鄉，花解隨人到處黄。',64,'全唐诗/poet.song.191000.json','["形安宇泰即吾鄉，花解隨人到處黄。", "何事歸心起張翰，有來妙語出君房。", "榮枯境裏自殊觀，造化機中無別香。", "不見儋州安樂法，隨花隨客作重陽。"]'),
('85402538-44b1-4cfd-abb8-f07c869f8201','用黄侍郎韻題宇文發運瑞萱亭  其一','魏了翁','宋','宋诗','song-poetry','','[]','春風拍拍壽觴前，人有何憂樹爾萱。',32,'全唐诗/poet.song.191000.json','["春風拍拍壽觴前，人有何憂樹爾萱。", "老眼未忘兒女愛，花隨人意瑞家園。"]'),
('62e10169-b445-43d8-a40e-38551b19a4b2','用黄侍郎韻題宇文發運瑞萱亭  其二','魏了翁','宋','宋诗','song-poetry','','[]','花開鄂鄂自相親，枝葉根心一氣春。',32,'全唐诗/poet.song.191000.json','["花開鄂鄂自相親，枝葉根心一氣春。", "認得箇中真血脈，孝慈天分匪由人。"]'),
('a77e8e38-0cd7-4988-b0df-87b592a339d0','用李致政韻題臨邛陳氏所居呂仙所留回道人來四字','魏了翁','宋','宋诗','song-poetry','','[]','負甕城邊閒日月，翻環門上幾春秋。',64,'全唐诗/poet.song.191000.json','["負甕城邊閒日月，翻環門上幾春秋。", "東陽謾識榴皮字，南郭曾偕柳樹遊。", "踏雪飛鴻痕偶在，寒潭過鴈影無留。", "至人御氣無今古，妙處疑同上下流。"]'),
('774740d5-46c4-4838-a335-4c53da23ff1c','燕新進士','魏了翁','宋','宋诗','song-poetry','','[]','已辦書生場屋緣，楓宸入對字三千。',64,'全唐诗/poet.song.191000.json','["已辦書生場屋緣，楓宸入對字三千。", "玉階喜得方寸地，屋漏如臨咫尺天。", "學自孔顔期用世，道非堯舜莫陳前。", "便聽第一鴻臚唱，衣鉢如余未足傳。"]'),
('89fd6f53-9fa1-47c8-836f-37db0208ba3d','送唐述之赴廷對','魏了翁','宋','宋诗','song-poetry','','[]','快着青冥輭玉鞭，穩騎騄耳踏雲煙。',64,'全唐诗/poet.song.191000.json','["快着青冥輭玉鞭，穩騎騄耳踏雲煙。", "便持全蜀無雙譽，去聽賓臚第一傳。", "衆所望君皆爾耳，人之好我豈云然。", "古來名下無虛士，試玩盈科放海篇。"]'),
('5e458e1b-5927-4ae1-aab6-2abce0d4c2e0','己未唱第後謝恩詩','魏了翁','宋','宋诗','song-poetry','','[]','聖皇學問富春秋，當宁宵衣渴壯猷。',64,'全唐诗/poet.song.191000.json','["聖皇學問富春秋，當宁宵衣渴壯猷。", "鵠立銀袍天北闕，龍飛金榜殿西頭。", "彤池繆對三千字，黄甲俄輸一二籌。", "初學粗知存大體，紛更要洗洛陽羞。"]'),
('ef47e61b-7e11-4765-9056-e8c6caf01720','次韻眉山胡宰喜雪','魏了翁','宋','宋诗','song-poetry','','[]','龍公試手發陰機，瑣定愁雲陣不飛。',64,'全唐诗/poet.song.191000.json','["龍公試手發陰機，瑣定愁雲陣不飛。", "老樹垂垂低欲壓，穉苗薿薿爛生輝。", "窮冬莫厭詩筒數，富歲先占訟缿稀。", "擬待明朝約清賞，剡溪興盡酒舡歸。"]'),
('df757aed-63f5-4737-872b-71d51956e242','次韻李參政李提刑見和鴈湖觀梅','魏了翁','宋','宋诗','song-poetry','','[]','春事何須羯鼓催，好春全看未花時。',64,'全唐诗/poet.song.191000.json','["春事何須羯鼓催，好春全看未花時。", "雨餘庭院湖光濕，人倚闌干夕暝遲。", "正會意時俄起起，到忘言處謾期期。", "鴈湖飲散人歸後，曾問梅花復幾枝。"]'),
('a22ec0b0-e152-43d5-80cd-f72b7dc2c3f3','次韻李參政上劉舍人閣學','魏了翁','宋','宋诗','song-poetry','','[]','滔滔陸海與潘江，得似韓渠受籍瀧。',64,'全唐诗/poet.song.191000.json','["滔滔陸海與潘江，得似韓渠受籍瀧。", "天下美官容易得，世間清論苦難降。", "龍隨凡介便儔伍，鶴聳孤雲誰等雙。", "一馬二童吾計决，山中花竹總麾幢。"]'),
('72ebf784-8447-40e2-a77c-10ddfb829efc','和別駕喜雨四絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','四山鎔日瀉黄金，誰載亭臯一尺霖。',32,'全唐诗/poet.song.191000.json','["四山鎔日瀉黄金，誰載亭臯一尺霖。", "息處生機無間斷，劃然有頃驗天心。"]'),
('00493ad0-9144-48ba-bce7-3b0f7b01585c','和別駕喜雨四絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','夏畦活活翠芊綿，起視微雲尚黯然。',32,'全唐诗/poet.song.191000.json','["夏畦活活翠芊綿，起視微雲尚黯然。", "底事化工渾不費，笑余何敢更貪天。"]'),
('5589419c-2956-42e7-b48e-2861c5d44387','和別駕喜雨四絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','爾游爾衍與天同，無處無時不感通。',32,'全唐诗/poet.song.191000.json','["爾游爾衍與天同，無處無時不感通。", "芸鼓漸稀鈴索靜，茶煙摇颺晚香中。"]'),
('405e124c-0577-443a-a288-928418e061b6','和別駕喜雨四絕  其四','魏了翁','宋','宋诗','song-poetry','','[]','山北山南徧插秧，天時較似去年彊。',32,'全唐诗/poet.song.191000.json','["山北山南徧插秧，天時較似去年彊。", "從今無事閒風月，分作屏星一半凉。"]'),
('e0e1898b-18f6-4285-a535-50204864629e','送安同知赴闕  其一','魏了翁','宋','宋诗','song-poetry','','[]','憂民白髮三千丈，報國丹心十二時。',32,'全唐诗/poet.song.191000.json','["憂民白髮三千丈，報國丹心十二時。", "獨倚長空望紅日，滿簾風雨燕喃呢。"]'),
('dc4b56b2-f8b1-4238-90a4-87238487b3ed','送安同知赴闕  其二','魏了翁','宋','宋诗','song-poetry','','[]','京邑殿留司馬相，東山無以我公歸。',32,'全唐诗/poet.song.191000.json','["京邑殿留司馬相，東山無以我公歸。", "德人用舍關天運，世上巫咸妄見機。"]'),
('0cf51055-225a-43bd-a9b3-ca8a745191b2','送安同知赴闕  其三','魏了翁','宋','宋诗','song-poetry','','[]','當年匣劍授彬時，都在將軍頤指麾。',32,'全唐诗/poet.song.191000.json','["當年匣劍授彬時，都在將軍頤指麾。", "誰者紛紛容易取，高皇約束變更爲。"]'),
('31e6c7ec-66e3-4160-a70f-ad623182040c','送安同知赴闕  其四','魏了翁','宋','宋诗','song-poetry','','[]','未須多買酇侯田，且可同乘曲逆舡。',32,'全唐诗/poet.song.191000.json','["未須多買酇侯田，且可同乘曲逆舡。", "昨夜皛山雲作雨，東流一水徑通天。"]'),
('b09e1c90-da82-49ca-9dd0-11ed3970e237','送安同知赴闕  其五','魏了翁','宋','宋诗','song-poetry','','[]','閉門睡息正齁齁，野卉蓬蓬爛不收。',32,'全唐诗/poet.song.191000.json','["閉門睡息正齁齁，野卉蓬蓬爛不收。", "只憂一夜西風急，惱亂東鄰卒未休。"]'),
('ee849e77-afb7-4656-a3f0-ec2d7d04294a','用大禮楊少卿韻題馮君山莊圖  其一','魏了翁','宋','宋诗','song-poetry','','[]','摩挲潘叟跨馿圖，便擬移家向此居。',32,'全唐诗/poet.song.191000.json','["摩挲潘叟跨馿圖，便擬移家向此居。", "素富素貧隨處樂，世間何地不嵩廬。"]'),
('928d4535-e676-4038-8c05-edc1d73956b3','用大禮楊少卿韻題馮君山莊圖  其二','魏了翁','宋','宋诗','song-poetry','','[]','入山佳趣已成無，何事猶馳門外車。',32,'全唐诗/poet.song.191000.json','["入山佳趣已成無，何事猶馳門外車。", "書裏一丁總憂患，人間六甲有孤虛。"]'),
('c3d7cfef-6b8e-4ab9-a22b-29dbd45297be','次韻李彭州乞鶴于虞萬州  其一','魏了翁','宋','宋诗','song-poetry','','[]','急景應如赴壑鱗，感時心事可憐生。',32,'全唐诗/poet.song.191000.json','["急景應如赴壑鱗，感時心事可憐生。", "湖邊鴈序殷勤叫，持寄新詩念故人。"]'),
('eba4e0ad-ced9-4c16-8f28-e3f07644c422','次韻李彭州乞鶴于虞萬州  其二','魏了翁','宋','宋诗','song-poetry','','[]','滄江羽客亦悠哉，水畔梅邊雪鬭皚。',32,'全唐诗/poet.song.191000.json','["滄江羽客亦悠哉，水畔梅邊雪鬭皚。", "白鶴山頭曾有約，至今華表望歸來。"]'),
('84837e15-3086-4555-b3a4-840c5708d7d1','次韻李彭州乞鶴于虞萬州  其三','魏了翁','宋','宋诗','song-poetry','','[]','賓朋滿座酒如江，雪月風花應接忙。',32,'全唐诗/poet.song.191000.json','["賓朋滿座酒如江，雪月風花應接忙。", "攬盡山林閒富貴，滄江公子太彊梁。"]'),
('d31cf640-7f65-4382-9936-54eced348c95','次韻李彭州乞鶴于虞萬州  其四','魏了翁','宋','宋诗','song-poetry','','[]','江頭夜釣雨連明，可是漁翁太不情。',32,'全唐诗/poet.song.191000.json','["江頭夜釣雨連明，可是漁翁太不情。", "白鶴縱違華表約，黄雞應念越人盟。"]'),
('9bb3fd04-4300-4b33-ba18-5aa6cc75c2e7','燕孫節推','魏了翁','宋','宋诗','song-poetry','','[]','快着青冥軟玉鞭，直騎騄耳踏雲煙。',64,'全唐诗/poet.song.191000.json','["快着青冥軟玉鞭，直騎騄耳踏雲煙。", "等閒禮樂三千字，酬答艱難十九年。", "鼎甲聲華今有繼，政涂事業豈無傳。", "願君更拓勛名地，重玩盈科放海篇。"]'),
('e194498e-0a4f-446b-9f6e-170f81961ce4','人日約李提刑李參政登蟆頤馬上醉書','魏了翁','宋','宋诗','song-poetry','','[]','只從元日到人日，便覺新年勝故年。',64,'全唐诗/poet.song.191000.json','["只從元日到人日，便覺新年勝故年。", "買酒買符酬舊社，宜蠶宜麥祝新田。", "般添和氣開花柳，嗺送韶華入管絃。", "我本田間飯牛者，偶來解后亦犁然。"]'),
('f64ace6e-dc36-4124-92fe-7ae0c6e51522','李提刑李參政再和招鶴詩再用韻以謝  其一','魏了翁','宋','宋诗','song-poetry','','[]','靜看瀺灂幾游鱗，爭似玄裳縞袂生。',32,'全唐诗/poet.song.191000.json','["靜看瀺灂幾游鱗，爭似玄裳縞袂生。", "幾度有書招不至，應慙側翅傍他人。"]'),
('f1d12e01-bd27-4910-9069-c407e873b3ef','李提刑李參政再和招鶴詩再用韻以謝  其二','魏了翁','宋','宋诗','song-poetry','','[]','錦江相去幾何哉，未見窗前落雪皚。',32,'全唐诗/poet.song.191000.json','["錦江相去幾何哉，未見窗前落雪皚。", "聲氣同時無間斷，有時夜半掠江來。"]'),
('386bbd4a-a1b7-472f-956d-ece106501ecd','李提刑李參政再和招鶴詩再用韻以謝  其三','魏了翁','宋','宋诗','song-poetry','','[]','須眉皓白何爲者，未出山時舉世忙。',32,'全唐诗/poet.song.191000.json','["須眉皓白何爲者，未出山時舉世忙。", "若使當時容易致，等閒鶖鶴混魚梁。"]'),
('0f78a9fc-4044-421f-bc77-7b29fc1bd3be','李提刑李參政再和招鶴詩再用韻以謝  其四','魏了翁','宋','宋诗','song-poetry','','[]','弟兄孫子總英明，玉雪成圍眩晝晴。',32,'全唐诗/poet.song.191000.json','["弟兄孫子總英明，玉雪成圍眩晝晴。", "寄語茅山何道士，不須苦共鶴尋盟。"]'),
('9c6413c8-1b62-4b04-ae5a-195a68a3b8e4','再和招鶴  其一','魏了翁','宋','宋诗','song-poetry','','[]','仰看翔翮俯游鱗，物意容容各自春。',32,'全唐诗/poet.song.191000.json','["仰看翔翮俯游鱗，物意容容各自春。", "遥想滄江五君子，長身玉立伴閒人。"]'),
('f3630f05-a341-463c-bd24-cb8937549778','再和招鶴  其二','魏了翁','宋','宋诗','song-poetry','','[]','聲色於渠何有哉，銀潢刷羽雪皚皚。',32,'全唐诗/poet.song.191000.json','["聲色於渠何有哉，銀潢刷羽雪皚皚。", "天邊亦是閒遊耳，爭向人間問去來。"]'),
('24c505fd-891c-45c1-a044-7de1048f39e2','再和招鶴  其三','魏了翁','宋','宋诗','song-poetry','','[]','蒼苔散啄旁清江，被服委蛇未肯忙。',32,'全唐诗/poet.song.191000.json','["蒼苔散啄旁清江，被服委蛇未肯忙。", "清唳九臯天聽在，也知雅意笑鵜梁。"]'),
('af3c5eb8-832a-44e9-ac84-1428e94bf731','再和招鶴  其四','魏了翁','宋','宋诗','song-poetry','','[]','蓬萊雲近綺疏明，鶴砌分茶午夢晴。',32,'全唐诗/poet.song.191000.json','["蓬萊雲近綺疏明，鶴砌分茶午夢晴。", "何似林間看不足，併呼鷗鷺狎齊盟。"]'),
('506034ed-68d1-4938-bf7d-140321e0ff4a','李參政折贈黄香梅與八詠俱至用韻以謝  其一','魏了翁','宋','宋诗','song-poetry','','[]','黄雲冉冉曉蒼蒼，閒倚平湖只自香。',32,'全唐诗/poet.song.191000.json','["黄雲冉冉曉蒼蒼，閒倚平湖只自香。", "較似寒枝雖未至，依然風韻挾冰霜。"]'),
('f596b012-309a-4eb5-b38c-7449daade9b1','李參政折贈黄香梅與八詠俱至用韻以謝  其二','魏了翁','宋','宋诗','song-poetry','','[]','犀鎮簾帷風綽開，當庭恰似剪花回。',32,'全唐诗/poet.song.191000.json','["犀鎮簾帷風綽開，當庭恰似剪花回。", "眉間一點看渾似，笑領江南春信來。"]'),
('97c1243d-4e75-45c2-af9a-25e7e26cd1b7','李參政折贈黄香梅與八詠俱至用韻以謝  其三','魏了翁','宋','宋诗','song-poetry','','[]','露拂薔薇不太深，春風庭院晚陰陰。',32,'全唐诗/poet.song.191000.json','["露拂薔薇不太深，春風庭院晚陰陰。", "來遲未入黄昏句，誰喚錢塘人姓林。"]'),
('1451e078-d42f-4642-85a4-70b24d9659e0','李參政折贈黄香梅與八詠俱至用韻以謝  其四','魏了翁','宋','宋诗','song-poetry','','[]','入眼風光似世情，金裳玉質轉分明。',32,'全唐诗/poet.song.191000.json','["入眼風光似世情，金裳玉質轉分明。", "額黄十二誰分似，疑是仙人成智瓊。"]'),
('467c38db-4ec0-4672-86f0-eb4cf6793f94','李參政折贈黄香梅與八詠俱至用韻以謝  其五','魏了翁','宋','宋诗','song-poetry','','[]','冰魂玉骨一枝春，風格南昌舊子真。',32,'全唐诗/poet.song.191000.json','["冰魂玉骨一枝春，風格南昌舊子真。", "誰幻神仙黄白術，時裝近日太尖新。"]'),
('81d3bad0-f81c-4513-bad7-08afbe1b6183','李參政折贈黄香梅與八詠俱至用韻以謝  其六','魏了翁','宋','宋诗','song-poetry','','[]','玄天黄露真顔色，金步摇中顫舞娃。',32,'全唐诗/poet.song.191000.json','["玄天黄露真顔色，金步摇中顫舞娃。", "更倩南窗書嬭味，不妨來伴太常齋。"]'),
('edf886f3-f2b7-4e45-9a00-940a3ab191fd','李參政折贈黄香梅與八詠俱至用韻以謝  其七','魏了翁','宋','宋诗','song-poetry','','[]','和羹心事歲寒姿，若第風標舍更誰。',32,'全唐诗/poet.song.191000.json','["和羹心事歲寒姿，若第風標舍更誰。", "謾道色輕花更豔，幾成塗抹水邊枝。"]'),
('3758b38c-ce63-4956-bd5b-4bb13713e2fe','李參政折贈黄香梅與八詠俱至用韻以謝  其八','魏了翁','宋','宋诗','song-poetry','','[]','詩翁曾住玉皇家，剛與梅花定等差。',32,'全唐诗/poet.song.191000.json','["詩翁曾住玉皇家，剛與梅花定等差。", "染上鞠衣宮樣淺，練裙縞帨覺無華。"]'),
('d485a99f-b8b2-42e3-8714-125fdfda54b1','李參政約客訪西郊海棠予以齋禁不與','魏了翁','宋','宋诗','song-poetry','','[]','十日花期九日齋，相園紅錦爛成堆。',64,'全唐诗/poet.song.191000.json','["十日花期九日齋，相園紅錦爛成堆。", "不將小雨輕陰駐，剛把和風暖日催。", "詩筆都隨許昌去，春光不待牧之來。", "要知榮悴適然耳，明日荼䕷芍藥開。"]'),
('f28dac06-736b-4e85-bfb4-0cf52cb37eb3','再和','魏了翁','宋','宋诗','song-poetry','','[]','芹宮日晚守祠齋，爭見花如火齊堆。',64,'全唐诗/poet.song.191000.json','["芹宮日晚守祠齋，爭見花如火齊堆。", "不復少年黄犢健，任令急景白駒催。", "繁紅才伴栗留至，衆綠又驚鶗鴂來。", "到會意時須命酒，莫論花謝與花開。"]'),
('0d4a7a36-acbc-4abb-91b4-28b755f773db','次韻虞萬州滄江海棠','魏了翁','宋','宋诗','song-poetry','','[]','維摩老子菌生菴，門外滄江綠正涵。',64,'全唐诗/poet.song.191000.json','["維摩老子菌生菴，門外滄江綠正涵。", "夜雨村村拆花柳，春風日日長桑蠶。", "晚粧才記海棠睡，朝色俄看禁藥酣。", "造化新功鎮如此，撫詩往往發余慙。"]'),
('c21836f2-72bb-4589-9dc6-e54f6ae71a16','上巳日約同僚過蟆頤晚視新開橫江堰','魏了翁','宋','宋诗','song-poetry','','[]','朏魄雙交氣候新，古今爲樂屬茲辰。',64,'全唐诗/poet.song.191000.json','["朏魄雙交氣候新，古今爲樂屬茲辰。", "蘭堂坐上皆豪逸，韋曲水邊多麗人。", "顧我未能真免俗，邀賓聊復共行春。", "却因遊豫思民事，檢校城東白虎津。"]'),
('449cbeb4-454f-42a8-8e14-85415027211e','題李彭州南亭','魏了翁','宋','宋诗','song-poetry','','[]','花木精神面面全，誰將好景作南園。',64,'全唐诗/poet.song.191000.json','["花木精神面面全，誰將好景作南園。", "栗留枝上春風思，鶗鴂聲中曉屐痕。", "簷外梅礬兄及弟，檻前竹鶴子生孫。", "我今猶是數旬客，遇意忺時即打門。"]'),
('16a3d493-7aac-40bc-ac47-9916375edfc0','送李梁山之官  其一','魏了翁','宋','宋诗','song-poetry','','[]','時論苦伊優，如君莫肯留。',48,'全唐诗/poet.song.191000.json','["時論苦伊優，如君莫肯留。", "乖逢惟有命，爵義不同謀。", "且袖長年手，來乘淺水舟。", "人間初水漲，一室自天遊。"]'),
('b3de6ec0-c60a-4e9f-a28b-76a392cd5c49','送李梁山之官  其二','魏了翁','宋','宋诗','song-poetry','','[]','質行疑似鈍，至論本亡奇。',48,'全唐诗/poet.song.191000.json','["質行疑似鈍，至論本亡奇。", "一寸虛靈地，千年德政碑。", "更窮山犖确，毋嘆路逶遲。", "官職時來作，天公自已知。"]'),
('fd4ecb67-8e72-4672-9e31-33171487ddd9','趙深甫年七十有親九十貧無以養索賦','魏了翁','宋','宋诗','song-poetry','','[]','囝思郎罷久無炊，父曰子行胡不歸。',32,'全唐诗/poet.song.191000.json','["囝思郎罷久無炊，父曰子行胡不歸。", "負米上堂寬带索，不妨逿地戲兒衣。"]'),
('4a1efa5e-4252-4a5e-bb3c-13f7db75404f','題三衢于艮室','魏了翁','宋','宋诗','song-poetry','','[]','後前止字誤箋題，只認連山終物時。',32,'全唐诗/poet.song.191000.json','["後前止字誤箋題，只認連山終物時。", "雨霽雲收青不改，悠然依舊看朝隮。"]'),
('267b8bdb-4d1e-4fb2-9833-89f804b32d09','次韻李彭州訪山居三絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','只嫌湫隘近城居，無着名山萬卷書。',32,'全唐诗/poet.song.191000.json','["只嫌湫隘近城居，無着名山萬卷書。", "不道八荒皆我宇，獨於此處認吾廬。"]'),
('20139d17-5e7a-4114-9841-021415f3b81c','次韻李彭州訪山居三絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','古剡溪頭寄短椽，山陰勝韻更誰傳。',32,'全唐诗/poet.song.191000.json','["古剡溪頭寄短椽，山陰勝韻更誰傳。", "似聞昨夜高軒過，人怪儒衣住檐肩。"]'),
('3b276978-d92b-4aaf-9788-7e30c72c9456','次韻李彭州訪山居三絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','不須更草北山文，歸去開關掃白雲。',32,'全唐诗/poet.song.191000.json','["不須更草北山文，歸去開關掃白雲。", "興未盡時仍重訪，我非辟世可同羣。"]'),
('9b135064-2cb8-4609-9653-847b609090ef','次韻李參政秋懷十絕  其一','魏了翁','宋','宋诗','song-poetry','','[]','怒濤撞擊吼籠銅，驚倒江邊百歲翁。',32,'全唐诗/poet.song.191000.json','["怒濤撞擊吼籠銅，驚倒江邊百歲翁。", "西望陰霾猶未定，火雲偏在五雲東。"]'),
('f35085df-00ca-4b59-8845-8dd2580ce535','次韻李參政秋懷十絕  其二','魏了翁','宋','宋诗','song-poetry','','[]','穉金老火戰重圍，京洛緇塵點客衣。',32,'全唐诗/poet.song.191000.json','["穉金老火戰重圍，京洛緇塵點客衣。", "輸却東園南閣老，水花闌檻夕陽稀。"]'),
('e23d194a-9c9e-4d7f-9423-a77f059752c3','次韻李參政秋懷十絕  其三','魏了翁','宋','宋诗','song-poetry','','[]','坱圠羣靈付大鈞，人生於世本何營。',32,'全唐诗/poet.song.191000.json','["坱圠羣靈付大鈞，人生於世本何營。", "浩然中夜存存氣，不藉西風夢亦清。"]'),
('a6202c65-1c77-4ebd-b95a-09f0d6f7bb94','次韻李參政秋懷十絕  其四','魏了翁','宋','宋诗','song-poetry','','[]','書棚尚有送春詩，又見秋風滿範圍。',32,'全唐诗/poet.song.191000.json','["書棚尚有送春詩，又見秋風滿範圍。", "夜雨床頭多釀酒，天邊一舸有人歸。"]'),
('a395814d-eca6-477f-9aa9-3607394780bc','次韻李參政秋懷十絕  其五','魏了翁','宋','宋诗','song-poetry','','[]','月華如水恰中庭，烏鵲枝頭栖復驚。',32,'全唐诗/poet.song.191000.json','["月華如水恰中庭，烏鵲枝頭栖復驚。", "晚暑三亭隨雨過，秋聲一半在蟲鳴。"]'),
('7e8bd088-bcd6-4100-b0a4-cf00dbd13425','次韻李參政秋懷十絕  其六','魏了翁','宋','宋诗','song-poetry','','[]','怒雷噀雨吹塵沙，樛枝草樹紛籠加。',32,'全唐诗/poet.song.191000.json','["怒雷噀雨吹塵沙，樛枝草樹紛籠加。", "可憐荷屋風不定，但有白紅三數花。"]'),
('3a7a7481-d1aa-48ce-8200-36b816a3cdd5','次韻李參政秋懷十絕  其七','魏了翁','宋','宋诗','song-poetry','','[]','河神不恤吾民勤，濤頭射山危欲傾。',32,'全唐诗/poet.song.191000.json','["河神不恤吾民勤，濤頭射山危欲傾。", "似聞凌雲灘頭水，前日肉薄幾危城。"]'),
('50eb3f73-f88a-4563-9c8f-d6290f672ba6','次韻李參政秋懷十絕  其八','魏了翁','宋','宋诗','song-poetry','','[]','母心日日兒當歸，屋山看盡烏鳥栖。',32,'全唐诗/poet.song.191000.json','["母心日日兒當歸，屋山看盡烏鳥栖。", "安得使我如烏飛，母旁衮地爲兒啼。"]'),
('eb7c77c7-d687-4c92-8c70-4086104bfaa0','次韻李參政秋懷十絕  其九','魏了翁','宋','宋诗','song-poetry','','[]','止處流行息處生，春作夏長秋敷榮。',32,'全唐诗/poet.song.191000.json','["止處流行息處生，春作夏長秋敷榮。", "其間毫髮皆帝力，民日用之無能名。"]'),
('06ecbd41-f805-4c77-9935-d0e5693fb621','次韻李參政秋懷十絕  其一○','魏了翁','宋','宋诗','song-poetry','','[]','新詩妙處古人過，節制場中老伏波。',32,'全唐诗/poet.song.191000.json','["新詩妙處古人過，節制場中老伏波。", "枯腸亦知費搜攪，奈此風景觸撥何。"]'),
('8c6647cc-fc9d-4cfd-b450-aef20196855f','次韻李參政賦蟆頤新堰  其一','魏了翁','宋','宋诗','song-poetry','','[]','蟆頤江上靜無濤，永逸功夫在一勞。',32,'全唐诗/poet.song.191000.json','["蟆頤江上靜無濤，永逸功夫在一勞。", "昨晚秋風原上看，長腰秔米薦琴高。"]'),
('a2c8e167-4472-49d3-8963-502dda857945','次韻李參政賦蟆頤新堰  其二','魏了翁','宋','宋诗','song-poetry','','[]','夏秋雨集澮溝盈，雨過江空洲渚生。',32,'全唐诗/poet.song.191000.json','["夏秋雨集澮溝盈，雨過江空洲渚生。", "事到無根元易涸，要將心地作池城。"]'),
('a5e7e52e-45d8-43c3-bf58-b7c2c95017b0','次韻李參政賦蟆頤新堰  其三','魏了翁','宋','宋诗','song-poetry','','[]','八表雲昏氣候偏，秋霖成澤市乘舡。',32,'全唐诗/poet.song.191000.json','["八表雲昏氣候偏，秋霖成澤市乘舡。", "平舟老子閒無事，看盡熙豐祐聖年。"]'),
('f2bb97c7-d55e-4681-bca4-490262ab10df','魯提幹以詩惠分茶椀用韻爲謝','魏了翁','宋','宋诗','song-poetry','','[]','禿盡春窗千兔毫，形容不盡意陶陶。',64,'全唐诗/poet.song.191000.json','["禿盡春窗千兔毫，形容不盡意陶陶。", "可人兩椀春風焙，滌我三升玉色醪。", "銅葉分花春意閙，銀瓶發乳雨聲高。", "試呼陶妓平章看，正恐紅綃未足褒。"]'),
('7b040dbc-d761-43d3-b6d6-bc447809c5ae','次韻虞萬州見寄除夕江村餞臘  其一','魏了翁','宋','宋诗','song-poetry','','[]','非我江山許我賒，有涯生事不無涯。',64,'全唐诗/poet.song.191000.json','["非我江山許我賒，有涯生事不無涯。", "雨添餠餌村村秀，風作羹胹樹樹花。", "行玉盤中看物化，縷銀幡裏感年華。", "初春心事誰人解，夢落滄江處士家。"]'),
('a32bdb37-8095-4bfd-8da2-187d3fbcb979','次韻虞萬州見寄除夕江村餞臘  其二','魏了翁','宋','宋诗','song-poetry','','[]','處士西城落照邊，春風吹袂意泠然。',64,'全唐诗/poet.song.191000.json','["處士西城落照邊，春風吹袂意泠然。", "閒中受用封千戶，聖處功夫祿九遷。", "竹外緩觴留急景，沙頭飽飯看豐年。", "詩來發我無窮思，擬上滄江別看天。"]'),
('530499d7-25a8-4291-9203-190324523864','南郊祖帳賦五十六言呈劉左史','魏了翁','宋','宋诗','song-poetry','','[]','綠水青畦潑眼明，紅英翠柏伴將迎。',64,'全唐诗/poet.song.191000.json','["綠水青畦潑眼明，紅英翠柏伴將迎。", "春懷拍拍渾無極，王事怱怱苦有程。", "迅驛星馳驚客夢，白袍鵠立喚人行。", "所嗟文物寥寥甚，况忍同時別兩卿。"]'),
('fc1e9a86-b455-4b47-a225-43f4d71e68d7','許侍郎同飲郊外王氏亭分韻得風字','魏了翁','宋','宋诗','song-poetry','','[]','萬綠成帷漲晚空，不知門外幾番風。',64,'全唐诗/poet.song.191000.json','["萬綠成帷漲晚空，不知門外幾番風。", "月拖樹影闌干角，燭挾花陰酒醆中。", "飲雋青山如有問，曲終遠意浩無窮。", "登臨此地知多少，氣味應難似此同。"]'),
('66b705bd-00c7-442b-80c9-56d01a84e14b','送李左史郊外和范瀘州贈李韻','魏了翁','宋','宋诗','song-poetry','','[]','滔滔斯世果誰歸，行止乖逢自四時。',64,'全唐诗/poet.song.191000.json','["滔滔斯世果誰歸，行止乖逢自四時。", "桃李貪看炫春晝，菅麻誰解漚東池。", "雨雲翻覆人輕薄，旱暵艱難女仳離。", "須信人生歸去好，此行惟有鴈行知。"]'),
('97f3b9ec-4a95-4379-be42-d9ad354a2b53','別東叔西叔二兄于遂寧門外','魏了翁','宋','宋诗','song-poetry','','[]','畢逋枝上曉光和，日日庭闈盼樹柯。',64,'全唐诗/poet.song.191000.json','["畢逋枝上曉光和，日日庭闈盼樹柯。", "風送驪歌驚短夢，雲拖鳩雨濕長坡。", "母心念子無時足，王事催人不奈何。", "但祝愛身崇令德，長教此意得天多。"]'),
('4a95fe93-45d2-4693-a8d9-cab68313e986','次韻遂寧府宴貢士即席賦  其一','魏了翁','宋','宋诗','song-poetry','','[]','過盡一春花信風，魚天鼓浪送蒙衝。',64,'全唐诗/poet.song.191000.json','["過盡一春花信風，魚天鼓浪送蒙衝。", "鳳翰有目爭先睹，牛角無人嘆不逢。", "選試謾稱新漢使，作成端屬舊春宗。", "鹿鳴賸作中和曲，嶉送飛黄出蟻封。"]'),
('581955da-3e76-48a4-9646-8482643696a3','次韻遂寧府宴貢士即席賦  其二','魏了翁','宋','宋诗','song-poetry','','[]','誰把浮華變古風，頹波衮衮日奔衝。',64,'全唐诗/poet.song.191000.json','["誰把浮華變古風，頹波衮衮日奔衝。", "人情容易隨流去，此道分明觸處逢。", "學似董晁猶有累，文過元白愧無宗。", "諸君自此皆升矣，更向根基厚自封。"]'),
('8b1d7bce-c63d-4628-b49f-a7638ae352fc','虞萬州生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','玉湖面面碧回環，六月寒飈撼屋山。',64,'全唐诗/poet.song.191000.json','["玉湖面面碧回環，六月寒飈撼屋山。", "跨鶴不隨刀夢去，卧龍甘與壁梭閒。", "漁樵是處便爭席，利欲年來早閉關。", "拂拭石君勤把酒，照人風節兩孱顔。"]'),
('4ddb21ef-c455-4bf0-9cd9-692b2da4b47e','虞萬州生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','滄江深處汲難渾，世味濃枯不見痕。',64,'全唐诗/poet.song.191000.json','["滄江深處汲難渾，世味濃枯不見痕。", "竹影移枰風澹蕩，芰荷摇艇月黄昏。", "坎離合處靈根峙，剝復機中碩果存。", "門地人才如許秀，可能投老釣魚村。"]'),
('aea5add0-92bf-4455-9ee7-0f35a77c206c','虞萬州生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','初度相望十日期，一尊無路扣江扉。',64,'全唐诗/poet.song.191000.json','["初度相望十日期，一尊無路扣江扉。", "羈人職事門重鍵，堆案文書山四圍。", "未辦五千餘卷讀，空慙三十九年非。", "遥思道義賓朋集，夢作滄江鷗鷺飛。"]'),
('945f3056-b64d-4066-abce-971dac5b5c80','董侍郎生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','紫氣飛騫一馬驄，當年輕下五雲東。',64,'全唐诗/poet.song.191000.json','["紫氣飛騫一馬驄，當年輕下五雲東。", "詩書意味江都相，琴鶴規模清獻公。", "長嘯驅風靜秋戍，精神喚雨作年豐。", "列城香火知何限，蒸起祥雲入頰紅。"]'),
('bd5d5e25-2056-48b1-bd37-127b3780eb0b','董侍郎生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','上到青天更上頭，好風滿地水連疇。',64,'全唐诗/poet.song.191000.json','["上到青天更上頭，好風滿地水連疇。", "雲開玉斧河邊戍，月照金牛峽外秋。", "舉目河山無盡藏，關心籌略最高樓。", "辛夷花下烏塘曲，未許夫公憶舊遊。"]'),
('4e3d55a1-e733-414d-a37c-a858a4a5fb0a','董侍郎生日  其三','魏了翁','宋','宋诗','song-poetry','','[]','潞公曩自蜀遄歸，約僅踰年秉政機。',64,'全唐诗/poet.song.191000.json','["潞公曩自蜀遄歸，約僅踰年秉政機。", "當日燕毛誰與並，後來接踵未應稀。", "從星元合陪天柱，戴氣寧當遠日畿。", "會看傳宣燕私第，賜香成霧綵成圍。"]'),
('9a542f56-359f-4dfa-b604-b4ab54c3570b','王總卿生日  其一','魏了翁','宋','宋诗','song-poetry','','[]','上到青天更上頭，蜀人猶記舊星軺。',64,'全唐诗/poet.song.191000.json','["上到青天更上頭，蜀人猶記舊星軺。", "安絃在昔猶危柱，挂壁於今倚大弨。", "棠樹留春便野茇，桂花和月引僊瓢。", "風雲不隔連天棧，門戶三槐拂絳霄。"]'),
('c564e216-d7a7-4d0b-8abc-edef0806f0d7','王總卿生日  其二','魏了翁','宋','宋诗','song-poetry','','[]','浮雲䆉稏卷晴疇，一目天隅盡好秋。',64,'全唐诗/poet.song.191000.json','["浮雲䆉稏卷晴疇，一目天隅盡好秋。", "路有醉人挑襏襫，邊無嘶馬趁兜鍪。", "開張叶氣憑弧矢，收拾豐年報冕旒。", "小小經綸已如此，不應留滯古梁州。"]'),
('7db03aa9-cd6c-4a5b-ad50-b2fe839e3680','登冠山次瞻叔兄壁間舊韻  其一','魏了翁','宋','宋诗','song-poetry','','[]','蘆花樸樸雪連天，楓葉槮槮日滿山。',32,'全唐诗/poet.song.191000.json','["蘆花樸樸雪連天，楓葉槮槮日滿山。", "似識遊人非俗客，遠峯呈露玉孱顔。"]'),
('b95e9e0b-b342-4e9d-87de-cb7e33345480','登冠山次瞻叔兄壁間舊韻  其二','魏了翁','宋','宋诗','song-poetry','','[]','又到黄昏別有天，落霞明水月銜山。',32,'全唐诗/poet.song.191000.json','["又到黄昏別有天，落霞明水月銜山。", "亂煙遠樹供詩卷，濁酒狂歌伴醉顔。"]'),
('fc31e6e8-239d-4f93-80b3-e4b99faaa9cb','與劉左史同別楊少卿于南郊舟中用宋兵部韻','魏了翁','宋','宋诗','song-poetry','','[]','玉龍老子訪僊鶴，沖佑散人歸瑞烏。',64,'全唐诗/poet.song.191000.json','["玉龍老子訪僊鶴，沖佑散人歸瑞烏。", "俗事祇今長刺促，可人自昔費招呼。", "憂時恨不百子駿，背我寧堪二大夫。", "艤纁黄昏不成別，畫成江上送行圖。"]'),
('e24cb93f-1752-46de-9017-79ea4ab38cf4','再用宋兵部韻送劉左史','魏了翁','宋','宋诗','song-poetry','','[]','縶維不住谷中駒，愛戀徒占屋上烏。',64,'全唐诗/poet.song.191000.json','["縶維不住谷中駒，愛戀徒占屋上烏。", "開漢樓前迎劍騎，臨津門外罷傳呼。", "宅家未忍忘賢傳，衡宇胡爲戒僕夫。", "閣束衣冠聊一笑，不爲耐辱司空圖。"]'),
('030113db-a481-4b16-a67d-fc826e12b925','次韻李參政和薛祕書詩見寄  其一','魏了翁','宋','宋诗','song-poetry','','[]','寒城眺晚牛羊下，翠蕩涵秋鸛鶴飛。',32,'全唐诗/poet.song.191000.json','["寒城眺晚牛羊下，翠蕩涵秋鸛鶴飛。", "風雨燈前話疇昔，應懷坡潁不成歸。"]'),
('964c4d34-d276-4a54-8c68-8a4dabbf36cf','次韻李參政和薛祕書詩見寄  其二','魏了翁','宋','宋诗','song-poetry','','[]','扶木之陰三萬丈，曉光絕出衆山尖。',32,'全唐诗/poet.song.191000.json','["扶木之陰三萬丈，曉光絕出衆山尖。", "分明大路平如掌，朝發崑崙夕至崦。"]'),
('67fbd580-a63f-4b3e-8251-46e88e04ac09','次韻李參政和薛祕書詩見寄  其三','魏了翁','宋','宋诗','song-poetry','','[]','行有尚時觀習坎，不終止處認兼山。',32,'全唐诗/poet.song.191000.json','["行有尚時觀習坎，不終止處認兼山。", "止中自有流行好，不在從違用舍間。"]'),
('7ac27863-4645-437e-9e6a-5f95b9173637','次韻李參政和薛祕書詩見寄  其四','魏了翁','宋','宋诗','song-poetry','','[]','將相時來應不免，人生難得自由身。',32,'全唐诗/poet.song.191000.json','["將相時來應不免，人生難得自由身。", "及今且續宋一藝，莫逐蟲魚注李巡。"]'),
('64305fd7-1b61-4b75-95d3-d2338e13e8b7','次韻李參政和薛祕書詩見寄  其五','魏了翁','宋','宋诗','song-poetry','','[]','書來寄我薛公詩，磊落襟期尉我思。',32,'全唐诗/poet.song.191000.json','["書來寄我薛公詩，磊落襟期尉我思。", "所謂伊人在空谷，公侯逸豫鎮無期。"]'),
('0b52da23-ccf6-4532-b435-582db3be4098','譙申甫惠詩有隨緣婚嫁之語因次韻贊之','魏了翁','宋','宋诗','song-poetry','','[]','幾見三星挂屋榮，人生難得是青春。',64,'全唐诗/poet.song.191000.json','["幾見三星挂屋榮，人生難得是青春。", "已驚梅實盈筐筥，方待河魴下釣綸。", "乃事未能超俗見，感時寧不念天倫。", "隨緣婚嫁君言是，且把乖逢付大鈞。"]'),
('01e0d75c-fa18-4db8-9732-8a5c4d0edc60','次韻瀘帥范郎中再和所送李季允韻見寄  其一','魏了翁','宋','宋诗','song-poetry','','[]','人老邊關未得師，行違久速只安時。',64,'全唐诗/poet.song.191000.json','["人老邊關未得師，行違久速只安時。", "令隨天闊風遥嶺，語挾春來草夢池。", "舊壘無華閒睥睨，新機有句到侏離。", "孤衷耿耿無人會，只傍天公作己知。"]'),
('2d36046a-1bd3-4893-8257-771e95ab8cda','次韻瀘帥范郎中再和所送李季允韻見寄  其二','魏了翁','宋','宋诗','song-poetry','','[]','新陽拆地喚春歸，生意綿綿重此時。',64,'全唐诗/poet.song.191000.json','["新陽拆地喚春歸，生意綿綿重此時。", "青女卷寒還朔易，朱輪駕暖出咸池。", "恩流未滲魚猶涸，禁網雖疏雉或離。", "撫事傷時無限意，馮梅折寄故人知。"]'),
('e196b2ac-0b95-45fc-aa0e-1a257e133085','題牟節叟介壽堂和劉左史韻','魏了翁','宋','宋诗','song-poetry','','[]','兒大詩書敵富强，婦供滫瀡養尊章。',64,'全唐诗/poet.song.191000.json','["兒大詩書敵富强，婦供滫瀡養尊章。", "照盤曉日龍爲炙，介壽春風玉作堂。", "禮物皆由天賦分，家榮亦使里生光。", "人生有子不翅足，况復孫枝習氣香。"]'),
('c4d8e05b-7ca5-49f7-a3c4-64a3cac3b095','次李參政所和五絕句韻因以爲壽  其一','魏了翁','宋','宋诗','song-poetry','','[]','竹外臯禽相與和，湖邊沙雁自由飛。',32,'全唐诗/poet.song.191000.json','["竹外臯禽相與和，湖邊沙雁自由飛。", "美人醉踏梅花月，笑領明年春事歸。"]'),
('4dc63dc2-2d6a-42c7-959e-f2efb54b8b4f','次李參政所和五絕句韻因以爲壽  其二','魏了翁','宋','宋诗','song-poetry','','[]','過眼浮雲齊劍吷，會心真趣付爐尖。',32,'全唐诗/poet.song.191000.json','["過眼浮雲齊劍吷，會心真趣付爐尖。", "羲皇弭節前余路，日景方中未迫崦。"]'),
('0b8d75f9-e580-4c7e-8f80-ff694694a08a','次李參政所和五絕句韻因以爲壽  其三','魏了翁','宋','宋诗','song-poetry','','[]','漠漠煙塵連北道，幽幽草樹蔽南山。',32,'全唐诗/poet.song.191000.json','["漠漠煙塵連北道，幽幽草樹蔽南山。", "照人明月長無寐，遶遍清風五百間。"]'),
('15b0406f-f47a-4efc-9fcd-c8d7cc826cc1','次李參政所和五絕句韻因以爲壽  其四','魏了翁','宋','宋诗','song-poetry','','[]','天地之心萬物靈，世間難得是人身。',32,'全唐诗/poet.song.191000.json','["天地之心萬物靈，世間難得是人身。", "面前放過知何限，好與光明做一巡。"]'),
('ebf1baf2-882f-49de-9014-d5671973cb01','次李參政所和五絕句韻因以爲壽  其五','魏了翁','宋','宋诗','song-poetry','','[]','天如有定開平治，寧患無人安子思。',32,'全唐诗/poet.song.191000.json','["天如有定開平治，寧患無人安子思。", "到出手時須卓卓，逢開口處莫期期。"]'),
('b333fef8-6bbb-4eca-8343-a7e92760c0d1','再和前韻答賦  其一','魏了翁','宋','宋诗','song-poetry','','[]','羣蜻海上迎機舞，雙雁天邊避弋飛。',32,'全唐诗/poet.song.191000.json','["羣蜻海上迎機舞，雙雁天邊避弋飛。", "犖犖此心天與識，滔滔斯世我誰歸。"]'),
('c2c4270d-0df3-45b4-b2a0-600d045c84f4','再和前韻答賦  其二','魏了翁','宋','宋诗','song-poetry','','[]','秋到山川自童涸，春回草木又勾尖。',32,'全唐诗/poet.song.191000.json','["秋到山川自童涸，春回草木又勾尖。", "陰機盡處雷居地，月魄生時日在崦。"]'),
('94a2db42-94e8-41a5-9bf9-376e0598d91b','再和前韻答賦  其三','魏了翁','宋','宋诗','song-poetry','','[]','甫田之田驕驕莠，大國之郊濯濯山。',32,'全唐诗/poet.song.191000.json','["甫田之田驕驕莠，大國之郊濯濯山。", "養且難成摧則折，寧居材與不材間。"]'),
('8738b3a5-eece-4e7a-8d24-b084cd629915','再和前韻答賦  其四','魏了翁','宋','宋诗','song-poetry','','[]','別來滿眼簿書塵，想像湖邊玉立身。',32,'全唐诗/poet.song.191000.json','["別來滿眼簿書塵，想像湖邊玉立身。", "文陣時傳騷將令，愁城不倩酒兵巡。"]'),
('4a10f19a-3a79-4a92-9b2f-8aab3ea721b8','再和前韻答賦  其五','魏了翁','宋','宋诗','song-poetry','','[]','一聲鳳咮朝陽裏，慰我雞鳴風雨思。',32,'全唐诗/poet.song.191000.json','["一聲鳳咮朝陽裏，慰我雞鳴風雨思。", "藐藐大鈞那可問，有才動與厄相期。"]'),
('932c370f-1b54-405d-8d11-8b471774cec8','書遂寧何氏穩興齋','魏了翁','宋','宋诗','song-poetry','','[]','巫峽孤舟嫌太重，山陽小艇又偏輕。',32,'全唐诗/poet.song.191000.json','["巫峽孤舟嫌太重，山陽小艇又偏輕。", "直須裝載停勻着，更要其間御者平。"]'),
('28901e9b-a67c-419a-a7ad-c47c174a030f','赴遂寧進士期集即席賦','魏了翁','宋','宋诗','song-poetry','','[]','聘幣鳴騶選實才，輦輸使者作行媒。',64,'全唐诗/poet.song.191000.json','["聘幣鳴騶選實才，輦輸使者作行媒。", "般添春意和氈墨，嗺送花風上翠桅。", "世論且然聊爾耳，諸君行矣勉之哉。", "邦人此意毋虛辱，滿貯香名萬里回。"]'),
('999275a5-c925-4910-9f2d-1413c883d80f','送劉類元奉對闕庭','魏了翁','宋','宋诗','song-poetry','','[]','突兀脩名磊磈胸，一鳴冠蜀未酬公。',64,'全唐诗/poet.song.191000.json','["突兀脩名磊磈胸，一鳴冠蜀未酬公。", "十年解瑟無調瑟，百載張弓未弛弓。", "剝啄門邊誰主客，畢逋城上孰雌雄。", "引吭爲作朝陽瑞，携取香名壽廼翁。"]'),
('1d0abea0-d352-40cf-ba63-3b0773074ba8','二月二日遂寧北郊迎富故事','魏了翁','宋','宋诗','song-poetry','','[]','才過結柳送貧日，又見簪花迎富時。',64,'全唐诗/poet.song.191000.json','["才過結柳送貧日，又見簪花迎富時。", "誰爲貧驅竟難逐，素爲富逼豈容辭。", "貧如易去人所欲，富若可求吾亦爲。", "里俗相傳今已久，謾隨人意看兒嬉。"]'),
('807d2834-441c-4699-961a-67eeaf7fca58','二月十九日席上賦  其一','魏了翁','宋','宋诗','song-poetry','','[]','野荼䕷發雪堆牆，草牡丹開月照梁。',32,'全唐诗/poet.song.191000.json','["野荼䕷發雪堆牆，草牡丹開月照梁。", "世眼都隨人毀譽，不知底處是真香。"]'),
('13438875-4d9b-46a5-b0d7-b2e0f5f1467e','二月十九日席上賦  其二','魏了翁','宋','宋诗','song-poetry','','[]','露漬風揉嬌婀娜，煙籠日炙綠鬅鬙。',32,'全唐诗/poet.song.191000.json','["露漬風揉嬌婀娜，煙籠日炙綠鬅鬙。", "風流名字時方污，亦爲儀容太不矜。"]'),
('ef66bfe4-0098-4547-b923-4ebbe3ec670e','二月十九日席上賦  其三','魏了翁','宋','宋诗','song-poetry','','[]','昨宵渾不遣花知，畚鍤和根带露移。',32,'全唐诗/poet.song.191000.json','["昨宵渾不遣花知，畚鍤和根带露移。", "睡裏驪珠醉中屐，想花失在未醒時。"]'),
('afdd203c-b2e1-46a2-9282-de5938e8c581','二月十九日席上賦  其四','魏了翁','宋','宋诗','song-poetry','','[]','年光又見一百五，春意才餘十二三。',32,'全唐诗/poet.song.191000.json','["年光又見一百五，春意才餘十二三。", "節物催人渾不覺，謾隨白墮看紅酣。"]'),
('3ddcf1f8-3000-474f-b8cc-9bd239b1193d','翌日約客有和者再用韻四首  其一','魏了翁','宋','宋诗','song-poetry','','[]','柳梢庭院杏花牆，尚記春風繞畫梁。',32,'全唐诗/poet.song.191000.json','["柳梢庭院杏花牆，尚記春風繞畫梁。", "二十四番花信盡，只餘簫鼓賣餳香。"]'),
('089ab915-d415-4394-bfa2-b35042527021','翌日約客有和者再用韻四首  其二','魏了翁','宋','宋诗','song-poetry','','[]','堆案文書長引睡，起來搔首亂鬅鬙。',32,'全唐诗/poet.song.191000.json','["堆案文書長引睡，起來搔首亂鬅鬙。", "眼明嘉卉紛紈綺，竟是脩篁聳棘矜。"]'),
('5001c136-e679-48f0-9542-96c54a2bc10d','翌日約客有和者再用韻四首  其三','魏了翁','宋','宋诗','song-poetry','','[]','妙處和春莫遣知，晚尊隨柳逐花移。',32,'全唐诗/poet.song.191000.json','["妙處和春莫遣知，晚尊隨柳逐花移。", "落花繡地春深日，翠柳簁空月上時。"]'),
('4b1b4f9f-3883-4af2-baeb-d3b349040c9f','翌日約客有和者再用韻四首  其四','魏了翁','宋','宋诗','song-poetry','','[]','古來長恨難并四，今日相逢所就三。',32,'全唐诗/poet.song.191000.json','["古來長恨難并四，今日相逢所就三。", "花裏賓朋皆臭味，夜凉風月更清酣。"]'),
('05e3c277-01b8-4e47-ac1c-822c2e5626b6','昨有禱于社稷及境內山川是夕枕上聞雨  其一','魏了翁','宋','宋诗','song-poetry','','[]','郊宮方社詩攸重，川澤山林禮所崇。',32,'全唐诗/poet.song.191000.json','["郊宮方社詩攸重，川澤山林禮所崇。", "古祀不修牲幣廢，梵鐃聲裏紙錢風。"]'),
('d6c59828-0ff3-4ede-a9e3-56d3b1ad0709','昨有禱于社稷及境內山川是夕枕上聞雨  其二','魏了翁','宋','宋诗','song-poetry','','[]','中春天氣似朱明，翕翕炎威惱亂人。',32,'全唐诗/poet.song.191000.json','["中春天氣似朱明，翕翕炎威惱亂人。", "一夜簷前天雨麥，曉來仍作本來春。"]'),
('c6055073-726e-402e-9585-2a215b74ad14','次虞萬州韻送曹簡夫守宣城','魏了翁','宋','宋诗','song-poetry','','[]','膂力方剛髮未翁，不令憂樂與民同。',64,'全唐诗/poet.song.191000.json','["膂力方剛髮未翁，不令憂樂與民同。", "卷人間事風塵表，收天下春襟府中。", "江北勤勞誰念德，湖南幹事未論功。", "如今又聽還家去，緩急分明要此公。"]'),
('67e4fbaf-97bf-4878-948c-8f35af21e416','次壁間韻題懷安道上三州王氏亭  其一','魏了翁','宋','宋诗','song-poetry','','[]','滿壁故人何在，倚闌心事誰同。',28,'全唐诗/poet.song.191000.json','["滿壁故人何在，倚闌心事誰同。", "蚤徑遊絲罥日，亂山瘦馬行空。"]'),
('9f0ea8d1-3b59-45d6-ab10-1ddcd0ff318f','次壁間韻題懷安道上三州王氏亭  其二','魏了翁','宋','宋诗','song-poetry','','[]','老農不留地力，萬物取具天公。',28,'全唐诗/poet.song.191000.json','["老農不留地力，萬物取具天公。", "曲曲拗坳夏隴，枝枝葉葉春風。"]'),
('e3099b47-12c0-4e6f-b28b-c347601975f1','以使事過成都訖事而歸虞萬州成都尉高表兄拉訪靈泉宰高表兄風雨連明遂謁朱祭酒祠即事賦  其一','魏了翁','宋','宋诗','song-poetry','','[]','薝蔔風清醉騎香，滿身花影踏斜陽。',32,'全唐诗/poet.song.191000.json','["薝蔔風清醉騎香，滿身花影踏斜陽。", "行花盡處山圍郭，又聽松風吹客裳。"]'),
('a724b263-76dd-4dd2-a26f-7a3a92ac23ed','以使事過成都訖事而歸虞萬州成都尉高表兄拉訪靈泉宰高表兄風雨連明遂謁朱祭酒祠即事賦  其二','魏了翁','宋','宋诗','song-poetry','','[]','青燈相對同胞弟，白酒交酬異姓兄。',32,'全唐诗/poet.song.191000.json','["青燈相對同胞弟，白酒交酬異姓兄。", "風雨似知人有約，終宵都作對床聲。"]'),
('0300987c-4db3-4ae1-9894-8271d859fc21','以使事過成都訖事而歸虞萬州成都尉高表兄拉訪靈泉宰高表兄風雨連明遂謁朱祭酒祠即事賦  其三','魏了翁','宋','宋诗','song-poetry','','[]','無事江流到處平，無言天運四時新。',32,'全唐诗/poet.song.191000.json','["無事江流到處平，無言天運四時新。", "真僊此意何曾間，直到如今瞪眎人。"]'),
('75a315e4-535c-4a69-a13c-75a23a499a04','以使事過成都訖事而歸虞萬州成都尉高表兄拉訪靈泉宰高表兄風雨連明遂謁朱祭酒祠即事賦  其四','魏了翁','宋','宋诗','song-poetry','','[]','天運無窮成變化，水流不息作江淮。',32,'全唐诗/poet.song.191000.json','["天運無窮成變化，水流不息作江淮。", "須知瞪處非無事，莫着僊人舊草鞋。"]'),
('9d2bec83-e0a4-47d3-baa5-3b05bf0eb6a1','臨發潼上許侍郎提刑餞于東山賦詩留別','魏了翁','宋','宋诗','song-poetry','','[]','人生出處亦何常，又到涪江江上鄉。',64,'全唐诗/poet.song.191000.json','["人生出處亦何常，又到涪江江上鄉。", "山色如逢故人語，松聲仍作去年香。", "紅裳大舶滿清鏡，翠瀲白沙明夕陽。", "未省此懽何日更，擬邀明月照昏黄。"]'),
('b463059f-d0ac-4938-b444-709fa3a40091','題潼川賈伯用崇雅閤出入體','魏了翁','宋','宋诗','song-poetry','','[]','寒鄉晚學恨無書，亦有藏書不若無。',64,'全唐诗/poet.song.191000.json','["寒鄉晚學恨無書，亦有藏書不若無。", "謾把詞章作禽犢，或鑽文字等蟲魚。", "新籤三萬幾成肆，拄腹五千猶類厨。", "崇雅主人來索句，謾哦七字勸躊躇。"]'),
('57a377a4-9cb3-4052-940d-9e4ca38adcd5','約客木犀下有賦','魏了翁','宋','宋诗','song-poetry','','[]','茂樹幽花兀老蒼，不隨衆卉入詞場。',64,'全唐诗/poet.song.191000.json','["茂樹幽花兀老蒼，不隨衆卉入詞場。", "虎頭點點開金粟，犀首纍纍佩印章。", "明月上時疑白傅，清風度處越黄香。", "人才生世元如此，不爲無人不肯芳。"]');
